insert into public.exercises (id,name,category,level,mechanic,force,equipment,primary_muscles,secondary_muscles,instructions,image_urls) values
('Glute_Kickback','Glute Kickback','strength','beginner','compound','push','body only',ARRAY['glutes']::text[],ARRAY['hamstrings']::text[],ARRAY['Kneel on the floor or an exercise mat and bend at the waist with your arms extended in front of you (perpendicular to the torso) in order to get into a kneeling push-up position but with the arms spaced at shoulder width. Your head should be looking forward and the bend of the knees should create a 90-degree angle between the hamstrings and the calves. This will be your starting position.','As you exhale, lift up your right leg until the hamstrings are in line with the back while maintaining the 90-degree angle bend. Contract the glutes throughout this movement and hold the contraction at the top for a second. Tip: At the end of the movement the upper leg should be parallel to the floor while the calf should be perpendicular to it.','Go back to the initial position as you inhale and now repeat with the left leg.','Continue to alternate legs until all of the recommended repetitions have been performed.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Glute_Kickback/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Glute_Kickback/1.jpg']::text[]),
('Goblet_Squat','Goblet Squat','strength','beginner','compound','push','kettlebells',ARRAY['quadriceps']::text[],ARRAY['calves','glutes','hamstrings','shoulders']::text[],ARRAY['Stand holding a light kettlebell by the horns close to your chest. This will be your starting position.','Squat down between your legs until your hamstrings are on your calves. Keep your chest and head up and your back straight.','At the bottom position, pause and use your elbows to push your knees out. Return to the starting position, and repeat for 10-20 repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Goblet_Squat/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Goblet_Squat/1.jpg']::text[]),
('Good_Morning','Good Morning','powerlifting','intermediate','compound','push','barbell',ARRAY['hamstrings']::text[],ARRAY['abdominals','glutes','lower back']::text[],ARRAY['Begin with a bar on a rack at shoulder height. Rack the bar across the rear of your shoulders as you would a power squat, not on top of your shoulders. Keep your back tight, shoulder blades pinched together, and your knees slightly bent. Step back from the rack.','Begin by bending at the hips, moving them back as you bend over to near parallel. Keep your back arched and your cervical spine in proper alignment.','Reverse the motion by extending through the hips with your glutes and hamstrings. Continue until you have returned to the starting position.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Good_Morning/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Good_Morning/1.jpg']::text[]),
('Good_Morning_off_Pins','Good Morning off Pins','powerlifting','intermediate','compound','push','barbell',ARRAY['hamstrings']::text[],ARRAY['abdominals','glutes','lower back']::text[],ARRAY['Begin with a bar on a rack at about the same height as your stomach. Bend over underneath the bar and rack the bar across the rear of your shoulders as you would a power squat, not on top of your shoulders. At the proper height, you should be near parallel to the floor when bent over. Keep your back tight, shoulder blades pinched together, and your knees slightly bent. Keep your back arched and your cervical spine in proper alignment.','Begin the motion by extending through the hips with your glutes and hamstrings, and you are standing with the weight. Slowly lower the weight back to the pins returning to the starting position.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Good_Morning_off_Pins/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Good_Morning_off_Pins/1.jpg']::text[]),
('Gorilla_Chin_Crunch','Gorilla Chin/Crunch','strength','intermediate','compound','pull','body only',ARRAY['abdominals']::text[],ARRAY['biceps','lats']::text[],ARRAY['Hang from a chin-up bar using an underhand grip (palms facing you) that is slightly wider than shoulder width.','Now bend your knees at a 90 degree angle so that the calves are parallel to the floor while the thighs remain perpendicular to it. This will be your starting position.','As you exhale, pull yourself up while crunching your knees up at the same time until your knees are at chest level. You will stop going up as soon as your nose is at the same level as the bar. Tip: When you get to this point you should also be finishing the crunch at the same time.','Slowly start to inhale as you return to the starting position.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Gorilla_Chin_Crunch/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Gorilla_Chin_Crunch/1.jpg']::text[]),
('Groin_and_Back_Stretch','Groin and Back Stretch','stretching','intermediate','compound','static',NULL,ARRAY['adductors']::text[],ARRAY[]::text[],ARRAY['Sit on the floor with your knees bent and feet together.','Interlock your fingers behind your head. This will be your starting position.','Curl downwards, bringing your elbows to the inside of your thighs. After a brief pause, return to the starting position with your head up and your back straight. Repeat for 10-20 repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Groin_and_Back_Stretch/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Groin_and_Back_Stretch/1.jpg']::text[]),
('Groiners','Groiners','stretching','intermediate','compound','pull','body only',ARRAY['adductors']::text[],ARRAY[]::text[],ARRAY['Begin in a pushup position on the floor. This will be your starting position.','Using both legs, jump forward landing with your feet next to your hands. Keep your head up as you do so.','Return to the starting position and immediately repeat the movement, continuing for 10-20 repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Groiners/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Groiners/1.jpg']::text[]),
('Hack_Squat','Hack Squat','strength','beginner','compound','push','machine',ARRAY['quadriceps']::text[],ARRAY['calves','glutes','hamstrings']::text[],ARRAY['Place the back of your torso against the back pad of the machine and hook your shoulders under the shoulder pads provided.','Position your legs in the platform using a shoulder width medium stance with the toes slightly pointed out. Tip: Keep your head up at all times and also maintain the back on the pad at all times.','Place your arms on the side handles of the machine and disengage the safety bars (which on most designs is done by moving the side handles from a facing front position to a diagonal position).','Now straighten your legs without locking the knees. This will be your starting position. (Note: For the purposes of this discussion we will use the medium stance described above which targets overall development; however you can choose any of the three stances described in the foot positioning section).','Begin to slowly lower the unit by bending the knees as you maintain a straight posture with the head up (back on the pad at all times). Continue down until the angle between the upper leg and the calves becomes slightly less than 90-degrees (which is the point in which the upper legs are below parallel to the floor). Inhale as you perform this portion of the movement. Tip: If you performed the exercise correctly, the front of the knees should make an imaginary straight line with the toes that is perpendicular to the front. If your knees are past that imaginary line (if they are past your toes) then you are placing undue stress on the knee and the exercise has been performed incorrectly.','Begin to raise the unit as you exhale by pushing the floor with mainly with the heel of your foot as you straighten the legs again and go back to the starting position.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hack_Squat/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hack_Squat/1.jpg']::text[]),
('Hammer_Curls','Hammer Curls','strength','beginner','isolation','pull','dumbbell',ARRAY['biceps']::text[],ARRAY[]::text[],ARRAY['Stand up with your torso upright and a dumbbell on each hand being held at arms length. The elbows should be close to the torso.','The palms of the hands should be facing your torso. This will be your starting position.','Now, while holding your upper arm stationary, exhale and curl the weight forward while contracting the biceps. Continue to raise the weight until the biceps are fully contracted and the dumbbell is at shoulder level. Hold the contracted position for a brief moment as you squeeze the biceps. Tip: Focus on keeping the elbow stationary and only moving your forearm.','After the brief pause, inhale and slowly begin the lower the dumbbells back down to the starting position.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hammer_Curls/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hammer_Curls/1.jpg']::text[]),
('Hammer_Grip_Incline_DB_Bench_Press','Hammer Grip Incline DB Bench Press','strength','beginner','compound','push','dumbbell',ARRAY['chest']::text[],ARRAY['shoulders','triceps']::text[],ARRAY['Lie back on an incline bench with a dumbbell on each hand on top of your thighs. The palms of your hand will be facing each other.','By using your thighs to help you get the dumbbells up, clean the dumbbells one arm at a time so that you can hold them at shoulder width.','Once at shoulder width, keep the palms of your hands with a neutral grip (palms facing each other). Keep your elbows flared out with the upper arms in line with the shoulders (perpendicular to the torso) and the elbows bent creating a 90-degree angle between the upper arm and the forearm. This will be your starting position.','Now bring down the weights slowly to your side as you breathe in. Keep full control of the dumbbells at all times.','As you breathe out, push the dumbbells up using your pectoral muscles. Lock your arms in the contracted position, hold for a second and then start coming down slowly. Tip: It should take at least twice as long to go down than to come up.','Repeat the movement for the prescribed amount of repetitions.','When you are done, place the dumbbells back in your thighs and then on the floor. This is the safest manner to dispose of the dumbbells.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hammer_Grip_Incline_DB_Bench_Press/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hammer_Grip_Incline_DB_Bench_Press/1.jpg']::text[]),
('Hamstring-SMR','Hamstring-SMR','stretching','beginner','isolation','static','foam roll',ARRAY['hamstrings']::text[],ARRAY[]::text[],ARRAY['In a seated position, extend your legs over a foam roll so that it is position on the back of the upper legs. Place your hands to the side or behind you to help support your weight. This will be your starting position.','Using your hands, lift your hips off of the floor and shift your weight on the foam roll to one leg. Relax the hamstrings of the leg you are stretching.','Roll over the foam from below the hip to above the back of the knee, pausing at points of tension for 10-30 seconds. Repeat for the other leg.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hamstring-SMR/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hamstring-SMR/1.jpg']::text[]),
('Hamstring_Stretch','Hamstring Stretch','stretching','beginner','isolation','static',NULL,ARRAY['hamstrings']::text[],ARRAY[]::text[],ARRAY['Lie on your back with one leg extended above you, with the hip at ninety degrees. Keep the other leg flat on the floor.','Loop a belt, band, or rope over the ball of your foot. This will be your starting position.','Pull on the belt to create tension in the calves and hamstrings. Hold this stretch for 10-30 seconds, and repeat with the other leg.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hamstring_Stretch/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hamstring_Stretch/1.jpg']::text[]),
('Handstand_Push-Ups','Handstand Push-Ups','strength','expert','compound','push','body only',ARRAY['shoulders']::text[],ARRAY['triceps']::text[],ARRAY['With your back to the wall bend at the waist and place both hands on the floor at shoulder width.','Kick yourself up against the wall with your arms straight. Your body should be upside down with the arms and legs fully extended. Keep your whole body as straight as possible. Tip: If doing this for the first time, have a spotter help you. Also, make sure that you keep facing the wall with your head, rather than looking down.','Slowly lower yourself to the ground as you inhale until your head almost touches the floor. Tip: It is of utmost importance that you come down slow in order to avoid head injury.','Push yourself back up slowly as you exhale until your elbows are nearly locked.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Handstand_Push-Ups/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Handstand_Push-Ups/1.jpg']::text[]),
('Hang_Clean','Hang Clean','olympic weightlifting','intermediate','compound','pull','barbell',ARRAY['quadriceps']::text[],ARRAY['calves','forearms','glutes','hamstrings','lower back','shoulders','traps']::text[],ARRAY['Begin with a shoulder width, double overhand or hook grip, with the bar hanging at the mid thigh position. Your back should be straight and inclined slightly forward.','Begin by aggressively extending through the hips, knees and ankles, driving the weight upward. As you do so, shrug your shoulders towards your ears.','Immediately recover by driving through the heels, keeping the torso upright and elbows up. Continue until you have risen to a standing position.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hang_Clean/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hang_Clean/1.jpg']::text[]),
('Hang_Clean_-_Below_the_Knees','Hang Clean - Below the Knees','olympic weightlifting','intermediate','compound','pull','barbell',ARRAY['quadriceps']::text[],ARRAY['calves','forearms','glutes','hamstrings','lower back','shoulders','traps']::text[],ARRAY['Begin with a shoulder width, double overhand or hook grip, with the bar hanging just below the knees. Your back should be straight and inclined slightly forward.','Begin by aggressively extending through the hips, knees and ankles, driving the weight upward. As you do so, shrug your shoulders towards your ears. As full extension is achieved, transition into the third pull by aggressively shrugging and flexing the arms with the elbows up and out.','At peak extension, aggressively pull yourself down, rotating your elbows under the bar as you do so. Receive the bar in a front squat position, the depth of which is dependent upon the height of the bar at the end of the third pull. The bar should be racked onto the protracted shoulders, lightly touching the throat with the hands relaxed. Continue to descend to the bottom squat position, which will help in the recovery.','Immediately recover by driving through the heels, keeping the torso upright and elbows up. Continue until you have risen to a standing position.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hang_Clean_-_Below_the_Knees/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hang_Clean_-_Below_the_Knees/1.jpg']::text[]),
('Hang_Snatch','Hang Snatch','olympic weightlifting','expert','compound','pull','barbell',ARRAY['hamstrings']::text[],ARRAY['abdominals','calves','forearms','glutes','lower back','quadriceps','shoulders','traps']::text[],ARRAY['Begin with a wide grip on the bar, with an overhand or hook grip. The feet should be directly below the hips with the feet turned out. Your knees should be slightly bent, and the torso inclined forward. The spine should be fully extended and the head facing forward. The bar should be at the hips. This will be your starting position.','Aggressively extend through the legs and hips. At peak extension, shrug the shoulders and allow the elbows to flex to the side.','As you move your feet into the receiving position, forcefully pull yourself below the bar as you elevate the bar overhead. Receive the bar with your body as low as possible and the arms fully extended overhead.','Return to a standing position with the weight overhead. Follow by returning the weight to the ground under control.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hang_Snatch/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hang_Snatch/1.jpg']::text[]),
('Hang_Snatch_-_Below_Knees','Hang Snatch - Below Knees','olympic weightlifting','expert','compound','pull','barbell',ARRAY['hamstrings']::text[],ARRAY['abdominals','calves','forearms','glutes','lower back','quadriceps','shoulders','traps']::text[],ARRAY['Begin with a wide grip on the bar, with an overhand or hook grip. The feet should be directly below the hips with the feet turned out. Your knees should be slightly bent, and the torso inclined forward. The spine should be fully extended and the head facing forward. The bar should be just below the knees. This will be your starting position.','Aggressively extend through the legs and hips. At peak extension, shrug the shoulders and allow the elbows to flex to the side.','As you move your feet into the receiving position, forcefully pull yourself below the bar as you elevate the bar overhead. Receive the bar with your body as low as possible and the arms fully extended overhead.','Return to a standing position with the weight overhead, and then return the weight to the floor under control.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hang_Snatch_-_Below_Knees/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hang_Snatch_-_Below_Knees/1.jpg']::text[]),
('Hanging_Bar_Good_Morning','Hanging Bar Good Morning','powerlifting','intermediate','compound','push','barbell',ARRAY['hamstrings']::text[],ARRAY['abdominals','glutes','lower back']::text[],ARRAY['Begin with a bar on a rack at about the same height as your stomach. Suspend the bar using chains or suspension straps.','Bend over underneath the bar and rack the bar across the rear of your shoulders as you would a power squat, not on top of your traps. At the proper height, you should be near parallel to the floor when bent over. Keep your back tight, shoulder blades pinched together, and your knees slightly bent. Keep your back arched and your cervical spine in proper alignment.','Begin the motion by extending through the hips with your glutes and hamstrings, and you are standing with the weight.','Slowly lower the weight back to the starting position, where it is supported by the chains.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hanging_Bar_Good_Morning/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hanging_Bar_Good_Morning/1.jpg']::text[]),
('Hanging_Leg_Raise','Hanging Leg Raise','strength','expert','isolation','pull','body only',ARRAY['abdominals']::text[],ARRAY[]::text[],ARRAY['Hang from a chin-up bar with both arms extended at arms length in top of you using either a wide grip or a medium grip. The legs should be straight down with the pelvis rolled slightly backwards. This will be your starting position.','Raise your legs until the torso makes a 90-degree angle with the legs. Exhale as you perform this movement and hold the contraction for a second or so.','Go back slowly to the starting position as you breathe in.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hanging_Leg_Raise/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hanging_Leg_Raise/1.jpg']::text[]),
('Hanging_Pike','Hanging Pike','strength','expert','compound','pull','body only',ARRAY['abdominals']::text[],ARRAY[]::text[],ARRAY['Hang from a chin-up bar with your legs and feet together using an overhand grip (palms facing away from you) that is slightly wider than shoulder width. Tip: You may use wrist wraps in order to facilitate holding on to the bar.','Now bend your knees at a 90 degree angle and bring the upper legs forward so that the calves are perpendicular to the floor while the thighs remain parallel to it. This will be your starting position.','Pull your legs up as you exhale until you almost touch your shins with the bar above you. Tip: Try to straighten your legs as much as possible while at the top.','Lower your legs as slowly as possible until you reach the starting position. Tip: Avoid swinging and using momentum at all times.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hanging_Pike/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hanging_Pike/1.jpg']::text[]),
('Heaving_Snatch_Balance','Heaving Snatch Balance','olympic weightlifting','intermediate','compound','push','barbell',ARRAY['quadriceps']::text[],ARRAY['abdominals','forearms','glutes','hamstrings','shoulders','triceps']::text[],ARRAY['This drill helps you learn the snatch. Begin by holding a light weight across the back of the shoulders. Your feet should be slightly wider than hip width apart with the feet turned out, the same position that you would perform a squat with.','Begin by dipping with the knees slightly, and popping back up to briefly unload the bar. Drive yourself underneath the bar, elevating it overhead as you descend into a full squat.','Return to a standing position.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Heaving_Snatch_Balance/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Heaving_Snatch_Balance/1.jpg']::text[]),
('Heavy_Bag_Thrust','Heavy Bag Thrust','plyometrics','beginner','compound','push','other',ARRAY['chest']::text[],ARRAY['abdominals','shoulders','triceps']::text[],ARRAY['Utilize a heavy bag for this exercise. Assume an upright stance next to the bag, with your feet staggered, fairly wide apart. Place your hand on the bag at about chest height. This will be your starting position.','Begin by twisting at the waist, pushing the bag forward as hard as possible. Perform this move quickly, pushing the bag away from your body.','Receive the bag as it swings back by reversing these steps.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Heavy_Bag_Thrust/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Heavy_Bag_Thrust/1.jpg']::text[]),
('High_Cable_Curls','High Cable Curls','strength','intermediate','compound','pull','cable',ARRAY['biceps']::text[],ARRAY[]::text[],ARRAY['Stand between a couple of high pulleys and grab a handle in each arm. Position your upper arms in a way that they are parallel to the floor with the palms of your hands facing you. This will be your starting position.','Curl the handles towards you until they are next to your ears. Make sure that as you do so you flex your biceps and exhale. The upper arms should remain stationary and only the forearms should move. Hold for a second in the contracted position as you squeeze the biceps.','Slowly bring back the arms to the starting position.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/High_Cable_Curls/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/High_Cable_Curls/1.jpg']::text[]),
('Hip_Circles_prone','Hip Circles (prone)','stretching','beginner','isolation','pull','body only',ARRAY['abductors']::text[],ARRAY['adductors']::text[],ARRAY['Position yourself on your hands and knees on the ground. Maintaining good posture, raise one bent knee off of the ground. This will be your starting position.','Keeping the knee in a bent position, rotate the femur in an arc, attempting to make a big circle with your knee.','Perform this slowly for a number of repetitions, and repeat on the other side.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hip_Circles_prone/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hip_Circles_prone/1.jpg']::text[]),
('Hip_Extension_with_Bands','Hip Extension with Bands','strength','beginner','compound','push','bands',ARRAY['glutes']::text[],ARRAY['hamstrings']::text[],ARRAY['Secure one end of the band to the lower portion of a post and attach the other to one ankle.','Facing the attachment point of the band, hold on to the column to stabilize yourself.','Keeping your head and your chest up, move the resisted leg back as far as you can while keeping the knee straight.','Return the leg to the starting position.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hip_Extension_with_Bands/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hip_Extension_with_Bands/1.jpg']::text[]),
('Hip_Flexion_with_Band','Hip Flexion with Band','strength','beginner','compound','pull','bands',ARRAY['quadriceps']::text[],ARRAY[]::text[],ARRAY['Secure one end of the band to the lower portion of a post and attach the other to one ankle.','Face away from the attachment point of the band.','Keeping your head and your chest up, raise your knee up to 90 degrees and pause.','Return the leg to the starting position.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hip_Flexion_with_Band/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hip_Flexion_with_Band/1.jpg']::text[]),
('Hip_Lift_with_Band','Hip Lift with Band','powerlifting','beginner','compound','push','bands',ARRAY['glutes']::text[],ARRAY['calves','hamstrings']::text[],ARRAY['After choosing a suitable band, lay down in the middle of the rack, after securing the band on either side of you. If your rack doesn''t have pegs, the band can be secured using heavy dumbbells or similar objects, just ensure they won''t move.','Adjust your position so that the band is directly over your hips. Bend your knees and place your feet flat on the floor. Your hands can be on the floor or holding the band in position.','Keeping your shoulders on the ground, drive through your heels to raise your hips, pushing into the band as high as you can.','Pause at the top of the motion, and return to the starting position.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hip_Lift_with_Band/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hip_Lift_with_Band/1.jpg']::text[]),
('Hug_A_Ball','Hug A Ball','stretching','beginner','isolation','static','exercise ball',ARRAY['lower back']::text[],ARRAY['calves','glutes']::text[],ARRAY['Seat yourself on the floor.','Straddle an exercise ball between both legs and lower your hips down toward the floor.','Hug your arms around the ball to support your body. Adjust your legs so that your feet are flat on the floor and your knees line up over your ankles. Keep a good grip on the ball so it doesn''t roll away from you and send you back onto your buttocks.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hug_A_Ball/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hug_A_Ball/1.jpg']::text[]),
('Hug_Knees_To_Chest','Hug Knees To Chest','stretching','beginner',NULL,'static',NULL,ARRAY['lower back']::text[],ARRAY['glutes']::text[],ARRAY['Lie down on your back and pull both knees up to your chest.','Hold your arms under the knees, not over (that would put to much pressure on your knee joints).','Slowly pull the knees toward your shoulders. This also stretches your buttocks muscles.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hug_Knees_To_Chest/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hug_Knees_To_Chest/1.jpg']::text[]),
('Hurdle_Hops','Hurdle Hops','plyometrics','beginner','compound','push','other',ARRAY['hamstrings']::text[],ARRAY['abductors','adductors','calves','glutes','hamstrings']::text[],ARRAY['Set up a row of hurdles or other small barriers, placing them a few feet apart.','Stand in front of the first hurdle with your feet shoulder width apart. This will be your starting position.','Begin by jumping with both feet over the first hurdle, swinging both arms as you jump.','Absorb the impact of landing by bending the knees, rebounding out of the first leap by jumping over the next hurdle. Continue until you have jumped over all of the hurdles.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hurdle_Hops/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hurdle_Hops/1.jpg']::text[]),
('Hyperextensions_Back_Extensions','Hyperextensions (Back Extensions)','strength','beginner','isolation','pull','other',ARRAY['lower back']::text[],ARRAY['glutes','hamstrings']::text[],ARRAY['Lie face down on a hyperextension bench, tucking your ankles securely under the footpads.','Adjust the upper pad if possible so your upper thighs lie flat across the wide pad, leaving enough room for you to bend at the waist without any restriction.','With your body straight, cross your arms in front of you (my preference) or behind your head. This will be your starting position. Tip: You can also hold a weight plate for extra resistance in front of you under your crossed arms.','Start bending forward slowly at the waist as far as you can while keeping your back flat. Inhale as you perform this movement. Keep moving forward until you feel a nice stretch on the hamstrings and you can no longer keep going without a rounding of the back. Tip: Never round the back as you perform this exercise. Also, some people can go farther than others. The key thing is that you go as far as your body allows you to without rounding the back.','Slowly raise your torso back to the initial position as you inhale. Tip: Avoid the temptation to arch your back past a straight line. Also, do not swing the torso at any time in order to protect the back from injury.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hyperextensions_Back_Extensions/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hyperextensions_Back_Extensions/1.jpg']::text[]),
('Hyperextensions_With_No_Hyperextension_Bench','Hyperextensions With No Hyperextension Bench','strength','intermediate','compound','pull','body only',ARRAY['lower back']::text[],ARRAY['glutes','hamstrings']::text[],ARRAY['With someone holding down your legs, slide yourself down to the edge a flat bench until your hips hang off the end of the bench. Tip: Your entire upper body should be hanging down towards the floor. Also, you will be in the same position as if you were on a hyperextension bench but the range of motion will be shorter due to the height of the flat bench vs. that of the hyperextension bench.','With your body straight, cross your arms in front of you (my preference) or behind your head. This will be your starting position. Tip: You can also hold a weight plate for extra resistance in front of you under your crossed arms.','Start bending forward slowly at the waist as far as you can while keeping your back flat. Inhale as you perform this movement. Keep moving forward until you almost touch the floor or you feel a nice stretch on the hamstrings (whichever comes first). Tip: Never round the back as you perform this exercise.','Slowly raise your torso back to the initial position as you exhale. Tip: Avoid the temptation to arch your back past a straight line. Also, do not swing the torso at any time in order to protect the back from injury.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hyperextensions_With_No_Hyperextension_Bench/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Hyperextensions_With_No_Hyperextension_Bench/1.jpg']::text[]),
('IT_Band_and_Glute_Stretch','IT Band and Glute Stretch','stretching','intermediate',NULL,'static','other',ARRAY['abductors']::text[],ARRAY[]::text[],ARRAY['Loop a belt, rope, or band around one of your feet, and swing that leg across your body to the opposite side, keeping the leg extended as you lay on the ground. This will be your starting position.','Keeping your foot off of the floor, pull on the belt, using the tension to pull the toes up. Hold for 10-20 seconds, and repeat on the other side.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/IT_Band_and_Glute_Stretch/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/IT_Band_and_Glute_Stretch/1.jpg']::text[]),
('Iliotibial_Tract-SMR','Iliotibial Tract-SMR','stretching','intermediate','isolation','static','foam roll',ARRAY['abductors']::text[],ARRAY[]::text[],ARRAY['Lay on your side, with the bottom leg placed onto a foam roller between the hip and the knee. The other leg can be crossed in front of you.','Place as much of your weight as is tolerable onto your bottom leg; there is no need to keep your bottom leg in contact with the ground. Be sure to relax the muscles of the leg you are stretching.','Roll your leg over the foam from you hip to your knee, pausing for 10-30 seconds at points of tension. Repeat with the opposite leg.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Iliotibial_Tract-SMR/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Iliotibial_Tract-SMR/1.jpg']::text[]),
('Inchworm','Inchworm','stretching','beginner','compound',NULL,'body only',ARRAY['hamstrings']::text[],ARRAY[]::text[],ARRAY['Stand with your feet close together. Keeping your legs straight, stretch down and put your hands on the floor directly in front of you. This will be your starting position.','Begin by walking your hands forward slowly, alternating your left and your right. As you do so, bend only at the hip, keeping your legs straight.','Keep going until your body is parallel to the ground in a pushup position.','Now, keep your hands in place and slowly take short steps with your feet, moving only a few inches at a time.','Continue walking until your feet are by hour hands, keeping your legs straight as you do so.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Inchworm/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Inchworm/1.jpg']::text[]),
('Incline_Barbell_Triceps_Extension','Incline Barbell Triceps Extension','strength','intermediate','isolation','push','barbell',ARRAY['triceps']::text[],ARRAY['forearms']::text[],ARRAY['Hold a barbell with an overhand grip (palms down) that is a little closer together than shoulder width.','Lie back on an incline bench set at any angle between 45-75-degrees.','Bring the bar overhead with your arms extended and elbows in. The arms should be in line with the torso above the head. This will be your starting position.','Now lower the bar in a semicircular motion behind your head until your forearms touch your biceps. Inhale as you perform this movement. Tip: Keep your upper arms stationary and close to your head at all times. Only the forearms should move.','Return to the starting position as you breathe out and you contract the triceps. Hold the contraction for a second.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Barbell_Triceps_Extension/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Barbell_Triceps_Extension/1.jpg']::text[]),
('Incline_Bench_Pull','Incline Bench Pull','strength','beginner','isolation','pull','barbell',ARRAY['middle back']::text[],ARRAY['lats','shoulders']::text[],ARRAY['Grab a dumbbell in each hand and lie face down on an incline bench that is set to an incline that is approximately 30 degrees.','Let the arms hang to your sides fully extended as they point to the floor.','Turn the wrists until your hands have a pronated (palms down) grip.','Now flare the elbows out. This will be your starting position.','As you breathe out, start to pull the dumbbells up as if you are doing a reverse bench press. You will do this by bending at the elbows and bringing the upper arms up as you let the forearms hang. Continue this motion until the upper arms are at the same level as your back. Tip: The elbows will come out to the side and your upper arms and torso should make the letter "T" at the top of the movement. Hold the contraction at the top for a second.','Slowly go back down to the starting position as you breathe in.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Bench_Pull/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Bench_Pull/1.jpg']::text[]),
('Incline_Cable_Chest_Press','Incline Cable Chest Press','strength','beginner','compound','push','cable',ARRAY['chest']::text[],ARRAY['shoulders','triceps']::text[],ARRAY['Adjust the weight to an appropriate amount and be seated, grasping the handles. Your upper arms should be about 45 degrees to the body, with your head and chest up. The elbows should be bent to about 90 degrees. This will be your starting position.','Begin by extending through the elbow, pressing the handles together straight in front of you. Keep your shoulder blades retracted as you execute the movement.','After pausing at full extension, return to the starting position, keeping tension on the cables.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Cable_Chest_Press/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Cable_Chest_Press/1.jpg']::text[]),
('Incline_Cable_Flye','Incline Cable Flye','strength','intermediate','isolation','push','cable',ARRAY['chest']::text[],ARRAY['shoulders']::text[],ARRAY['To get yourself into the starting position, set the pulleys at the floor level (lowest level possible on the machine that is below your torso).','Place an incline bench (set at 45 degrees) in between the pulleys, select a weight on each one and grab a pulley on each hand.','With a handle on each hand, lie on the incline bench and bring your hands together at arms length in front of your face. This will be your starting position.','With a slight bend of your elbows (in order to prevent stress at the biceps tendon), lower your arms out at both sides in a wide arc until you feel a stretch on your chest. Breathe in as you perform this portion of the movement. Tip: Keep in mind that throughout the movement, the arms should remain stationary. The movement should only occur at the shoulder joint.','Return your arms back to the starting position as you squeeze your chest muscles and exhale. Hold the contracted position for a second. Tip: Make sure to use the same arc of motion used to lower the weights.','Repeat the movement for the prescribed amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Cable_Flye/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Cable_Flye/1.jpg']::text[]),
('Incline_Dumbbell_Bench_With_Palms_Facing_In','Incline Dumbbell Bench With Palms Facing In','strength','beginner','compound','push','dumbbell',ARRAY['chest']::text[],ARRAY['shoulders','triceps']::text[],ARRAY['Lie back on an incline bench with a dumbbell on each hand on top of your thighs. The palms of your hand will be facing each other.','By using your thighs to help you get the dumbbells up, clean the dumbbells one arm at a time so that you can hold them at shoulder width.','Once at shoulder width, keep the palms of your hands with a neutral grip (palms facing each other). Keep your elbows flared out with the upper arms in line with the shoulders (perpendicular to the torso) and the elbows bent creating a 90-degree angle between the upper arm and the forearm. This will be your starting position.','Now bring down the weights slowly to your side as you breathe in. Keep full control of the dumbbells at all times.','As you breathe out, push the dumbbells up using your pectoral muscles. Lock your arms in the contracted position, hold for a second and then start coming down slowly. Tip: It should take at least twice as long to go down than to come up.','Repeat the movement for the prescribed amount of repetitions.','When you are done, place the dumbbells back in your thighs and then on the floor. This is the safest manner to dispose of the dumbbells.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Dumbbell_Bench_With_Palms_Facing_In/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Dumbbell_Bench_With_Palms_Facing_In/1.jpg']::text[]),
('Incline_Dumbbell_Curl','Incline Dumbbell Curl','strength','beginner','isolation','pull','dumbbell',ARRAY['biceps']::text[],ARRAY[]::text[],ARRAY['Sit back on an incline bench with a dumbbell in each hand held at arms length. Keep your elbows close to your torso and rotate the palms of your hands until they are facing forward. This will be your starting position.','While holding the upper arm stationary, curl the weights forward while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the dumbbells are at shoulder level. Hold the contracted position for a second.','Slowly begin to bring the dumbbells back to starting position as your breathe in.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Dumbbell_Curl/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Dumbbell_Curl/1.jpg']::text[]),
('Incline_Dumbbell_Flyes','Incline Dumbbell Flyes','strength','beginner','compound','push','dumbbell',ARRAY['chest']::text[],ARRAY['shoulders']::text[],ARRAY['Hold a dumbbell on each hand and lie on an incline bench that is set to an incline angle of no more than 30 degrees.','Extend your arms above you with a slight bend at the elbows.','Now rotate the wrists so that the palms of your hands are facing you. Tip: The pinky fingers should be next to each other. This will be your starting position.','As you breathe in, start to slowly lower the arms to the side while keeping the arms extended and while rotating the wrists until the palms of the hand are facing each other. Tip: At the end of the movement the arms will be by your side with the palms facing the ceiling.','As you exhale start to bring the dumbbells back up to the starting position by reversing the motion and rotating the hands so that the pinky fingers are next to each other again. Tip: Keep in mind that the movement will only happen at the shoulder joint and at the wrist. There is no motion that happens at the elbow joint.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Dumbbell_Flyes/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Dumbbell_Flyes/1.jpg']::text[]),
('Incline_Dumbbell_Flyes_-_With_A_Twist','Incline Dumbbell Flyes - With A Twist','strength','beginner','compound','push','dumbbell',ARRAY['chest']::text[],ARRAY['shoulders']::text[],ARRAY['Hold a dumbbell in each hand and lie on an incline bench that is set to an incline angle of no more than 30 degrees.','Extend your arms above you with a slight bend at the elbows.','Now rotate the wrists so that the palms of your hands are facing you. Tip: The pinky fingers should be next to each other. This will be your starting position.','As you breathe in, start to slowly lower the arms to the side while keeping the arms extended and while rotating the wrists until the palms of the hand are facing each other. Tip: At the end of the movement the arms will be by your side with the palms facing the ceiling.','As you exhale start to bring the dumbbells back up to the starting position by reversing the motion and rotating the hands so that the pinky fingers are next to each other again. Tip: Keep in mind that the movement will only happen at the shoulder joint and at the wrist. There is no motion that happens at the elbow joint.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Dumbbell_Flyes_-_With_A_Twist/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Dumbbell_Flyes_-_With_A_Twist/1.jpg']::text[]),
('Incline_Dumbbell_Press','Incline Dumbbell Press','strength','beginner','compound','push','dumbbell',ARRAY['chest']::text[],ARRAY['shoulders','triceps']::text[],ARRAY['Lie back on an incline bench with a dumbbell in each hand atop your thighs. The palms of your hands will be facing each other.','Then, using your thighs to help push the dumbbells up, lift the dumbbells one at a time so that you can hold them at shoulder width.','Once you have the dumbbells raised to shoulder width, rotate your wrists forward so that the palms of your hands are facing away from you. This will be your starting position.','Be sure to keep full control of the dumbbells at all times. Then breathe out and push the dumbbells up with your chest.','Lock your arms at the top, hold for a second, and then start slowly lowering the weight. Tip Ideally, lowering the weights should take about twice as long as raising them.','Repeat the movement for the prescribed amount of repetitions.','When you are done, place the dumbbells back on your thighs and then on the floor. This is the safest manner to release the dumbbells.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Dumbbell_Press/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Dumbbell_Press/1.jpg']::text[]),
('Incline_Hammer_Curls','Incline Hammer Curls','strength','beginner','isolation','pull','dumbbell',ARRAY['biceps']::text[],ARRAY[]::text[],ARRAY['Seat yourself on an incline bench with a dumbbell in each hand. You should pressed firmly against he back with your feet together. Allow the dumbbells to hang straight down at your side, holding them with a neutral grip. This will be your starting position.','Initiate the movement by flexing at the elbow, attempting to keep the upper arm stationary.','Continue to the top of the movement and pause, then slowly return to the start position.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Hammer_Curls/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Hammer_Curls/1.jpg']::text[]),
('Incline_Inner_Biceps_Curl','Incline Inner Biceps Curl','strength','beginner','isolation',NULL,'dumbbell',ARRAY['biceps']::text[],ARRAY[]::text[],ARRAY['Hold a dumbbell in each hand and lie back on an incline bench.','The dumbbells should be at arm''s length hanging at your sides and your palms should be facing out. This will be your starting position.','Now as you exhale curl the weight outward and up while keeping your forearms in line with your side deltoids. Continue the curl until the dumbbells are at shoulder height and to the sides of your deltoids. Tip: The end of the movement should look similar to a double biceps pose.','After a second contraction at the top of the movement, start to inhale and slowly lower the weights back to the starting position using the same path used to bring them up.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Inner_Biceps_Curl/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Inner_Biceps_Curl/1.jpg']::text[]),
('Incline_Push-Up','Incline Push-Up','strength','beginner','compound','push','body only',ARRAY['chest']::text[],ARRAY['shoulders','triceps']::text[],ARRAY['Stand facing bench or sturdy elevated platform. Place hands on edge of bench or platform, slightly wider than shoulder width.','Position forefoot back from bench or platform with arms and body straight. Arms should be perpendicular to body. Keeping body straight, lower chest to edge of box or platform by bending arms.','Push body up until arms are extended. Repeat.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Push-Up/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Push-Up/1.jpg']::text[]),
('Incline_Push-Up_Close-Grip','Incline Push-Up Close-Grip','strength','beginner','compound','push','body only',ARRAY['triceps']::text[],ARRAY['chest','shoulders']::text[],ARRAY['Stand facing a Smith machine bar or sturdy elevated platform at an appropriate height.','Place your hands next to one another on the bar.','Position your feet back from the bar with arms and body straight. This will be your starting position.','Keeping your body straight, lower your chest to the bar by bending the arms.','Return to the starting position by extending the elbows, pressing yourself back up.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Push-Up_Close-Grip/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Push-Up_Close-Grip/1.jpg']::text[]),
('Incline_Push-Up_Depth_Jump','Incline Push-Up Depth Jump','plyometrics','beginner','compound','push','other',ARRAY['chest']::text[],ARRAY['shoulders','triceps']::text[],ARRAY['For this drill you will need a box about 12 inches high, and two thick mats or aerobics steps.','Place the steps just outside of your shoulders, and place your feet on top of the box so that you are in an incline pushup position, your hands just inside the steps. This will be your starting position.','Begin by bending at the elbows to lower your body, quickly reversing position to push your body off of the ground. As you leave the ground, move your hands onto the steps, bending your elbows to absorb the impact.','Repeat the motion to return to the starting position.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Push-Up_Depth_Jump/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Push-Up_Depth_Jump/1.jpg']::text[]),
('Incline_Push-Up_Medium','Incline Push-Up Medium','strength','beginner','compound','push','body only',ARRAY['chest']::text[],ARRAY['abdominals','shoulders','triceps']::text[],ARRAY['Stand facing a Smith machine bar or sturdy elevated platform at an appropriate height.','Place your hands on the bar, with your hands about shoulder width apart.','Position your feet back from the bar with arms and body straight. This will be your starting position.','Keeping your body straight, lower your chest to the bar by bending the arms.','Return to the starting position by extending the elbows, pressing yourself back up.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Push-Up_Medium/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Push-Up_Medium/1.jpg']::text[]),
('Incline_Push-Up_Reverse_Grip','Incline Push-Up Reverse Grip','strength','beginner','compound','push','body only',ARRAY['chest']::text[],ARRAY['abdominals','shoulders','triceps']::text[],ARRAY['Stand facing a Smith machine bar or sturdy elevated platform at an appropriate height.','Place your hands on the bar palms up, with your hands about shoulder width apart.','Position your feet back from the bar with arms and body straight. This will be your starting position.','Keeping your body straight, lower your chest to the bar by bending the arms.','Return to the starting position by extending the elbows, pressing yourself back up.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Push-Up_Reverse_Grip/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Push-Up_Reverse_Grip/1.jpg']::text[]),
('Incline_Push-Up_Wide','Incline Push-Up Wide','strength','beginner','compound','push','body only',ARRAY['chest']::text[],ARRAY['abdominals','shoulders','triceps']::text[],ARRAY['Stand facing a Smith machine bar or sturdy elevated platform at an appropriate height.','Place your hands on the bar, with your hands wider than shoulder width.','Position your feet back from the bar with arms and body straight. Your arms should be perpendicular to the body. This will be your starting position.','Keeping your body straight, lower your chest to the bar by bending the arms.','Return to the starting position by extending the elbows, pressing yourself back up.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Push-Up_Wide/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Incline_Push-Up_Wide/1.jpg']::text[]),
('Intermediate_Groin_Stretch','Intermediate Groin Stretch','stretching','intermediate','isolation','static','other',ARRAY['hamstrings']::text[],ARRAY[]::text[],ARRAY['Lie on your back with your legs extended. Loop a belt, rope, or band around one of your feet, and swing that leg as far to the side as you can. This will be your starting position.','Pull gently on the belt to create tension in your groin and hamstring muscles. Hold for 10-20 seconds, and repeat on the other side.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Intermediate_Groin_Stretch/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Intermediate_Groin_Stretch/1.jpg']::text[]),
('Intermediate_Hip_Flexor_and_Quad_Stretch','Intermediate Hip Flexor and Quad Stretch','stretching','intermediate','compound','static','other',ARRAY['quadriceps']::text[],ARRAY[]::text[],ARRAY['Lie face down on the floor, with a rope, belt, or band looped around one foot.','Flex the knee and extend the hip of the leg to be stretched, using both hands to pull on the belt. Your knee and your hip should come off of the floor, creating tension in the hip flexors and quadriceps. Hold the stretch for 10-20 seconds, and repeat on the other leg.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Intermediate_Hip_Flexor_and_Quad_Stretch/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Intermediate_Hip_Flexor_and_Quad_Stretch/1.jpg']::text[]),
('Internal_Rotation_with_Band','Internal Rotation with Band','strength','beginner','isolation',NULL,'bands',ARRAY['shoulders']::text[],ARRAY[]::text[],ARRAY['Choke the band around a post. The band should be at the same height as your elbow. Stand with your right side to the band a couple of feet away.','Grasp the end of the band with your right hand, and keep your elbow pressed firmly to your side. We recommend you hold a pad or foam roll in place with your elbow to keep it firmly in position.','With your upper arm in position, your elbow should be flexed to 90 degrees with your hand reaching away from your torso. This will be your starting position.','Execute the movement by rotating your arm in a forehand motion, keeping your elbow in place.','Continue as far as you are able, pause, and then return to the starting position.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Internal_Rotation_with_Band/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Internal_Rotation_with_Band/1.jpg']::text[]),
('Inverted_Row','Inverted Row','strength','beginner','compound','pull',NULL,ARRAY['middle back']::text[],ARRAY['lats']::text[],ARRAY['Position a bar in a rack to about waist height. You can also use a smith machine.','Take a wider than shoulder width grip on the bar and position yourself hanging underneath the bar. Your body should be straight with your heels on the ground with your arms fully extended. This will be your starting position.','Begin by flexing the elbow, pulling your chest towards the bar. Retract your shoulder blades as you perform the movement.','Pause at the top of the motion, and return yourself to the start position.','Repeat for the desired number of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Inverted_Row/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Inverted_Row/1.jpg']::text[]),
('Inverted_Row_with_Straps','Inverted Row with Straps','strength','beginner','compound','pull','other',ARRAY['middle back']::text[],ARRAY['biceps','lats']::text[],ARRAY['Hang a rope or suspension straps from a rack or other stable object. Grasp the ends and position yourself in a supine position hanging from the ropes. Your body should be straight with your heels on the ground with your arms fully extended. This will be your starting position.','Begin by flexing the elbow, pulling your chest to your hands. Retract your shoulder blades as you perform the movement.','Pause at the top of the motion, and return yourself to the start position.','Repeat for the desired number of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Inverted_Row_with_Straps/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Inverted_Row_with_Straps/1.jpg']::text[]),
('Iron_Cross','Iron Cross','strength','intermediate','compound','push','dumbbell',ARRAY['shoulders']::text[],ARRAY['chest','glutes','hamstrings','lower back','quadriceps','traps']::text[],ARRAY[]::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Iron_Cross/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Iron_Cross/1.jpg']::text[]),
('Iron_Crosses_stretch','Iron Crosses (stretch)','stretching','intermediate','compound','pull',NULL,ARRAY['quadriceps']::text[],ARRAY[]::text[],ARRAY['Lie face down on the floor, with your arms extended out to your side, palms pressed to the floor. This will be your starting position.','To begin, flex one knee and bring that leg across the back of your body, attempting to touch it to the ground near the opposite hand.','Promptly return the leg to the starting postion, and quickly repeat with the other leg. Continue alternating for 10-20 repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Iron_Crosses_stretch/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Iron_Crosses_stretch/1.jpg']::text[]),
('Isometric_Chest_Squeezes','Isometric Chest Squeezes','plyometrics','beginner','compound','static','body only',ARRAY['chest']::text[],ARRAY['shoulders','triceps']::text[],ARRAY['While either seating or standing, bend your arms at a 90-degree angle and place the palms of your hands together in front of your chest. Tip: Your hands should be open with the palms together and fingers facing forward (perpendicular to your torso).','Push both hands against each other as you contract your chest. Start with slow tension and increase slowly. Keep breathing normally as you execute this contraction.','Hold for the recommended number of seconds.','Now release the tension slowly.','Rest for the recommended amount of time and repeat.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Isometric_Chest_Squeezes/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Isometric_Chest_Squeezes/1.jpg']::text[]),
('Isometric_Neck_Exercise_-_Front_And_Back','Isometric Neck Exercise - Front And Back','strength','beginner','isolation','static','body only',ARRAY['neck']::text[],ARRAY[]::text[],ARRAY['With your head and neck in a neutral position (normal position with head erect facing forward), place both of your hands on the front side of your head.','Now gently push forward as you contract the neck muscles but resisting any movement of your head. Start with slow tension and increase slowly. Keep breathing normally as you execute this contraction.','Hold for the recommended number of seconds.','Now release the tension slowly.','Rest for the recommended amount of time and repeat with your hands placed on the back side of your head.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Isometric_Neck_Exercise_-_Front_And_Back/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Isometric_Neck_Exercise_-_Front_And_Back/1.jpg']::text[]),
('Isometric_Neck_Exercise_-_Sides','Isometric Neck Exercise - Sides','strength','beginner','isolation','static','body only',ARRAY['neck']::text[],ARRAY[]::text[],ARRAY['With your head and neck in a neutral position (normal position with head erect facing forward), place your left hand on the left side of your head.','Now gently push towards the left as you contract the left neck muscles but resisting any movement of your head. Start with slow tension and increase slowly. Keep breathing normally as you execute this contraction.','Hold for the recommended number of seconds.','Now release the tension slowly.','Rest for the recommended amount of time and repeat with your right hand placed on the right side of your head.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Isometric_Neck_Exercise_-_Sides/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Isometric_Neck_Exercise_-_Sides/1.jpg']::text[]),
('Isometric_Wipers','Isometric Wipers','strength','beginner','compound','push','body only',ARRAY['chest']::text[],ARRAY['abdominals','shoulders','triceps']::text[],ARRAY['Assume a push-up position, supporting your weight on your hands and toes while keeping your body straight. Your hands should be just outside of shoulder width. This will be your starting position.','Begin by shifting your body weight as far to one side as possible, allowing the elbow on that side to flex as you lower your body.','Reverse the motion by extending the flexed arm, pushing yourself up and then dropping to the other side.','Repeat for the desired number of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Isometric_Wipers/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Isometric_Wipers/1.jpg']::text[]),
('JM_Press','JM Press','strength','beginner','compound','push','barbell',ARRAY['triceps']::text[],ARRAY['chest','shoulders']::text[],ARRAY['Start the exercise the same way you would a close grip bench press. You will lie on a flat bench while holding a barbell at arms length (fully extended) with the elbows in. However, instead of having the arms perpendicular to the torso, make sure the bar is set in a direct line above the upper chest. This will be your starting position.','Now beginning from a fully extended position lower the bar down as if performing a lying triceps extension. Inhale as you perform this movement. When you reach the half way point, let the bar roll back about one inch by moving the upper arms towards your legs until they are perpendicular to the torso. Tip: Keep the bend at the elbows constant as you bring the upper arms forward.','As you exhale, press the bar back up by using the triceps to perform a close grip bench press.','Now go back to the starting position and start over.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/JM_Press/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/JM_Press/1.jpg']::text[]),
('Jackknife_Sit-Up','Jackknife Sit-Up','strength','beginner','compound','pull','body only',ARRAY['abdominals']::text[],ARRAY[]::text[],ARRAY['Lie flat on the floor (or exercise mat) on your back with your arms extended straight back behind your head and your legs extended also. This will be your starting position.','As you exhale, bend at the waist while simultaneously raising your legs and arms to meet in a jackknife position. Tip: The legs should be extended and lifted at approximately a 35-45 degree angle from the floor and the arms should be extended and parallel to your legs. The upper torso should be off the floor.','While inhaling, lower your arms and legs back to the starting position.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Jackknife_Sit-Up/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Jackknife_Sit-Up/1.jpg']::text[]),
('Janda_Sit-Up','Janda Sit-Up','strength','beginner','isolation','pull','body only',ARRAY['abdominals']::text[],ARRAY[]::text[],ARRAY['Position your body on the floor in the basic sit-up position; knees to a ninety degree angle with feet flat on the floor and arms either crossed over your chest or to the sides. This will be your starting position.','As you strongly tighten your glutes and hamstrings, fill your lungs with air and in a slow (three to six second count) ascent, slowly exhale. Tip: It is important to tighten the glutes and hamstrings as this will cause the hip flexors to be inactivated in a process called reciprocal inhibition, which basically means that opposite muscles to the contracted ones will relax.','As you inhale, slowly go back in a controlled manner to the starting position.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Janda_Sit-Up/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Janda_Sit-Up/1.jpg']::text[]),
('Jefferson_Squats','Jefferson Squats','strength','intermediate','compound','push','barbell',ARRAY['quadriceps']::text[],ARRAY['calves','glutes','hamstrings','lower back','traps']::text[],ARRAY['Place a barbell on the floor.','Stand in the middle of the bar length wise.','Bend down by bending at the knees and keeping your back straight and grasp the front of the bar with your right hand. Your palm should be in (neutral grip) facing the left side.','Grasp the rear of the bar with your left hand. The palm of your hand should be in neutral grip alignment (palms facing the right side). Tip: Ensure that your grip is even on the bar. Your torso should be positioned right in the middle of the bar and the distance between your torso and your right hand (which should be at the front) should be the same as the distance between your torso and your left hand (which should be to your back).','Now stand straight up with the weight. Tip: Your feet should be shoulder width apart and your toes slightly pointed out.','Squat down by bending at the knees and keeping your back straight until your upper thighs are parallel with the floor. Tip: Keep your back as vertical as possible with the floor and your head up. Also remember to not let your knees go past your toes. Inhale during this portion of the movement.','Now drive yourself back up to the starting position by pushing with the feet . Tip: Keep the bar hanging at arm''s length and your elbows locked with a slight bend. The arms only serve as hooks. Avoid doing any lifting with them. Do the lifting with your thighs; not your arms.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Jefferson_Squats/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Jefferson_Squats/1.jpg']::text[]),
('Jerk_Balance','Jerk Balance','olympic weightlifting','intermediate','compound','push','barbell',ARRAY['shoulders']::text[],ARRAY['glutes','hamstrings','quadriceps','triceps']::text[],ARRAY['This drill helps you learn to drive yourself low enough during the jerk and corrects those who move backward during the movement. Begin with the bar racked in the jerk position, with the shoulders forward, torso upright, and the feet split slightly apart.','Initiate the movement as you would a normal jerk, dipping at the knees while keeping your torso vertical, and driving back up forcefully, using momentum and not your arms to elevate the weight.','Keep the rear foot in place, using it to drive your body forward into a full split as you jerk the weight. Recover by standing up with the weight overhead.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Jerk_Balance/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Jerk_Balance/1.jpg']::text[]),
('Jerk_Dip_Squat','Jerk Dip Squat','olympic weightlifting','intermediate','compound','push','barbell',ARRAY['quadriceps']::text[],ARRAY['abdominals','calves']::text[],ARRAY['This movement strengthens the dip portion of the jerk. Begin with the bar racked in the jerk position, with the shoulders forward to create a shelf and the bar lightly contacting the throat. The feet should be directly under the hips, with the feet turned out as is comfortable.','Keeping the torso vertical, dip by flexing the knees, allowing them to travel forward and without moving the hips to the rear. The dip should not be excessive. Return the weight to the starting position by driving forcefully though the feet.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Jerk_Dip_Squat/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Jerk_Dip_Squat/1.jpg']::text[]),
('Jogging_Treadmill','Jogging, Treadmill','cardio','beginner',NULL,NULL,'machine',ARRAY['quadriceps']::text[],ARRAY['glutes','hamstrings']::text[],ARRAY['To begin, step onto the treadmill and select the desired option from the menu. Most treadmills have a manual setting, or you can select a program to run. Typically, you can enter your age and weight to estimate the amount of calories burned during exercise. Elevation can be adjusted to change the intensity of the workout.','Treadmills offer convenience, cardiovascular benefits, and usually have less impact than jogging outside. A 150 lb person will burn almost 250 calories jogging for 30 minutes, compared to more than 450 calories running. Maintain proper posture as you jog, and only hold onto the handles when necessary, such as when dismounting or checking your heart rate.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Jogging_Treadmill/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Jogging_Treadmill/1.jpg']::text[]),
('Keg_Load','Keg Load','strongman','intermediate','compound','pull','other',ARRAY['lower back']::text[],ARRAY['abdominals','biceps','calves','forearms','glutes','hamstrings','middle back','quadriceps','shoulders','traps']::text[],ARRAY['To load kegs, place the desired number a distance from the loading platform, typically 30-50 feet.','Begin by grabbing the close handle of the first keg, tilting it onto its side to grab the opposite edge of the bottom of the keg. Lift the keg up to your chest.','The higher you can place the keg, the faster you should be able to move to the platform. Shouldering is usually not allowed. Be sure to keep a firm hold on the keg. Move as quickly as possible to the platform, and load it, extending through your hips, knees, and ankles to get it as high as possible.','Return to the starting position to retrieve the next keg, and repeat until the event is completed.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Keg_Load/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Keg_Load/1.jpg']::text[]),
('Kettlebell_Arnold_Press','Kettlebell Arnold Press','strength','intermediate','compound','push','kettlebells',ARRAY['shoulders']::text[],ARRAY['triceps']::text[],ARRAY['Clean a kettlebell to your shoulder. Clean the kettlebell to your shoulder by extending through the legs and hips as you raise the kettlebell towards your shoulder. The palm should be facing inward.','Looking straight ahead, press the kettlebell out and overhead, rotating your wrist so that your palm faces forward at the top of the motion.','Return the kettlebell to the starting position, with the palm facing in.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Arnold_Press/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Arnold_Press/1.jpg']::text[]),
('Kettlebell_Dead_Clean','Kettlebell Dead Clean','strength','intermediate','compound','pull','kettlebells',ARRAY['hamstrings']::text[],ARRAY['calves','glutes','lower back','quadriceps','traps']::text[],ARRAY['Place kettlebell between your feet. To get in the starting position, push your butt back and look straight ahead.','Clean the kettlebell to your shoulder. Clean the kettlebell to your shoulders by extending through the legs and hips as you raise the kettlebell towards your shoulder. The wrist should rotate as you do so.','Lower the kettlebell, keeping the hamstrings loaded by keeping your back straight and your butt out.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Dead_Clean/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Dead_Clean/1.jpg']::text[]),
('Kettlebell_Figure_8','Kettlebell Figure 8','strength','intermediate',NULL,'pull','kettlebells',ARRAY['abdominals']::text[],ARRAY['hamstrings','shoulders']::text[],ARRAY['Place one kettlebell between your legs and take a wider than shoulder width stance. Bend over by pushing your butt out and keeping your back flat.','Pick up a kettlebell and pass it to your other hand between your legs. The receiving hand should reach from behind the legs. Go back and forth for several repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Figure_8/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Figure_8/1.jpg']::text[]),
('Kettlebell_Hang_Clean','Kettlebell Hang Clean','strength','intermediate','compound','pull','kettlebells',ARRAY['hamstrings']::text[],ARRAY['calves','glutes','lower back','shoulders','traps']::text[],ARRAY['Place kettlebell between your feet. To get in the starting position, push your butt back and look straight ahead.','Clean kettlebell to your shoulder. Clean the kettlebell to your shoulders by extending through the legs and hips as you raise the kettlebell towards your shoulder. The wrist should rotate as you do so.','Lower kettlebell to a hanging position between your legs while keeping the hamstrings loaded. Keep your head up at all times.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Hang_Clean/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Hang_Clean/1.jpg']::text[]),
('Kettlebell_One-Legged_Deadlift','Kettlebell One-Legged Deadlift','strength','intermediate','compound','pull','kettlebells',ARRAY['hamstrings']::text[],ARRAY['glutes','lower back']::text[],ARRAY['Hold a kettlebell by the handle in one hand. Stand on one leg, on the same side that you hold the kettlebell.','Keeping that knee slightly bent, perform a stiff legged deadlift by bending at the hip, extending your free leg behind you for balance.','Continue lowering the kettlebell until you are parallel to the ground, and then return to the upright position.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_One-Legged_Deadlift/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_One-Legged_Deadlift/1.jpg']::text[]),
('Kettlebell_Pass_Between_The_Legs','Kettlebell Pass Between The Legs','strength','intermediate','compound','pull','kettlebells',ARRAY['abdominals']::text[],ARRAY['glutes','hamstrings','shoulders']::text[],ARRAY['Place one kettlebell between your legs and take a comfortable stance. Bend over by pushing your butt out and keeping your back flat.','Pick up a kettlebell and pass it to your other hand between your legs, in the fashion of a "W". Go back and forth for several repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Pass_Between_The_Legs/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Pass_Between_The_Legs/1.jpg']::text[]),
('Kettlebell_Pirate_Ships','Kettlebell Pirate Ships','strength','beginner','compound','push','kettlebells',ARRAY['shoulders']::text[],ARRAY['abdominals']::text[],ARRAY['With a wide stance, hold a kettlebell with both hands. Allow it to hang at waist level with your arms extended. This will be your starting position.','Initiate the movement by turning to one side, swinging the kettlebell to head height. Briefly pause at the top of the motion.','Allow the bell to drop as you rotate to the opposite side, again raising the kettlebell to head height.','Repeat for the desired amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Pirate_Ships/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Pirate_Ships/1.jpg']::text[]),
('Kettlebell_Pistol_Squat','Kettlebell Pistol Squat','strength','expert','compound','push','kettlebells',ARRAY['quadriceps']::text[],ARRAY['calves','glutes','hamstrings','shoulders']::text[],ARRAY['Pick up a kettlebell with two hands and hold it by the horns. Hold one leg off of the floor and squat down on the other.','Squat down by flexing the knee and sitting back with the hips, holding the kettlebell up in front of you.','Hold the bottom position for a second and then reverse the motion, driving through the heel and keeping your head and chest up.','Lower yourself again and repeat.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Pistol_Squat/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Pistol_Squat/1.jpg']::text[]),
('Kettlebell_Seated_Press','Kettlebell Seated Press','strength','intermediate','compound','push','kettlebells',ARRAY['shoulders']::text[],ARRAY['triceps']::text[],ARRAY['Sit on the floor and spread your legs out comfortably.','Clean one kettlebell to your shoulder.','Press the kettlebell up and out until it is locked out overhead. Return to the starting position.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Seated_Press/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Seated_Press/1.jpg']::text[]),
('Kettlebell_Seesaw_Press','Kettlebell Seesaw Press','strength','intermediate','compound','push','kettlebells',ARRAY['shoulders']::text[],ARRAY['triceps']::text[],ARRAY['Clean two kettlebells two your shoulders.','Press one kettlebell.','Lower the kettlebell and immediately press the other kettlebell. Make sure to do the same amount of reps on both sides.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Seesaw_Press/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Seesaw_Press/1.jpg']::text[]),
('Kettlebell_Sumo_High_Pull','Kettlebell Sumo High Pull','strength','intermediate','compound','pull','kettlebells',ARRAY['traps']::text[],ARRAY['adductors','glutes','hamstrings','quadriceps','shoulders']::text[],ARRAY['Place a kettlebell on the ground between your feet. Position your feet in a wide stance, and grasp the kettlebell with two hands. Set your hips back as far as possible, with your knees bent. Keep your chest and head up. This will be your starting position.','Begin by extending the hips and knees, simultaneously pulling the kettlebell to your shoulders, raising your elbows as you do so. Reverse the motion to return to the starting position.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Sumo_High_Pull/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Sumo_High_Pull/1.jpg']::text[]),
('Kettlebell_Thruster','Kettlebell Thruster','strength','intermediate','compound','push','kettlebells',ARRAY['shoulders']::text[],ARRAY['quadriceps','triceps']::text[],ARRAY['Clean two kettlebells to your shoulders. Clean the kettlebells to your shoulders by extending through the legs and hips as you pull the kettlebells towards your shoulders. Rotate your wrists as you do so. This will be your starting position.','Begin to squat by flexing your hips and knees, lowering your hips between your legs. Maintain an upright, straight back as you descend as low as you can.','At the bottom, reverse direction and squat by extending your knees and hips, driving through your heels. As you do so, press both kettlebells overhead by extending your arms straight up, using the momentum from the squat to help drive the weights upward.','As you begin the next repetition, return the weights to the shoulders.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Thruster/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Thruster/1.jpg']::text[]),
('Kettlebell_Turkish_Get-Up_Lunge_style','Kettlebell Turkish Get-Up (Lunge style)','strength','intermediate','compound','push','kettlebells',ARRAY['shoulders']::text[],ARRAY['abdominals','hamstrings','quadriceps','triceps']::text[],ARRAY['Lie on your back on the floor and press a kettlebell to the top position by extending the elbow. Bend the knee on the same side as the kettlebell.','Keeping the kettlebell locked out at all times, pivot to the opposite side and use your non- working arm to assist you in driving forward to the lunge position. Using your free hand, push yourself to a seated position, then progressing to one knee.','While looking up at the kettlebell, slowly stand up. Reverse the motion back to the starting position and repeat.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Turkish_Get-Up_Lunge_style/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Turkish_Get-Up_Lunge_style/1.jpg']::text[]),
('Kettlebell_Turkish_Get-Up_Squat_style','Kettlebell Turkish Get-Up (Squat style)','strength','intermediate','compound','push','kettlebells',ARRAY['shoulders']::text[],ARRAY['abdominals','calves','hamstrings','quadriceps','triceps']::text[],ARRAY['Lie on your back on the floor and press a kettlebell to the top position by extending the elbow. Bend the knee on the same side as the kettlebell.','Keeping the kettlebell locked out at all times, pivot to the opposite side and use your non- working arm to assist you in driving forward to the lunge position.','Using your free hand, push yourself to a seated position, then progressing to your feet. While looking up at the kettlebell, slowly stand up. Reverse the motion back to the starting position and repeat.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Turkish_Get-Up_Squat_style/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Turkish_Get-Up_Squat_style/1.jpg']::text[]),
('Kettlebell_Windmill','Kettlebell Windmill','strength','intermediate','compound','pull','kettlebells',ARRAY['abdominals']::text[],ARRAY['glutes','hamstrings','shoulders','triceps']::text[],ARRAY['Place a kettlebell in front of your lead foot and clean and press it overhead with your opposite arm. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulders. Rotate your wrist as you do so, so that the palm faces forward. Press it overhead by extending the elbow.','Keeping the kettlebell locked out at all times, push your butt out in the direction of the locked out kettlebell. Turn your feet out at a forty-five degree angle from the arm with the locked out kettlebell. Bending at the hip to one side, sticking your butt out, slowly lean until you can touch the floor with your free hand. Keep your eyes on the kettlebell that you hold over your head at all times.','Pause for a second after reaching the ground and reverse the motion back to the starting position.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Windmill/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kettlebell_Windmill/1.jpg']::text[]),
('Kipping_Muscle_Up','Kipping Muscle Up','strength','intermediate','compound','pull','other',ARRAY['lats']::text[],ARRAY['abdominals','biceps','forearms','middle back','shoulders','traps','triceps']::text[],ARRAY['Grip the rings using a false grip, with the base of your palms on top of the rings.','Begin with a movement swinging your legs backward slightly.','Counter that movement by swinging your legs forward and up, jerking your chin and chest back, pulling yourself up with both arms as you do so. As you reach the top position of the pull-up, pull the rings to your armpits as you roll your shoulders forward, allowing your elbows to move straight back behind you. This puts you into the proper position to continue into the dip portion of the movement.','Maintaining control and stability, extend through the elbow to complete the motion.','Use care when lowering yourself to the ground.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kipping_Muscle_Up/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kipping_Muscle_Up/1.jpg']::text[]),
('Knee_Across_The_Body','Knee Across The Body','stretching','beginner',NULL,'static',NULL,ARRAY['glutes']::text[],ARRAY['abductors','lower back']::text[],ARRAY['Lie down on the floor with your right leg straight. Bend your left leg and lower it across your body, holding the knee down toward the floor with your right hand. (The knee doesn''t need to touch the floor if you''re tight.)','Place your left arm comfortably beside you and turn your head to the left. Imagine you have a weight tied to your tailbone. let your tailbone fall back toward the floor as your chest reaches in the opposite direction to stretch your lower back. Switch sides.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Knee_Across_The_Body/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Knee_Across_The_Body/1.jpg']::text[]),
('Knee_Circles','Knee Circles','stretching','beginner','compound','pull','body only',ARRAY['calves']::text[],ARRAY['hamstrings','quadriceps']::text[],ARRAY['Stand with your legs together and hands by your waist.','Now move your knees in a circular motion as you breathe normally.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Knee_Circles/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Knee_Circles/1.jpg']::text[]),
('Knee_Hip_Raise_On_Parallel_Bars','Knee/Hip Raise On Parallel Bars','strength','beginner','isolation','pull','other',ARRAY['abdominals']::text[],ARRAY[]::text[],ARRAY['Position your body on the vertical leg raise bench so that your forearms are resting on the pads next to the torso and holding on to the handles. Your arms will be bent at a 90 degree angle.','The torso should be straight with the lower back pressed against the pad of the machine and the legs extended pointing towards the floor. This will be your starting position.','Now as you breathe out, lift your legs up as you keep them extended. Continue this movement until your legs are roughly parallel to the floor and then hold the contraction for a second. Tip: Do not use any momentum or swinging as you perform this exercise.','Slowly go back to the starting position as you breathe in.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Knee_Hip_Raise_On_Parallel_Bars/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Knee_Hip_Raise_On_Parallel_Bars/1.jpg']::text[]),
('Knee_Tuck_Jump','Knee Tuck Jump','plyometrics','beginner','compound','push','body only',ARRAY['hamstrings']::text[],ARRAY['abductors','adductors','calves','glutes','quadriceps']::text[],ARRAY['Begin in a comfortable standing position with your knees slightly bent. Hold your hands in front of you, palms down with your fingertips together at chest height. This will be your starting position.','Rapidly dip down into a quarter squat and immediately explode upward. Drive the knees towards the chest, attempting to touch them to the palms of the hands.','Jump as high as you can, raising your knees up, and then ensure a good land be re-extending your legs, absorbing impact through be allowing the knees to rebend.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Knee_Tuck_Jump/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Knee_Tuck_Jump/1.jpg']::text[]),
('Kneeling_Arm_Drill','Kneeling Arm Drill','plyometrics','beginner',NULL,'pull',NULL,ARRAY['shoulders']::text[],ARRAY['abdominals']::text[],ARRAY['This drill helps increase arm efficiency during the run. Begin kneeling, left foot in front, right knee down. Apply pressure through the front heel to keep your glutes and hamstrings activated.','Begin by blocking the arms in long, pendulum like swings. Close the arm angle, blocking with the arms as you would when jogging, progressing to a run and finally a sprint.','As soon as your hands pass the hip, accelerate them forward during the sprinting motion to move them as quickly as possible.','Switch knees and repeat.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Arm_Drill/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Arm_Drill/1.jpg']::text[]),
('Kneeling_Cable_Crunch_With_Alternating_Oblique_Twists','Kneeling Cable Crunch With Alternating Oblique Twists','strength','beginner','isolation','pull','cable',ARRAY['abdominals']::text[],ARRAY[]::text[],ARRAY['Connect a rope attachment to a high pulley cable and position a mat on the floor in front of it.','Grab the rope with both hands and kneel approximately two feet back from the tower.','Position the rope behind your head with your hands by your ears.','Keep your hands in the same place, contract your abs and pull downward on the rope in a crunching movement until your elbows reach your knees.','Pause briefly at the bottom and rise up in a slow and controlled manner until you reach the starting position.','Repeat the same downward movement until you''re halfway down, at which time you''ll begin rotating one of your elbows to the opposite knee.','Again, pause briefly at the bottom and rise up in a slow and controlled manner until you reach the starting position.','Repeat the same movement as before, but alternate the other elbow to the opposite knee.','Continue this series of movements to failure.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Cable_Crunch_With_Alternating_Oblique_Twists/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Cable_Crunch_With_Alternating_Oblique_Twists/1.jpg']::text[]),
('Kneeling_Cable_Triceps_Extension','Kneeling Cable Triceps Extension','strength','intermediate','isolation','push','cable',ARRAY['triceps']::text[],ARRAY[]::text[],ARRAY['Place a bench sideways in front of a high pulley machine.','Hold a straight bar attachment above your head with your hands about 6 inches apart with your palms facing down.','Face away from the machine and kneel.','Place your head and the back of your upper arms on the bench. Your elbows should be bent with the forearms pointing towards the high pulley. This will be your starting position.','While keeping your upper arms close to your head at all times with the elbows in, press the bar out in a semicircular motion until the elbows are locked and your arms are parallel to the floor. Contract the triceps hard and keep this position for a second. Exhale as you perform this movement.','Slowly return to the starting position as you breathe in.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Cable_Triceps_Extension/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Cable_Triceps_Extension/1.jpg']::text[]),
('Kneeling_Forearm_Stretch','Kneeling Forearm Stretch','stretching','beginner','isolation','static',NULL,ARRAY['forearms']::text[],ARRAY[]::text[],ARRAY['Start by kneeling on a mat with your palms flat and your fingers pointing back toward your knees.','Slowly lean back keeping your palms flat on the floor until you feel a stretch in your wrists and forearms. Hold for 20-30 seconds.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Forearm_Stretch/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Forearm_Stretch/1.jpg']::text[]),
('Kneeling_High_Pulley_Row','Kneeling High Pulley Row','strength','beginner','compound','pull','cable',ARRAY['lats']::text[],ARRAY['biceps','middle back']::text[],ARRAY['Select the appropriate weight using a pulley that is above your head. Attach a rope to the cable and kneel a couple of feet away, holding the rope out in front of you with both arms extended. This will be your starting position.','Initiate the movement by flexing the elbows and fully retracting your shoulders, pulling the rope toward your upper chest with your elbows out.','After pausing briefly, slowly return to the starting position.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_High_Pulley_Row/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_High_Pulley_Row/1.jpg']::text[]),
('Kneeling_Hip_Flexor','Kneeling Hip Flexor','stretching','beginner','isolation','static',NULL,ARRAY['quadriceps']::text[],ARRAY['quadriceps']::text[],ARRAY['Kneel on a mat and bring your right knee up so the bottom of your foot is on the floor and extend your left leg out behind you so the top of your foot is on the floor.','Shift your weight forward until you feel a stretch in your hip. Hold for 15 seconds, then repeat for your other side.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Hip_Flexor/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Hip_Flexor/1.jpg']::text[]),
('Kneeling_Jump_Squat','Kneeling Jump Squat','olympic weightlifting','expert','compound','push','barbell',ARRAY['glutes']::text[],ARRAY['calves','hamstrings','quadriceps']::text[],ARRAY['Begin kneeling on the floor with a barbell racked across the back of your shoulders, or you can use your body weight for this exercise. This can be done inside of a power rack to make unracking easier.','Sit back with your hips until your glutes touch your feet, keeping your head and chest up.','Explode up with your hips, generating enough power to land with your feet flat on the floor.','Continue with the squat by driving through your heels and extending the knees to come to a standing position.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Jump_Squat/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Jump_Squat/1.jpg']::text[]),
('Kneeling_Single-Arm_High_Pulley_Row','Kneeling Single-Arm High Pulley Row','strength','beginner','compound','pull','cable',ARRAY['lats']::text[],ARRAY['biceps','middle back']::text[],ARRAY['Attach a single handle to a high pulley and make your weight selection.','Kneel in front of the cable tower, taking the cable with one hand with your arm extended. This will be your starting position.','Starting with your palm facing forward, pull the weight down to your torso by flexing the elbow and retract the shoulder blade. As you do so, rotate the wrist so that at the completion of the movement, your palm is now facing you.','After a brief pause, return to the starting position.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Single-Arm_High_Pulley_Row/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Single-Arm_High_Pulley_Row/1.jpg']::text[]),
('Kneeling_Squat','Kneeling Squat','powerlifting','intermediate','compound','push','barbell',ARRAY['glutes']::text[],ARRAY['abdominals','hamstrings','lower back']::text[],ARRAY['Set the bar to the proper height in a power rack. Kneel behind the bar; it may be beneficial to put a mat down to pad your knees. Slide under the bar, racking it across the back of your shoulders. Your shoulder blades should be retracted and the bar tight across your back. Unrack the weight.','With your head looking forward, sit back with your butt until you touch your calves.','Reverse the motion, returning the torso to an upright position.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Squat/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Kneeling_Squat/1.jpg']::text[]),
('Landmine_180s','Landmine 180''s','strength','beginner','compound','pull','barbell',ARRAY['abdominals']::text[],ARRAY['glutes','lower back','shoulders']::text[],ARRAY['Position a bar into a landmine or securely anchor it in a corner. Load the bar to an appropriate weight.','Raise the bar from the floor, taking it to shoulder height with both hands with your arms extended in front of you. Adopt a wide stance. This will be your starting position.','Perform the movement by rotating the trunk and hips as you swing the weight all the way down to one side. Keep your arms extended throughout the exercise.','Reverse the motion to swing the weight all the way to the opposite side.','Continue alternating the movement until the set is complete.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Landmine_180s/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Landmine_180s/1.jpg']::text[]),
('Landmine_Linear_Jammer','Landmine Linear Jammer','strength','intermediate','compound','push','barbell',ARRAY['shoulders']::text[],ARRAY['abdominals','calves','chest','hamstrings','quadriceps','triceps']::text[],ARRAY['Position a bar into landmine or, lacking one, securely anchor it in a corner. Load the bar to an appropriate weight and position the handle attachment on the bar.','Raise the bar from the floor, taking the handles to your shoulders. This will be your starting position.','In an athletic stance, squat by flexing your hips and setting your hips back, keeping your arms flexed.','Reverse the motion by powerfully extending through the hips, knees, and ankles, while also extending the elbows to straighten the arms. This movement should be done explosively, coming out of the squat to full extension as powerfully as possible.','Return to the starting position.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Landmine_Linear_Jammer/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Landmine_Linear_Jammer/1.jpg']::text[]),
('Lateral_Bound','Lateral Bound','plyometrics','beginner','compound','push','body only',ARRAY['adductors']::text[],ARRAY['abductors','calves','glutes','hamstrings','quadriceps']::text[],ARRAY['Assume a half squat position facing 90 degrees from your direction of travel. This will be your starting position.','Allow your lead leg to do a countermovement inward as you shift your weight to the outside leg.','Immediately push off and extend, attempting to bound to the side as far as possible.','Upon landing, immediately push off in the opposite direction, returning to your original start position.','Continue back and forth for several repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lateral_Bound/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lateral_Bound/1.jpg']::text[]),
('Lateral_Box_Jump','Lateral Box Jump','plyometrics','beginner','compound','push','other',ARRAY['adductors']::text[],ARRAY['abductors','calves','glutes','hamstrings','quadriceps']::text[],ARRAY['Assume a comfortable standing position, with a short box positioned next to you. This will be your starting position.','Quickly dip into a quarter squat to initiate the stretch reflex, and immediately reverse direction to jump up and to the side.','Bring your knees high enough to ensure your feet have good clearance over the box.','Land on the center of the box, using your legs to absorb the impact.','Carefully jump down to the other side of the box, and continue going back and forth for several repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lateral_Box_Jump/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lateral_Box_Jump/1.jpg']::text[]),
('Lateral_Cone_Hops','Lateral Cone Hops','plyometrics','beginner','compound','push','other',ARRAY['adductors']::text[],ARRAY['abductors','calves','glutes','hamstrings','quadriceps']::text[],ARRAY['Position a number of cones in a row several feet apart.','Stand next to the end of the cones, facing 90 degrees to the direction of travel. This will be your starting position.','Begin the jump by dipping with the knees to initiate a stretch reflex, and immediately reverse direction to push off the ground, jumping up and sideways over the cone.','Use your legs to absorb impact upon landing, and rebound into the next jump, continuing down the row of cones.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lateral_Cone_Hops/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lateral_Cone_Hops/1.jpg']::text[]),
('Lateral_Raise_-_With_Bands','Lateral Raise - With Bands','strength','beginner','isolation','push','bands',ARRAY['shoulders']::text[],ARRAY[]::text[],ARRAY['To begin, stand on an exercise band so that tension begins at arm''s length. Grasp the handles using a pronated (palms facing your thighs) grip that is slightly less than shoulder width. The handles should be resting on the sides of your thighs. Your arms should be extended with a slight bend at the elbows and your back should be straight. This will be your starting position.','Use your side shoulders to lift the handles to the sides as you exhale. Continue to lift the handles until they are slightly above parallel. Tip: As you lift the handles, slightly tilt the hand as if you were pouring water and keep your arms extended. Also, keep your torso stationary and pause for a second at the top of the movement.','Lower the handles back down slowly to the starting position. Inhale as you perform this portion of the movement.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lateral_Raise_-_With_Bands/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lateral_Raise_-_With_Bands/1.jpg']::text[]),
('Latissimus_Dorsi-SMR','Latissimus Dorsi-SMR','stretching','beginner','isolation','static','foam roll',ARRAY['lats']::text[],ARRAY[]::text[],ARRAY['While lying on the floor, place a foam roll under your back and to one side, just behind your arm pit. This will be your starting position.','Keep the arm of the side being stretched behind and to the side of you as you shift your weight onto your lats, keeping your upper body off of the ground. Hold for 10-30 seconds, and switch sides.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Latissimus_Dorsi-SMR/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Latissimus_Dorsi-SMR/1.jpg']::text[]),
('Leg-Over_Floor_Press','Leg-Over Floor Press','strength','intermediate','compound','push','kettlebells',ARRAY['chest']::text[],ARRAY['shoulders','triceps']::text[],ARRAY['Lie on the floor with one kettlebell in place on your chest, holding it by the handle. Extend leg on working side over leg on non-working side.Your free arm can be extended out to your side for support.','Press the kettlebll into a locked out position.','Lower the weight until the elbow touches the ground, keeping the kettlebell above the elbow. Repeat for the desired number of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leg-Over_Floor_Press/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leg-Over_Floor_Press/1.jpg']::text[]),
('Leg-Up_Hamstring_Stretch','Leg-Up Hamstring Stretch','stretching','beginner','isolation','push',NULL,ARRAY['hamstrings']::text[],ARRAY[]::text[],ARRAY['Lie flat on your back, bend one knee, and put that foot flat on the floor to stabilize your spine.','Extend the other leg in the air. If you''re tight, you wont be able to straighten it. That''s okay. Extend the knee so that the sole of the lifted foot faces the ceiling (or as close as you can get it).','Slowly straighten the legs as much as possible and then pull the leg toward your nose. Switch sides.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leg-Up_Hamstring_Stretch/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leg-Up_Hamstring_Stretch/1.jpg']::text[]),
('Leg_Extensions','Leg Extensions','strength','beginner','isolation','push','machine',ARRAY['quadriceps']::text[],ARRAY[]::text[],ARRAY['For this exercise you will need to use a leg extension machine. First choose your weight and sit on the machine with your legs under the pad (feet pointed forward) and the hands holding the side bars. This will be your starting position. Tip: You will need to adjust the pad so that it falls on top of your lower leg (just above your feet). Also, make sure that your legs form a 90-degree angle between the lower and upper leg. If the angle is less than 90-degrees then that means the knee is over the toes which in turn creates undue stress at the knee joint. If the machine is designed that way, either look for another machine or just make sure that when you start executing the exercise you stop going down once you hit the 90-degree angle.','Using your quadriceps, extend your legs to the maximum as you exhale. Ensure that the rest of the body remains stationary on the seat. Pause a second on the contracted position.','Slowly lower the weight back to the original position as you inhale, ensuring that you do not go past the 90-degree angle limit.','Repeat for the recommended amount of times.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leg_Extensions/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leg_Extensions/1.jpg']::text[]),
('Leg_Lift','Leg Lift','strength','beginner','isolation','push','body only',ARRAY['glutes']::text[],ARRAY['hamstrings']::text[],ARRAY['While standing up straight with both feet next to each other at around shoulder width, grab a sturdy surface such as the sides of a squat rack or the top of a chair to brace yourself and keep balance.','With or without an ankle weight, lift one leg behind you as if performing a leg curl but standing up while keeping the other leg straight. Breathe out as you perform this movement.','Slowly bring the raised leg back to the floor as you breathe in.','Repeat for the recommended amount of repetitions.','Repeat the movement with the opposite leg.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leg_Lift/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leg_Lift/1.jpg']::text[]),
('Leg_Press','Leg Press','strength','beginner','compound','push','machine',ARRAY['quadriceps']::text[],ARRAY['calves','glutes','hamstrings']::text[],ARRAY['Using a leg press machine, sit down on the machine and place your legs on the platform directly in front of you at a medium (shoulder width) foot stance. (Note: For the purposes of this discussion we will use the medium stance described above which targets overall development; however you can choose any of the three stances described in the foot positioning section).','Lower the safety bars holding the weighted platform in place and press the platform all the way up until your legs are fully extended in front of you. Tip: Make sure that you do not lock your knees. Your torso and the legs should make a perfect 90-degree angle. This will be your starting position.','As you inhale, slowly lower the platform until your upper and lower legs make a 90-degree angle.','Pushing mainly with the heels of your feet and using the quadriceps go back to the starting position as you exhale.','Repeat for the recommended amount of repetitions and ensure to lock the safety pins properly once you are done. You do not want that platform falling on you fully loaded.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leg_Press/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leg_Press/1.jpg']::text[]),
('Leg_Pull-In','Leg Pull-In','strength','beginner','compound','pull','body only',ARRAY['abdominals']::text[],ARRAY[]::text[],ARRAY['Lie on an exercise mat with your legs extended and your hands either palms facing down next to you or under your glutes. Tip: My preference is with the hands next to me. This will be your starting position.','Bend your knees and pull your upper thighs into your midsection as you breathe out. Continue the motion until your knees are around chest level. Contract your abs as you execute this movement and hold for a second at the top. Tip: As you perform the motion, the lower legs (calves) should always remain parallel to the floor.','Return to the starting position as you inhale.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leg_Pull-In/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leg_Pull-In/1.jpg']::text[]),
('Leverage_Chest_Press','Leverage Chest Press','strength','beginner','compound','push','machine',ARRAY['chest']::text[],ARRAY['shoulders','triceps']::text[],ARRAY['Load an appropriate weight onto the pins and adjust the seat for your height. The handles should be near the bottom or middle of the pectorals at the beginning of the motion.','Your chest and head should be up and your shoulder blades retracted. This will be your starting position.','Press the handles forward by extending through the elbow.','After a brief pause at the top, return the weight just above the start position, keeping tension on the muscles by not returning the weight to the stops until the set is complete.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leverage_Chest_Press/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leverage_Chest_Press/1.jpg']::text[]),
('Leverage_Deadlift','Leverage Deadlift','strength','beginner','compound','pull','machine',ARRAY['quadriceps']::text[],ARRAY['glutes','hamstrings']::text[],ARRAY['Load the pins to an appropriate weight. Position yourself directly between the handles. Grasp the bottom handles with a comfortable grip, and then lower your hips as you take a breath. Look forward with your head and keep your chest up. This will be your starting position.','Return the weight to the starting position.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leverage_Deadlift/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leverage_Deadlift/1.jpg']::text[]),
('Leverage_Decline_Chest_Press','Leverage Decline Chest Press','strength','beginner','compound','push','machine',ARRAY['chest']::text[],ARRAY['shoulders','triceps']::text[],ARRAY['Load an appropriate weight onto the pins and adjust the seat for your height. The handles should be near the bottom of the pectorals at the beginning of the motion. Your chest and head should be up and your shoulder blades retracted. This will be your starting position.','Press the handles forward by extending through the elbow.','After a brief pause at the top, return the weight just above the start position, keeping tension on the muscles by not returning the weight to the stops until the set is complete.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leverage_Decline_Chest_Press/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leverage_Decline_Chest_Press/1.jpg']::text[]),
('Leverage_High_Row','Leverage High Row','strength','beginner','compound','pull','machine',ARRAY['middle back']::text[],ARRAY['lats']::text[],ARRAY['Load an appropriate weight onto the pins and adjust the seat height so that you can just reach the handles above you. Adjust the knee pad to help keep you down. Grasp the handles with a pronated grip. This will be your starting position.','Pull the handles towards your torso, retracting your shoulder blades as you flex the elbow.','Pause at the bottom of the motion, and then slowly return the handles to the starting position.','For multiple repetitions, avoid completely returning the weight to the stops to keep tension on the muscles being worked.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leverage_High_Row/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leverage_High_Row/1.jpg']::text[]),
('Leverage_Incline_Chest_Press','Leverage Incline Chest Press','strength','beginner','compound','push','machine',ARRAY['chest']::text[],ARRAY['shoulders','triceps']::text[],ARRAY['Load an appropriate weight onto the pins and adjust the seat for your height. The handles should be near the top of the pectorals at the beginning of the motion. Your chest and head should be up and your shoulder blades retracted. This will be your starting position.','Press the handles forward by extending through the elbow.','After a brief pause at the top, return the weight just above the start position, keeping tension on the muscles by not returning the weight to the stops until the set is complete.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leverage_Incline_Chest_Press/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leverage_Incline_Chest_Press/1.jpg']::text[]),
('Leverage_Iso_Row','Leverage Iso Row','strength','beginner','compound','pull','machine',ARRAY['lats']::text[],ARRAY['biceps','middle back']::text[],ARRAY['Load an appropriate weight onto the pins and adjust the seat height so that the handles are at chest level. Grasp the handles with either a neutral or pronated grip. This will be your starting position.','Pull the handles towards your torso, retracting your shoulder blades as you flex the elbow.','Pause at the bottom of the motion, and then slowly return the handles to the starting position. For multiple repetitions, avoid completely returning the weight to the stops to keep tension on the muscles being worked.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leverage_Iso_Row/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leverage_Iso_Row/1.jpg']::text[]),
('Leverage_Shoulder_Press','Leverage Shoulder Press','strength','beginner','compound','push','machine',ARRAY['shoulders']::text[],ARRAY['triceps']::text[],ARRAY['Load an appropriate weight onto the pins and adjust the seat for your height. The handles should be near the top of the shoulders at the beginning of the motion. Your chest and head should be up and handles held with a pronated grip. This will be your starting position.','Press the handles upward by extending through the elbow.','After a brief pause at the top, return the weight to just above the start position, keeping tension on the muscles by not returning the weight to the stops until the set is complete.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leverage_Shoulder_Press/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leverage_Shoulder_Press/1.jpg']::text[]),
('Leverage_Shrug','Leverage Shrug','strength','beginner','isolation','pull','machine',ARRAY['traps']::text[],ARRAY['forearms']::text[],ARRAY['Load the pins to an appropriate weight. Position yourself directly between the handles.','Grasp the top handles with a comfortable grip, and then lower your hips as you take a breath. Look forward with your head and keep your chest up.','Drive through the floor with your heels, extending your hips and knees as you rise to a standing position. Keep your arms straight throughout the movement, finishing with your shoulders back. This will be your starting position.','Raise the weight by shrugging the shoulders towards your ears, moving straight up and down.','Pause at the top of the motion, and then return the weight to the starting position.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leverage_Shrug/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Leverage_Shrug/1.jpg']::text[]),
('Linear_3-Part_Start_Technique','Linear 3-Part Start Technique','plyometrics','beginner','compound','push',NULL,ARRAY['hamstrings']::text[],ARRAY['calves','quadriceps']::text[],ARRAY['This drill helps you accelerate as quickly as possible into a sprint from a dead stop. It helps to use a line to start from. Begin with two feet on the line. Place your left foot with the toe next to your right ankle. Place your right foot 4-6 inches behind the left.','Place your right hand onto the line, and thing bring your nose close to your left knee.','Squat down as you lean foward, your head being lower than your hips and your weight loaded onto the left leg. This will be your starting position.','Take your left hand up so that it is parallel to the ground, pointing behind you, and explode out when ready.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Linear_3-Part_Start_Technique/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Linear_3-Part_Start_Technique/1.jpg']::text[]),
('Linear_Acceleration_Wall_Drill','Linear Acceleration Wall Drill','plyometrics','beginner','compound',NULL,NULL,ARRAY['hamstrings']::text[],ARRAY['calves','glutes','quadriceps']::text[],ARRAY['Lean at around 45 degrees against a wall. Your feet should be together, glutes contracted.','Begin by lifting your right knee quickly, pausing, and then driving it straight down into the ground.','Switch legs, raising the opposite knee, and then attacking the ground straight down.','Repeat once more with your right leg, and as soon as the right foot strikes the ground hammer them out rapidly, alternating left and right as fast as you can.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Linear_Acceleration_Wall_Drill/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Linear_Acceleration_Wall_Drill/1.jpg']::text[]),
('Linear_Depth_Jump','Linear Depth Jump','plyometrics','intermediate','compound','push','other',ARRAY['quadriceps']::text[],ARRAY['calves','glutes','hamstrings']::text[],ARRAY['You will need two boxes or benches spaced a few feet away from each other. Begin by standing on one box facing towards the other platform.','To initiate the movement, gently drop down to the ground between your platforms, allowing the knees and hips to flex.','Reverse the motion by exploding, extending through the hips, knees, and ankles to jump onto the other platform.','Land softly, asborbing the impact through the legs.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Linear_Depth_Jump/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Linear_Depth_Jump/1.jpg']::text[]),
('Log_Lift','Log Lift','strongman','intermediate','compound','push','other',ARRAY['shoulders']::text[],ARRAY['abdominals','chest','glutes','hamstrings','lower back','middle back','quadriceps','traps','triceps']::text[],ARRAY['Begin standing with the log in front of you. Grasp the handles, and begin to clean the log. As you are bent over to start the clean, attempt to get the log as high as possible, pulling it into your chest. Extend through the hips and knees to bring it up to complete the clean.','Push your head back and look up, creating a shelf on your chest to rest the log. Begin the press by dipping, flexing slightly through the knees and reversing the motion. This push press will generate momentum to start the log moving vertically. Continue by extending through the elbows to press the log above your head. There are no strict rules on form, so use whatever techniques you are most efficient with. As the log is pressed, ensure that you push your head through on each repetition, looking forward.','Repeat as many times as possible. Attempt to control the descent of the log as it is returned to the ground.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Log_Lift/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Log_Lift/1.jpg']::text[]),
('London_Bridges','London Bridges','strength','intermediate','compound','pull','other',ARRAY['lats']::text[],ARRAY['biceps','forearms','middle back']::text[],ARRAY['Attach a climbing rope to a high beam or cross member. Below it, ensure that the smith machine bar is locked in place with the safeties and cannot move. Alternatively, a secure box could also be utilized.','Stand on the bar, using the rope to balance yourself. This will be your starting position.','Keeping your body straight, lean back and lower your body by slowly going hand over hand with the rope. Continue until you are perpendicular to the ground.','Keeping your body straight, reverse the motion, going hand over hand back to the starting position.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/London_Bridges/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/London_Bridges/1.jpg']::text[]),
('Looking_At_Ceiling','Looking At Ceiling','stretching','beginner','isolation','static',NULL,ARRAY['quadriceps']::text[],ARRAY[]::text[],ARRAY['Kneel on the floor, holding your heels with both hands.','Lift your buttocks up and forward while bringing your head back to look up at the ceiling, to give an arch in your back.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Looking_At_Ceiling/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Looking_At_Ceiling/1.jpg']::text[]),
('Low_Cable_Crossover','Low Cable Crossover','strength','beginner','isolation','push','cable',ARRAY['chest']::text[],ARRAY['shoulders']::text[],ARRAY['To move into the starting position, place the pulleys at the low position, select the resistance to be used and grasp a handle in each hand.','Step forward, gaining tension in the pulleys. Your palms should be facing forward, hands below the waist, and your arms straight. This will be your starting position.','With a slight bend in your arms, draw your hands upward and toward the midline of your body. Your hands should come together in front of your chest, palms facing up.','Return your arms back to the starting position after a brief pause.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Low_Cable_Crossover/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Low_Cable_Crossover/1.jpg']::text[]),
('Low_Cable_Triceps_Extension','Low Cable Triceps Extension','strength','beginner','isolation','push','cable',ARRAY['triceps']::text[],ARRAY[]::text[],ARRAY['Select the desired weight and lay down face up on the bench of a seated row machine that has a rope attached to it. Your head should be pointing towards the attachment.','Grab the outside of the rope ends with your palms facing each other (neutral grip).','Position your elbows so that they are bent at a 90 degree angle and your upper arms are perpendicular (90 degree angle) to your torso. Tip: Keep the elbows in and make sure that the upper arms point to the ceiling while your forearms point towards the pulley above your head. This will be your starting position.','As you breathe out, extend your lower arms until they are straight and vertical. The upper arms and elbows remain stationary throughout the movement. Only the forearms should move. Contract the triceps hard for a second.','As you breathe in slowly return to the starting position.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Low_Cable_Triceps_Extension/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Low_Cable_Triceps_Extension/1.jpg']::text[]),
('Low_Pulley_Row_To_Neck','Low Pulley Row To Neck','strength','beginner','compound','pull','cable',ARRAY['shoulders']::text[],ARRAY['biceps','middle back','traps']::text[],ARRAY['Sit on a low pulley row machine with a rope attachment.','Grab the ends of the rope using a palms-down grip and sit with your back straight and your knees slightly bent. Tip: Keep your back almost completely vertical and your arms fully extended in front of you. This will be your starting position.','While keeping your torso stationary, lift your elbows and start bending them as you pull the rope towards your neck while exhaling. Throughout the movement your upper arms should remain parallel to the floor. Tip: Continue this motion until your hands are almost next to your ears (the forearms will not be parallel to the floor at the end of the movement as they will be angled a bit upwards) and your elbows are out away from your sides.','After holding for a second or so at the contracted position, come back slowly to the starting position as you inhale. Tip: Again, during no part of the movement should the torso move.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Low_Pulley_Row_To_Neck/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Low_Pulley_Row_To_Neck/1.jpg']::text[]),
('Lower_Back-SMR','Lower Back-SMR','stretching','beginner',NULL,'static','foam roll',ARRAY['lower back']::text[],ARRAY[]::text[],ARRAY['In a seated position, place a foam roll under your lower back. Cross your arms in front of you and protract your shoulders. This will be your starting position.','Raise your hips off of the floor and lean back, keeping your weight on your lower back. Now shift your weight slightly to one side, keeping your weight off of the spine and on the muscles to the side of it. Roll over your lower back, holding points of tension for 10-30 seconds. Repeat on the other side.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lower_Back-SMR/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lower_Back-SMR/1.jpg']::text[]),
('Lower_Back_Curl','Lower Back Curl','stretching','beginner',NULL,'static','body only',ARRAY['abdominals']::text[],ARRAY[]::text[],ARRAY['Lie on your stomach with your arms out to your sides. This will be your starting position.','Using your lower back muscles, extend your spine lifting your chest off of the ground. Do not use your arms to push yourself up. Keep your head up during the movement. Repeat for 10-20 repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lower_Back_Curl/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lower_Back_Curl/1.jpg']::text[]),
('Lunge_Pass_Through','Lunge Pass Through','strength','intermediate','compound','push','kettlebells',ARRAY['hamstrings']::text[],ARRAY['calves','glutes','quadriceps']::text[],ARRAY['Stand with your torso upright holding a kettlebell in your right hand. This will be your starting position.','Step forward with your left foot and lower your upper body down by flexing the hip and the knee, keeping the torso upright. Lower your back knee until it nearly touches the ground.','As you lunge, pass the kettlebell under your front leg to your opposite hand.','Pressing through the heel of your foot, return to the starting position.','Repeat the movement for the recommended amount of repetitions, alternating legs.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lunge_Pass_Through/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lunge_Pass_Through/1.jpg']::text[]),
('Lunge_Sprint','Lunge Sprint','strength','intermediate','compound','push','machine',ARRAY['quadriceps']::text[],ARRAY['calves','glutes','hamstrings']::text[],ARRAY['Adjust a bar in a Smith machine to an appropriate height. Position yourself under the bar, racking it across the back of your shoulders. Unrack the bar, and then split your feet, moving one foot forward and one foot back. This will be your starting position.','Lower your back knee nearly to the ground, flexing the knees and lowering your hips as you do so.','At the bottom of the descent, immediately reverse direction. Explosively drive through the heel of your front foot with light pressure from your back foot. Jump up and reverse the position of your legs.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lunge_Sprint/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lunge_Sprint/1.jpg']::text[]),
('Lying_Bent_Leg_Groin','Lying Bent Leg Groin','stretching','expert',NULL,'static','other',ARRAY['adductors']::text[],ARRAY[]::text[],ARRAY['Lie on your back with your knees bent and the soles of the feet pressed together. Have your partner hold your knees. This will be your starting position.','Attempt to squeeze your knees together, while your partner prevents any movement from occurring.','After 10-20 seconds, relax your muscles as your partner gently pushes your knees towards the floor. Be sure to inform your helper when the stretch is adequate to prevent injury or overstretching.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Bent_Leg_Groin/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Bent_Leg_Groin/1.jpg']::text[]),
('Lying_Cable_Curl','Lying Cable Curl','strength','intermediate','isolation','pull','cable',ARRAY['biceps']::text[],ARRAY[]::text[],ARRAY['Grab a straight bar or E-Z bar attachment that is attached to the low pulley with both hands, using an underhand (palms facing up) shoulder-width grip.','Lie flat on your back on top of an exercise mat in front of the weight stack with your feet flat against the frame of the pulley machine and your legs straight.','With your arms extended and your elbows close to your body slightly bend your arms. This will be your starting position.','While keeping your upper arms stationary and the elbows close to your body, curl the bar up slowly toward your chest as you breathe out and you squeeze the biceps.','After a second squeeze at the top of the movement, slowly return to the starting position.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Cable_Curl/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Cable_Curl/1.jpg']::text[]),
('Lying_Cambered_Barbell_Row','Lying Cambered Barbell Row','strength','beginner','isolation','pull','barbell',ARRAY['middle back']::text[],ARRAY['biceps','lats','traps']::text[],ARRAY['Place a cambered bar underneath an exercise bench.','Lie face down on the exercise bench and grab the bar using a palms down (pronated grip) that is wider than shoulder width. This will be your starting position.','As you exhale row the bar up as you keep the elbows close to your body to either your chest, in order to target the upper mid back, or to your stomach if targeting the lats is your goal.','After a second hold at the top, lower back down to the starting position slowly as you inhale.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Cambered_Barbell_Row/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Cambered_Barbell_Row/1.jpg']::text[]),
('Lying_Close-Grip_Bar_Curl_On_High_Pulley','Lying Close-Grip Bar Curl On High Pulley','strength','beginner','isolation','pull','cable',ARRAY['biceps']::text[],ARRAY[]::text[],ARRAY['Place a flat bench in front of a high pulley or lat pulldown machine.','Hold the straight bar attachment using an underhand grip (palms up) that is about shoulder width.','Lie on your back with your head over the end of the bench.','Now extend your arms straight above your shoulders. Your torso and your arms should make a 90-degree angle and the elbows should be in. This will be your starting position.','As you breathe out, curl the bar down in a semicircular motion until it touches your chin. Squeeze the biceps for a second at the top contracted position. Tip: As you execute this motion only the forearms should move. At no time should the upper arms be moving at all. They are to remain perpendicular throughout the movement.','Return to starting position slowly.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Close-Grip_Bar_Curl_On_High_Pulley/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Close-Grip_Bar_Curl_On_High_Pulley/1.jpg']::text[]),
('Lying_Close-Grip_Barbell_Triceps_Extension_Behind_The_Head','Lying Close-Grip Barbell Triceps Extension Behind The Head','strength','intermediate','isolation','push','barbell',ARRAY['triceps']::text[],ARRAY[]::text[],ARRAY['While holding a barbell or EZ Curl bar with a pronated grip (palms facing forward), lie on your back on a flat bench with your head close to the end of the bench. Tip: If you are holding a barbell grab it using a shoulder-width grip and if you are using an E-Z Bar grab it on the inner handles.','Extend your arms in front of you and slowly bring the bar back in a semi circular motion (while keeping the arms extended) to a position over your head. At the end of this step your arms should be overhead and parallel to the floor. This will be your starting position. Tip: Keep your elbows in at all times.','As you inhale, lower the bar by bending at the elbows and while keeping the upper arm stationary. Keep lowering the bar until your forearms are perpendicular to the floor.','As you exhale bring the bar back up to the starting position by pushing the bar up in a semi-circular motion until the lower arms are also parallel to the floor. Contract the triceps hard at the top of the movement for a second. Tip: Again, only the forearms should move. The upper arms should remain stationary at all times.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Close-Grip_Barbell_Triceps_Extension_Behind_The_Head/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Close-Grip_Barbell_Triceps_Extension_Behind_The_Head/1.jpg']::text[]),
('Lying_Close-Grip_Barbell_Triceps_Press_To_Chin','Lying Close-Grip Barbell Triceps Press To Chin','strength','intermediate','isolation','push','e-z curl bar',ARRAY['triceps']::text[],ARRAY[]::text[],ARRAY['While holding a barbell or EZ Curl bar with a pronated grip (palms facing forward), lie on your back on a flat bench with your head off the end of the bench. Tip: If you are holding a barbell grab it using a shoulder-width grip and if you are using an E-Z Bar grab it on the inner handles.','Extend your arms in front of you as you hold the barbell over your chest. The arms should be perpendicular to your torso (90-degree angle). This will be your starting position.','As you inhale, lower the bar in a semi-circular motion by bending at the elbows and while keeping the upper arm stationary and elbows in. Keep lowering the bar until it lightly touches your chin.','As you exhale bring the bar back up to the starting position by pushing the bar up in a semi-circular motion. Contract the triceps hard at the top of the movement for a second. Tip: Again, only the forearms should move. The upper arms should remain stationary at all times.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Close-Grip_Barbell_Triceps_Press_To_Chin/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Close-Grip_Barbell_Triceps_Press_To_Chin/1.jpg']::text[]),
('Lying_Crossover','Lying Crossover','stretching','expert',NULL,'static','body only',ARRAY['abductors']::text[],ARRAY[]::text[],ARRAY['Lie on your back with your legs extended.','Cross one leg over your body with the knee bent, attempting to touch the knee to the ground. Your partner should kneel beside you, holding your shoulder down with one hand and controlling the crossed leg with the other. this will be your starting position.','Attempt to raise the bent knee off of the ground as your partner prevents any actual movement.','After 10-20 seconds, relax the leg as your partner gently presses the knee towards the floor. Repeat with the other side.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Crossover/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Crossover/1.jpg']::text[]),
('Lying_Dumbbell_Tricep_Extension','Lying Dumbbell Tricep Extension','strength','intermediate','isolation','push','dumbbell',ARRAY['triceps']::text[],ARRAY['chest','shoulders']::text[],ARRAY['Lie on a flat bench while holding two dumbbells directly in front of you. Your arms should be fully extended at a 90-degree angle from your torso and the floor. The palms should be facing in and the elbows should be tucked in. This is the starting position.','As you breathe in and you keep the upper arms stationary with the elbows in, slowly lower the weight until the dumbbells are near your ears.','At that point, while keeping the elbows in and the upper arms stationary, use the triceps to bring the weight back up to the starting position as you breathe out.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Dumbbell_Tricep_Extension/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Dumbbell_Tricep_Extension/1.jpg']::text[]),
('Lying_Face_Down_Plate_Neck_Resistance','Lying Face Down Plate Neck Resistance','strength','intermediate','isolation','pull','other',ARRAY['neck']::text[],ARRAY[]::text[],ARRAY['Lie face down with your whole body straight on a flat bench while holding a weight plate behind your head. Tip: You will need to position yourself so that your shoulders are slightly above the end of a flat bench in order for the upper chest, neck and face to be off the bench. This will be your starting position.','While keeping the plate secure on the back of your head slowly lower your head (as in saying "yes") as you breathe in.','Raise your head back up to the starting position in a semi-circular motion as you breathe out. Hold the contraction for a second.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Face_Down_Plate_Neck_Resistance/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Face_Down_Plate_Neck_Resistance/1.jpg']::text[]),
('Lying_Face_Up_Plate_Neck_Resistance','Lying Face Up Plate Neck Resistance','strength','intermediate','isolation','pull','other',ARRAY['neck']::text[],ARRAY[]::text[],ARRAY['Lie face up with your whole body straight on a flat bench while holding a weight plate on top of your forehead. Tip: You will need to position yourself so that your shoulders are slightly above the end of a flat bench in order for the traps, neck and head to be off the bench. This will be your starting position.','While keeping the plate secure on your forehead slowly lower your head back in a semi-circular motion as you breathe in.','Raise your head back up to the starting position in a semi-circular motion as you breathe out. Hold the contraction for a second.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Face_Up_Plate_Neck_Resistance/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Face_Up_Plate_Neck_Resistance/1.jpg']::text[]),
('Lying_Glute','Lying Glute','stretching','expert',NULL,'static','body only',ARRAY['glutes']::text[],ARRAY['abductors']::text[],ARRAY['Lie on your back with your partner kneeling beside you.','Flex the hip of one leg, raising it off of the floor. Rotate the leg so the foot is over the opposite hip, the lower leg perpendicular to your body. Your partner should hold the knee and ankle in place. This will be your starting position.','Attempt to push your leg towards your partner, who should be preventing any actual movement of the leg.','After 10-20 seconds, completely relax as your partner gently pushes the ankle and knee towards your chest. Be sure to inform your helper when the stretch is adequate to prevent injury or overstretching.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Glute/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Glute/1.jpg']::text[]),
('Lying_Hamstring','Lying Hamstring','stretching','expert',NULL,'static','other',ARRAY['hamstrings']::text[],ARRAY['calves']::text[],ARRAY['Lie on your back with your legs extended. Your partner should be kneeling beside you. Raise one leg up towards the ceiling and have your partner hold the ankle. Your partner can use their shoulder to brace your leg if necessary. This will be your starting position.','With your partner holding your leg in place, attempt to flex the knee, contracting the hamstrings for 10-20 seconds.','Then relax your leg, allowing your partner to gently push the leg towards your head. Be sure to inform your helper when the stretch is adequate to prevent injury or overstretching. Switch sides once complete.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Hamstring/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Hamstring/1.jpg']::text[]),
('Lying_High_Bench_Barbell_Curl','Lying High Bench Barbell Curl','strength','intermediate','isolation','pull','barbell',ARRAY['biceps']::text[],ARRAY[]::text[],ARRAY['Lie face forward on a tall flat bench while holding a barbell with a supinated grip (palms facing up). Tip: If you are holding a barbell grab it using a shoulder-width grip and if you are using an E-Z Bar grab it on the inner handles. Your upper body should be positioned in a way that the upper chest is over the end of the bench and the barbell is hanging in front of you with the arms extended and perpendicular to the floor. This will be your starting position.','While keeping the elbows in and the upper arms stationary, curl the weight up in a semi-circular motion as you contract the biceps and exhale. Hold at the top of the movement for a second.','As you inhale, slowly go back to the starting position. Tip: Maintain full control of the weight at all times and avoid any swinging. Remember, only the forearms should move throughout the movement.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_High_Bench_Barbell_Curl/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_High_Bench_Barbell_Curl/1.jpg']::text[]),
('Lying_Leg_Curls','Lying Leg Curls','strength','beginner','isolation','pull','machine',ARRAY['hamstrings']::text[],ARRAY[]::text[],ARRAY['Adjust the machine lever to fit your height and lie face down on the leg curl machine with the pad of the lever on the back of your legs (just a few inches under the calves). Tip: Preferably use a leg curl machine that is angled as opposed to flat since an angled position is more favorable for hamstrings recruitment.','Keeping the torso flat on the bench, ensure your legs are fully stretched and grab the side handles of the machine. Position your toes straight (or you can also use any of the other two stances described on the foot positioning section). This will be your starting position.','As you exhale, curl your legs up as far as possible without lifting the upper legs from the pad. Once you hit the fully contracted position, hold it for a second.','As you inhale, bring the legs back to the initial position. Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Leg_Curls/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Leg_Curls/1.jpg']::text[]),
('Lying_Machine_Squat','Lying Machine Squat','strength','intermediate','compound','push','machine',ARRAY['quadriceps']::text[],ARRAY['calves','glutes','hamstrings']::text[],ARRAY['Adjust the leg machine to a height that will allow you to get inside it with your knees bent and the thighs slightly below parallel.','Once you select the weight, position yourself inside the machine face up with the knees bent and thighs slightly below parallel to the platform. Make sure that the knees do not go past the toes. The angle created between the hamstrings and the calves should be one that is slightly less than 90 degrees (since your starting position requires you to start slightly below parallel). Your back and your head should be resting on the machine while your shoulders are pressed under the shoulder pads.','Place your hands by the handles and position your feet slightly pointing out at a shoulder width position. This will be your starting position.','While pressing with the balls of the feet as you breathe out, make your whole body erect as you squeeze the quads. Hold the contracted position for a second. Tip: Since you are starting below parallel, you can opt to use your hands to help you up by pressing on your thighs only on the first repetition.','Slowly squat down as you inhale but instead of going all the way down to the starting position, just stop once your thighs are parallel to the platform. The angle between your hamstrings and calves should be a 90-degree angle.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Machine_Squat/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Machine_Squat/1.jpg']::text[]),
('Lying_One-Arm_Lateral_Raise','Lying One-Arm Lateral Raise','strength','intermediate','isolation','pull','dumbbell',ARRAY['shoulders']::text[],ARRAY[]::text[],ARRAY['While holding a dumbbell in one hand, lay with your chest down on a flat bench. The other hand can be used to hold to the leg of the bench for stability.','Position the palm of the hand that is holding the dumbbell in a neutral manner (palms facing your torso) as you keep the arm extended with the elbow slightly bent. This will be your starting position.','Now raise the arm with the dumbbell to the side until your elbow is at shoulder height and your arm is roughly parallel to the floor as you exhale. Tip: Maintain your arm perpendicular to the torso while keeping your arm extended throughout the movement. Also, keep the contraction at the top for a second.','Slowly lower the dumbbell to the starting position as you inhale.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_One-Arm_Lateral_Raise/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_One-Arm_Lateral_Raise/1.jpg']::text[]),
('Lying_Prone_Quadriceps','Lying Prone Quadriceps','stretching','expert',NULL,NULL,'body only',ARRAY['quadriceps']::text[],ARRAY[]::text[],ARRAY['Lay face down on the floor with your partner kneeling beside you. Flex one knee and raise that leg off the ground, attempting to touch your glutes with your foot. Your partner should hold the knee and ankle. This will be your starting position.','Attempt to extend your knee while your partner prevents any actual movement.','After 10-20 seconds, relax your muscles as your partner gently pushes the foot towards your glutes, further stretching the quadriceps and hip flexors.','After 10-20 seconds, switch sides.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Prone_Quadriceps/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Prone_Quadriceps/1.jpg']::text[]),
('Lying_Rear_Delt_Raise','Lying Rear Delt Raise','strength','intermediate','isolation','pull','dumbbell',ARRAY['shoulders']::text[],ARRAY[]::text[],ARRAY['While holding a dumbbell in each hand, lay with your chest down on a flat bench.','Position the palms of the hands in a neutral manner (palms facing your torso) as you keep the arms extended with the elbows slightly bent. This will be your starting position.','Now raise the arms to the side until your elbows are at shoulder height and your arms are roughly parallel to the floor as you exhale. Tip: Maintain your arms perpendicular to the torso while keeping them extended throughout the movement. Also, keep the contraction at the top for a second.','Slowly lower the dumbbells to the starting position as you inhale.','Repeat for the recommended amount of repetitions and then switch to the other arm.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Rear_Delt_Raise/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Rear_Delt_Raise/1.jpg']::text[]),
('Lying_Supine_Dumbbell_Curl','Lying Supine Dumbbell Curl','strength','beginner','isolation','pull','dumbbell',ARRAY['biceps']::text[],ARRAY[]::text[],ARRAY['Lie down on a flat bench face up while holding a dumbbell in each arm on top of your thighs.','Bring the dumbbells to the sides with the arms extended and the palms of the hands facing your thighs (neutral grip).','While keeping the arms close to your torso and elbows in, slowly lower your arms (as you keep them extended with a slight bend at the elbows) as far down towards the floor as you can go. Once you cannot go down any further, lock your upper arms in that position and that will be your starting position.','As you breathe out, slowly begin to curl the weights up as you simultaneously rotate your wrists so that the palms of the hands face up. Continue curling the weight until your biceps are fully contracted and squeeze hard at the top position for a second. Tip: Only the forearms should move. Upper arms should remain stationary and elbows should stay in throughout the movement.','Return back to the starting position very slowly.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Supine_Dumbbell_Curl/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Supine_Dumbbell_Curl/1.jpg']::text[]),
('Lying_T-Bar_Row','Lying T-Bar Row','strength','intermediate','compound','pull','machine',ARRAY['middle back']::text[],ARRAY['biceps','lats']::text[],ARRAY['Load up the T-bar Row Machine with the desired weight and adjust the leg height so that your upper chest is at the top of the pad. Tip: In some machines all you can do is stand on the appropriate step that allows you to be at a height that has the upper chest at the top of the pad.','Lay face down on the pad and grab the handles. You can either use a palms down, palms up, or palms in position depending on what part of your back you want to emphasize.','Lift the bar off the rack and extend your arms in front of you. This will be your starting position.','As you exhale slowly pull the weight up and squeeze your back at the top of the movement. Tip: Keep the upper arms as close to the torso as possible throughout the movement in order to better engage the back muscles. Also, do not lift your body off of the pad at any time and refrain from using the biceps to lift the weight.','After a second contraction at the top of the movement, as you inhale, slowly go back down to the starting position.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_T-Bar_Row/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_T-Bar_Row/1.jpg']::text[]),
('Lying_Triceps_Press','Lying Triceps Press','strength','intermediate','isolation','push','e-z curl bar',ARRAY['triceps']::text[],ARRAY[]::text[],ARRAY['Lie on a flat bench with either an e-z bar (my preference) or a straight bar placed on the floor behind your head and your feet on the floor.','Grab the bar behind you, using a medium overhand (pronated) grip, and raise the bar in front of you at arms length. Tip: The arms should be perpendicular to the torso and the floor. The elbows should be tucked in. This is the starting position.','As you breathe in, slowly lower the weight until the bar lightly touches your forehead while keeping the upper arms and elbows stationary.','At that point, use the triceps to bring the weight back up to the starting position as you breathe out.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Triceps_Press/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Lying_Triceps_Press/1.jpg']::text[]),
('Machine_Bench_Press','Machine Bench Press','strength','beginner','compound','push','machine',ARRAY['chest']::text[],ARRAY['shoulders','triceps']::text[],ARRAY['Sit down on the Chest Press Machine and select the weight.','Step on the lever provided by the machine since it will help you to bring the handles forward so that you can grab the handles and fully extend the arms.','Grab the handles with a palms-down grip and lift your elbows so that your upper arms are parallel to the floor to the sides of your torso. Tip: Your forearms will be pointing forward since you are grabbing the handles. Once you bring the handles forward and extend the arms you will be at the starting position.','Now bring the handles back towards you as you breathe in.','Push the handles away from you as you flex your pecs and you breathe out. Hold the contraction for a second before going back to the starting position.','Repeat for the recommended amount of reps.','When finished step on the lever again and slowly get the handles back to their original place.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Machine_Bench_Press/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Machine_Bench_Press/1.jpg']::text[]),
('Machine_Bicep_Curl','Machine Bicep Curl','strength','beginner','isolation','pull','machine',ARRAY['biceps']::text[],ARRAY[]::text[],ARRAY['Adjust the seat to the appropriate height and make your weight selection. Place your upper arms against the pads and grasp the handles. This will be your starting position.','Perform the movement by flexing the elbow, pulling your lower arm towards your upper arm.','Pause at the top of the movement, and then slowly return the weight to the starting position.','Avoid returning the weight all the way to the stops until the set is complete to keep tension on the muscles being worked.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Machine_Bicep_Curl/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Machine_Bicep_Curl/1.jpg']::text[]),
('Machine_Preacher_Curls','Machine Preacher Curls','strength','beginner','isolation','pull','machine',ARRAY['biceps']::text[],ARRAY[]::text[],ARRAY['Sit down on the Preacher Curl Machine and select the weight.','Place the back of your upper arms (your triceps) on the preacher pad provided and grab the handles using an underhand grip (palms facing up). Tip: Make sure that when you place the arms on the pad you keep the elbows in. This will be your starting position.','Now lift the handles as you exhale and you contract the biceps. At the top of the position make sure that you hold the contraction for a second. Tip: Only the forearms should move. The upper arms should remain stationary and on the pad at all times.','Lower the handles slowly back to the starting position as you inhale.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Machine_Preacher_Curls/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Machine_Preacher_Curls/1.jpg']::text[]),
('Machine_Shoulder_Military_Press','Machine Shoulder (Military) Press','strength','beginner','compound','push','machine',ARRAY['shoulders']::text[],ARRAY['triceps']::text[],ARRAY['Sit down on the Shoulder Press Machine and select the weight.','Grab the handles to your sides as you keep the elbows bent and in line with your torso. This will be your starting position.','Now lift the handles as you exhale and you extend the arms fully. At the top of the position make sure that you hold the contraction for a second.','Lower the handles slowly back to the starting position as you inhale.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Machine_Shoulder_Military_Press/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Machine_Shoulder_Military_Press/1.jpg']::text[]),
('Machine_Triceps_Extension','Machine Triceps Extension','strength','beginner','isolation','push','machine',ARRAY['triceps']::text[],ARRAY[]::text[],ARRAY['Adjust the seat to the appropriate height and make your weight selection. Place your upper arms against the pads and grasp the handles. This will be your starting position.','Perform the movement by extending the elbow, pulling your lower arm away from your upper arm.','Pause at the completion of the movement, and then slowly return the weight to the starting position.','Avoid returning the weight all the way to the stops until the set is complete to keep tension on the muscles being worked.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Machine_Triceps_Extension/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Machine_Triceps_Extension/1.jpg']::text[]),
('Medicine_Ball_Chest_Pass','Medicine Ball Chest Pass','plyometrics','beginner','compound','push','medicine ball',ARRAY['chest']::text[],ARRAY['shoulders','triceps']::text[],ARRAY['You will need a partner for this exercise. Lacking one, this movement can be performed against a wall.','Begin facing your partner holding the medicine ball at your torso with both hands.','Pull the ball to your chest, and reverse the motion by extending through the elbows. For sports applications, you can take a step as you throw.','Your partner should catch the ball, and throw it back to you.','Receive the throw with both hands at chest height.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Medicine_Ball_Chest_Pass/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Medicine_Ball_Chest_Pass/1.jpg']::text[]),
('Medicine_Ball_Full_Twist','Medicine Ball Full Twist','plyometrics','beginner','compound','pull','medicine ball',ARRAY['abdominals']::text[],ARRAY['shoulders']::text[],ARRAY['For this exercise you will need a medicine ball and a partner. Stand back to back with your partner, spaced 2-3 feet apart. This will be your starting position.','Hold the ball in front of the trunk. Open the hips and turn the shoulders at the same time as your partner.','For full rotation, you and your partner should twist in the same direction, i.e. counter-clockwise.','Pass the ball to your partner, and both of you can now twist in the opposite direction to repeat the procedure.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Medicine_Ball_Full_Twist/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Medicine_Ball_Full_Twist/1.jpg']::text[]),
('Medicine_Ball_Scoop_Throw','Medicine Ball Scoop Throw','plyometrics','beginner','compound','push','medicine ball',ARRAY['shoulders']::text[],ARRAY['abdominals','hamstrings','quadriceps']::text[],ARRAY['Assume a semisquat stance with a medicine ball in your hands. Your arms should hang so the ball is near your feet.','Begin by thrusting the hips forward as you extend through the legs, jumping up.','As you do, swing your arms up and over your head, keeping them extended, releasing the ball at the peak of your movement. The goal is to throw the ball the greatest distance behind you.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Medicine_Ball_Scoop_Throw/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Medicine_Ball_Scoop_Throw/1.jpg']::text[]),
('Middle_Back_Shrug','Middle Back Shrug','strength','intermediate','isolation','pull','dumbbell',ARRAY['middle back']::text[],ARRAY[]::text[],ARRAY['Lie facedown on an incline bench while holding a dumbbell in each hand. Your arms should be fully extended hanging down and pointing towards the floor. The palms of your hands should be facing each other. This will be your starting position.','As you exhale, squeeze your shoulder blades together and hold the contraction for a full second. Tip: This movement is just like the reverse action of a hug, or trying to perform rear laterals as if you had no arms.','As you inhale go back to the starting position.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Middle_Back_Shrug/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Middle_Back_Shrug/1.jpg']::text[]),
('Middle_Back_Stretch','Middle Back Stretch','stretching','beginner','isolation','static',NULL,ARRAY['middle back']::text[],ARRAY['abdominals','lats','lower back']::text[],ARRAY['Stand so your feet are shoulder width apart and your hands are on your hips.','Twist at your waist until you feel a stretch. Hold for 10 to 15 seconds, then twist to the other side.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Middle_Back_Stretch/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Middle_Back_Stretch/1.jpg']::text[]),
('Mixed_Grip_Chin','Mixed Grip Chin','strength','expert','compound','pull','other',ARRAY['middle back']::text[],ARRAY['biceps','lats']::text[],ARRAY['Using a spacing that is just about 1 inch wider than shoulder width, grab a pull-up bar with the palms of one hand facing forward and the palms of the other hand facing towards you. This will be your starting position.','Now start to pull yourself up as you exhale. Tip: With the arm that has the palms facing up concentrate on using the back muscles in order to perform the movement. The elbow of that arm should remain close to the torso. With the other arm that has the palms facing forward, the elbows will be away but in line with the torso. You will concentrate on using the lats to pull your body up.','After a second contraction at the top, start to slowly come down as you inhale.','Repeat for the recommended amount of repetitions.','On the following set, switch grips; so if you had the right hand with the palms facing you and the left one with the palms facing forward, on the next set you will have the palms facing forward for the right hand and facing you for the left.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Mixed_Grip_Chin/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Mixed_Grip_Chin/1.jpg']::text[]),
('Monster_Walk','Monster Walk','strength','beginner','compound','pull','bands',ARRAY['abductors']::text[],ARRAY[]::text[],ARRAY['Place a band around both ankles and another around both knees. There should be enough tension that they are tight when your feet are shoulder width apart.','To begin, take short steps forward alternating your left and right foot.','After several steps, do just the opposite and walk backward to where you started.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Monster_Walk/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Monster_Walk/1.jpg']::text[]),
('Mountain_Climbers','Mountain Climbers','plyometrics','beginner','compound','pull',NULL,ARRAY['quadriceps']::text[],ARRAY['chest','hamstrings','shoulders']::text[],ARRAY['Begin in a pushup position, with your weight supported by your hands and toes. Flexing the knee and hip, bring one leg until the knee is approximately under the hip. This will be your starting position.','Explosively reverse the positions of your legs, extending the bent leg until the leg is straight and supported by the toe, and bringing the other foot up with the hip and knee flexed. Repeat in an alternating fashion for 20-30 seconds.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Mountain_Climbers/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Mountain_Climbers/1.jpg']::text[]),
('Moving_Claw_Series','Moving Claw Series','plyometrics','beginner','compound',NULL,NULL,ARRAY['hamstrings']::text[],ARRAY['calves','quadriceps']::text[],ARRAY['This move helps prepare your running form to help you excel at sprinting. As you run, be sure to flex the knee, aiming to kick your glutes as the hip extends.','Reload the quad as the leg moves back forward, attacking the ground on the next step.','Ensure that as you run, you block with the arms, punching through in a rapid 1-2 motion.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Moving_Claw_Series/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Moving_Claw_Series/1.jpg']::text[]),
('Muscle_Snatch','Muscle Snatch','olympic weightlifting','intermediate','compound','pull','barbell',ARRAY['hamstrings']::text[],ARRAY['glutes','lower back','quadriceps','shoulders','triceps']::text[],ARRAY['Begin with a loaded barbell held at the mid thigh position with a wide grip. The feet should be directly below the hips, with the feet turned out as needed. Lower the hips, with the chest up and the head looking forward. The shoulders should be just in front of the bar. This will be the starting position.','Begin the pull by driving through the front of the heels, raising the bar. Transition into the second pull by extending through the hips knees and ankles, driving the bar up as quickly as possible. The bar should be close to the body.','Continue raising the bar to the overhead position, without rebending the knees.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Muscle_Snatch/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Muscle_Snatch/1.jpg']::text[]),
('Muscle_Up','Muscle Up','strength','intermediate','compound','pull','other',ARRAY['lats']::text[],ARRAY['abdominals','biceps','forearms','middle back','shoulders','traps','triceps']::text[],ARRAY['Grip the rings using a false grip, with the base of your palms on top of the rings. Initiate a pull up by pulling the elbows down to your side, flexing the elbows.','As you reach the top position of the pull-up, pull the rings to your armpits as you roll your shoulders forward, allowing your elbows to move straight back behind you. This puts you into the proper position to continue into the dip portion of the movement.','Maintaining control and stability, extend through the elbow to complete the motion.','Use care when lowering yourself to the ground.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Muscle_Up/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Muscle_Up/1.jpg']::text[]),
('Narrow_Stance_Hack_Squats','Narrow Stance Hack Squats','strength','intermediate','compound','push','machine',ARRAY['quadriceps']::text[],ARRAY['calves','glutes','hamstrings']::text[],ARRAY['Place the back of your torso against the back pad of the machine and hook your shoulders under the shoulder pads provided.','Position your legs in the platform using a less than shoulder width narrow stance with the toes slightly pointed out. Your feet should be around 3 inches or less apart. Tip: Keep your head up at all times and also maintain the back on the pad at all times.','Place your arms on the side handles of the machine and disengage the safety bars (which on most designs is done by moving the side handles from a facing front position to a diagonal position).','Now straighten your legs without locking the knees. This will be your starting position.','Begin to slowly lower the unit by bending the knees as you maintain a straight posture with the head up (back on the pad at all times). Continue down until the angle between the upper leg and the calves becomes slightly less than 90-degrees (which is the point in which the upper legs are below parallel to the floor). Inhale as you perform this portion of the movement.','Begin to raise the unit as you exhale by pushing the floor with mainly with the heels of your feet as you straighten the legs again and go back to the starting position.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Narrow_Stance_Hack_Squats/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Narrow_Stance_Hack_Squats/1.jpg']::text[]),
('Narrow_Stance_Leg_Press','Narrow Stance Leg Press','strength','intermediate','compound','push','machine',ARRAY['quadriceps']::text[],ARRAY['calves','glutes','hamstrings']::text[],ARRAY['Using a leg press machine, sit down on the machine and place your legs on the platform directly in front of you at a less-than-shoulder-width narrow stance with the toes slightly pointed out. Your feet should be around 3 inches or less apart. Tip: Keep your head up at all times and also maintain the back on the pad at all times.','Lower the safety bars holding the weighted platform in place and press the platform all the way up until your legs are fully extended in front of you. Tip: Make sure that you do not lock your knees. Your torso and the legs should make a perfect 90-degree angle. This will be your starting position.','As you inhale, slowly lower the platform until your upper and lower legs make a 90-degree angle.','Pushing mainly with the heels of your feet and using the quadriceps go back to the starting position as you exhale.','Repeat for the recommended amount of repetitions and ensure to lock the safety pins properly once you are done. You do not want that platform falling on you fully loaded.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Narrow_Stance_Leg_Press/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Narrow_Stance_Leg_Press/1.jpg']::text[]),
('Narrow_Stance_Squats','Narrow Stance Squats','strength','intermediate','compound','push','barbell',ARRAY['quadriceps']::text[],ARRAY['calves','glutes','hamstrings','lower back']::text[],ARRAY['This exercise is best performed inside a squat rack for safety purposes. To begin, first set the bar on a rack that best matches your height. Once the correct height is chosen and the bar is loaded, step under the bar and place the back of your shoulders (slightly below the neck) across it.','Hold on to the bar using both arms at each side and lift it off the rack by first pushing with your legs and at the same time straightening your torso.','Step away from the rack and position your legs using a less-than-shoulder-width narrow stance with the toes slightly pointed out. Feet should be around 3-6 inches apart. Keep your head up at all times (looking down will get you off balance) and maintain a straight back. This will be your starting position. (Note: For the purposes of this discussion we will use the medium stance described above which targets overall development; however you can choose any of the three stances discussed in the foot stances section).','Begin to slowly lower the bar by bending the knees as you maintain a straight posture with the head up. Continue down until the angle between the upper leg and the calves becomes slightly less than 90-degrees (which is the point in which the upper legs are below parallel to the floor). Inhale as you perform this portion of the movement. Tip: If you performed the exercise correctly, the front of the knees should make an imaginary straight line with the toes that is perpendicular to the front. If your knees are past that imaginary line (if they are past your toes) then you are placing undue stress on the knee and the exercise has been performed incorrectly.','Begin to raise the bar as you exhale by pushing the floor with the heel of your foot mainly as you straighten the legs again and go back to the starting position.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Narrow_Stance_Squats/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Narrow_Stance_Squats/1.jpg']::text[]),
('Natural_Glute_Ham_Raise','Natural Glute Ham Raise','strength','intermediate','compound','pull','body only',ARRAY['hamstrings']::text[],ARRAY['calves','glutes','lower back']::text[],ARRAY['Using the leg pad of a lat pulldown machine or a preacher bench, position yourself so that your ankles are under the pads, knees on the seat, and you are facing away from the machine. You should be upright and maintaining good posture.','This will be your starting position. Lower yourself under control until your knees are almost completely straight.','Remaining in control, raise yourself back up to the starting position.','If you are unable to complete a rep, use a band, a partner, or push off of a box to aid in completing a repetition.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Natural_Glute_Ham_Raise/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Natural_Glute_Ham_Raise/1.jpg']::text[]),
('Neck-SMR','Neck-SMR','stretching','intermediate',NULL,'static','other',ARRAY['neck']::text[],ARRAY[]::text[],ARRAY['Using a muscle roller or a rolling pin, place the roller behind your head and against your neck. Make sure that you do not place the roller directly against the spine, but turned slightly so that the roller is pressed against the muscles to either side of the spine. This will be your starting position.','Starting at the top of your neck, slowly roll down the muscles of your neck, pausing at points of tension for 10-30 seconds.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Neck-SMR/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Neck-SMR/1.jpg']::text[]),
('Neck_Press','Neck Press','strength','intermediate','compound','push','barbell',ARRAY['chest']::text[],ARRAY['shoulders','triceps']::text[],ARRAY['Lie back on a flat bench. Using a medium-width grip (a grip that creates a 90-degree angle in the middle of the movement between the forearms and the upper arms), lift the bar from the rack and hold it straight over your neck with your arms locked. This will be your starting position.','As you breathe in, come down slowly until you feel the bar on your neck.','After a second pause, bring the bar back to the starting position as you breathe out and push the bar using your chest muscles. Lock your arms and squeeze your chest in the contracted position, hold for a second and then start coming down slowly again. Tip: It should take at least twice as long to go down than to come up).','Repeat the movement for the prescribed amount of repetitions.','When you are done, place the bar back in the rack.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Neck_Press/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Neck_Press/1.jpg']::text[]),
('Oblique_Crunches','Oblique Crunches','strength','beginner','isolation','pull','body only',ARRAY['abdominals']::text[],ARRAY[]::text[],ARRAY['Lie flat on the floor with your lower back pressed to the ground. For this exercise, you will need to put one hand beside your head and the other to the side against the floor.','Make sure your feet are elevated and resting on a flat surface.','Now lift the shoulder in which your hand is touching your head.','Simply elevate your shoulder and body upward until you touch your knee. For example, if you have your right hand besides your head, then you want to elevate your body upwards until your right elbow touches your left knee. The same variation can be applied doing the inverse and using your left elbow to touch your right knee.','After your knee touches your elbow, lower your body until you have reached the starting position.','Remember to breathe in during the eccentric (lowering) part of the exercise and to breathe out during the concentric (upward) part of the exercise.','Continue alternating in this manner until all of the recommended repetitions for each side have been completed.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Oblique_Crunches/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Oblique_Crunches/1.jpg']::text[]),
('Oblique_Crunches_-_On_The_Floor','Oblique Crunches - On The Floor','strength','beginner','isolation','pull','body only',ARRAY['abdominals']::text[],ARRAY[]::text[],ARRAY['Start out by lying on your right side with your legs lying on top of each other. Make sure your knees are bent a little bit.','Place your left hand behind your head.','Once you are in this set position, begin by moving your left elbow up as you would perform a normal crunch except this time the main emphasis is on your obliques.','Crunch as high as you can, hold the contraction for a second and then slowly drop back down into the starting position.','Remember to breathe in during the eccentric (lowering) part of the exercise and to breathe out during the concentric (elevation) part of the exercise.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Oblique_Crunches_-_On_The_Floor/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Oblique_Crunches_-_On_The_Floor/1.jpg']::text[]),
('Olympic_Squat','Olympic Squat','olympic weightlifting','intermediate','compound','push','barbell',ARRAY['quadriceps']::text[],ARRAY['calves','glutes','hamstrings']::text[],ARRAY['Begin with a barbell supported on top of the traps. The chest should be up, and the head facing forward. Adopt a hip width stance with the feet turned out as needed.','Descend by flexing the knees, refraining from moving the hips back as much as possible. This requires that the knees travel forward; ensure that they stay aligned with the feet. The goal is to keep the torso as upright as possible. Continue all the way down, keeping the weight on the front of the heel.','At the moment the upper legs contact the lower, reverse the motion, driving the weight upward.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Olympic_Squat/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Olympic_Squat/1.jpg']::text[]),
('On-Your-Back_Quad_Stretch','On-Your-Back Quad Stretch','stretching','beginner','isolation','static','other',ARRAY['quadriceps']::text[],ARRAY[]::text[],ARRAY['Lie on a flat bench or step, and hang one leg and arm over the side.','Bend the knee and hold the top of the foot. As you do this, be careful not to arch your lower back.','Pull the belly button to the spine to stay in neutral. Press your foot down and into your hand. To add the hip stretch, lift the hip of the leg you''re holding up toward the ceiling.','Switch sides.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/On-Your-Back_Quad_Stretch/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/On-Your-Back_Quad_Stretch/1.jpg']::text[]),
('On_Your_Side_Quad_Stretch','On Your Side Quad Stretch','stretching','beginner','isolation','static',NULL,ARRAY['quadriceps']::text[],ARRAY[]::text[],ARRAY['Start off by lying on your right side, with your right knee bent at a 90-degree angle resting on the floor in front of you (this stabilizes the torso).','Bend your left knee behind you and hold your left foot with your left hand. To stretch your hip flexor, press your left hip forward as you push your left foot back into your hand. Switch sides.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/On_Your_Side_Quad_Stretch/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/On_Your_Side_Quad_Stretch/1.jpg']::text[]),
('One-Arm_Dumbbell_Row','One-Arm Dumbbell Row','strength','beginner','compound','pull','dumbbell',ARRAY['middle back']::text[],ARRAY['biceps','lats','shoulders']::text[],ARRAY['Choose a flat bench and place a dumbbell on each side of it.','Place the right leg on top of the end of the bench, bend your torso forward from the waist until your upper body is parallel to the floor, and place your right hand on the other end of the bench for support.','Use the left hand to pick up the dumbbell on the floor and hold the weight while keeping your lower back straight. The palm of the hand should be facing your torso. This will be your starting position.','Pull the resistance straight up to the side of your chest, keeping your upper arm close to your side and keeping the torso stationary. Breathe out as you perform this step. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. Also, make sure that the force is performed with the back muscles and not the arms. Finally, the upper torso should remain stationary and only the arms should move. The forearms should do no other work except for holding the dumbbell; therefore do not try to pull the dumbbell up using the forearms.','Lower the resistance straight down to the starting position. Breathe in as you perform this step.','Repeat the movement for the specified amount of repetitions.','Switch sides and repeat again with the other arm.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Dumbbell_Row/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Dumbbell_Row/1.jpg']::text[]),
('One-Arm_Flat_Bench_Dumbbell_Flye','One-Arm Flat Bench Dumbbell Flye','strength','beginner','isolation','push','dumbbell',ARRAY['chest']::text[],ARRAY[]::text[],ARRAY['Lie down on a flat bench with a dumbbell in one hand resting on top of your thigh. The palm of your hand with the dumbbell in it should be at a neutral grip.','By using your thighs to help you get the dumbbell up, clean the dumbbell so that you can hold it in front of you with your lifting arm being fully extended. Remember to maintain a neutral grip with this exercise. Your non lifting hand should be to the side holding the flat bench for better support. This will be your starting position.','Your arm with the weight should have a slight bend on your elbow in order to prevent stress at the biceps tendon. Begin by lowering your arm with the weight in it out in a wide arc until you feel a stretch on your chest. Breathe in as you perform this portion of the movement. Tip: Keep in mind that throughout the movement, your lifting arm should remain stationary; the movement should only occur at the shoulder joint.','Return your lifting arm back to the starting position as you squeeze your chest muscles and breathe out. Tip: Make sure to use the same arc of motion used to lower the weights.','Hold for a second at the contracted position and repeat the movement for the prescribed amount of repetitions.','Switch arms and repeat the exercise.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Flat_Bench_Dumbbell_Flye/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Flat_Bench_Dumbbell_Flye/1.jpg']::text[]),
('One-Arm_High-Pulley_Cable_Side_Bends','One-Arm High-Pulley Cable Side Bends','strength','beginner','isolation','pull','cable',ARRAY['abdominals']::text[],ARRAY[]::text[],ARRAY['Connect a standard handle to a tower. Move cable to highest pulley position.','Stand with side to cable. With one hand, reach up and grab handle with underhand grip.','Pull down cable until elbow touches your side and the handle is by your shoulder.','Position feet hip-width apart. Place free hand on hip to help gauge pivot point.','Keep arm in static position. Contract oblique to bring the weight down in a side crunch.','Once you reach maximum contraction, slowly release the weight to the starting position. The weight stack should never be unloaded in a resting position. The aim is constant tension during the set.','Repeat to failure.','Then, reposition and repeat the same series of movements on the opposite side.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_High-Pulley_Cable_Side_Bends/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_High-Pulley_Cable_Side_Bends/1.jpg']::text[]),
('One-Arm_Incline_Lateral_Raise','One-Arm Incline Lateral Raise','strength','beginner','isolation','push','dumbbell',ARRAY['shoulders']::text[],ARRAY[]::text[],ARRAY['Lie down sideways on an incline bench press with a dumbbell in the hand. Make sure the shoulder is pressing against the incline bench and the arm is lying across your body with the palm around your navel.','Hold a dumbbell in your uppermost arm while keeping it extended in front of you parallel to the floor. This is your starting position.','While keeping the dumbbell parallel to the floor at all times, perform a lateral raise. Your arm should travel straight up until it is pointing at the ceiling. Tip: Exhale as you perform this movement. Hold the dumbbell in the position and feel the contraction in the shoulders for a second.','While inhaling lower the weight across your body back into the starting position.','Repeat the movement for the prescribed amount of repetitions.','Switch arms and repeat the movement.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Incline_Lateral_Raise/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Incline_Lateral_Raise/1.jpg']::text[]),
('One-Arm_Kettlebell_Clean','One-Arm Kettlebell Clean','strength','intermediate','compound','pull','kettlebells',ARRAY['hamstrings']::text[],ARRAY['glutes','lower back','shoulders','traps']::text[],ARRAY['Place a kettlebell between your feet. As you bend down to grab the kettlebell, push your butt back and keep your eyes looking forward.','Clean the kettlebell to your shoulders by extending through the legs and hips as you raise the kettlebell towards your shoulder. The wrist should rotate as you do so.','Return the weight to the starting position.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Clean/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Clean/1.jpg']::text[]),
('One-Arm_Kettlebell_Clean_and_Jerk','One-Arm Kettlebell Clean and Jerk','strength','intermediate','compound','push','kettlebells',ARRAY['shoulders']::text[],ARRAY[]::text[],ARRAY['Hold a kettlebell by the handle.','Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so, so that the palm faces forward.','Dip your body by bending the knees, keeping your torso upright.','Immediately reverse direction, driving through the heels, in essence jumping to create momentum. As you do so, press the kettlebell overhead to lockout by extending the arms, using your body''s momentum to move the weight.','Receive the weight overhead by returning to a squat position underneath the weight.','Keeping the weight overhead, return to a standing position. Lower the weight to the floor to perform the next repetition.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Clean_and_Jerk/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Clean_and_Jerk/1.jpg']::text[]),
('One-Arm_Kettlebell_Floor_Press','One-Arm Kettlebell Floor Press','strength','intermediate','compound','push','kettlebells',ARRAY['chest']::text[],ARRAY['triceps']::text[],ARRAY['Lie on the floor holding a kettlebell with one hand, with your upper arm supported by the floor. The palm should be facing in.','Press the kettlebell straight up toward the ceiling, rotating your wrist.','Lower the kettlebell back to the starting position and repeat.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Floor_Press/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Floor_Press/1.jpg']::text[]),
('One-Arm_Kettlebell_Jerk','One-Arm Kettlebell Jerk','strength','intermediate','compound','push','kettlebells',ARRAY['shoulders']::text[],ARRAY['calves','quadriceps','triceps']::text[],ARRAY['Hold a kettlebell by the handle. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so, so that the palm faces forward. This will be your starting position.','Dip your body by bending the knees, keeping your torso upright.','Immediately reverse direction, driving through the heels, in essence jumping to create momentum. As you do so, press the kettlebell overhead to lockout by extending the arms, using your body''s momentum to move the weight. Receive the weight overhead by returning to a squat position underneath the weight. Keeping the weight overhead, return to a standing position.','Lower the weight to perform the next repetition.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Jerk/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Jerk/1.jpg']::text[]),
('One-Arm_Kettlebell_Military_Press_To_The_Side','One-Arm Kettlebell Military Press To The Side','strength','intermediate','compound','push','kettlebells',ARRAY['shoulders']::text[],ARRAY['triceps']::text[],ARRAY['Clean a kettlebell to your shoulder. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so, so that the palm faces inward. This will be your starting position.','Look at the kettlebell and press it up and out until it is locked out overhead.','Lower the kettlebell back to your shoulder under control and repeat. Make sure to contract your lat, butt, and stomach forcefully for added stability and strength.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Military_Press_To_The_Side/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Military_Press_To_The_Side/1.jpg']::text[]),
('One-Arm_Kettlebell_Para_Press','One-Arm Kettlebell Para Press','strength','intermediate','compound','push','kettlebells',ARRAY['shoulders']::text[],ARRAY['triceps']::text[],ARRAY['Clean a kettlebell to your shoulder. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so, so that the palm faces forward. This will be your starting position.','Hold the kettlebell with the elbow out to the side, and press it up and out until it is locked out overhead.','Lower the kettlebell back to your shoulder under control and repeat. Make sure to contract your lat, butt, and stomach forcefully for added stability and strength.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Para_Press/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Para_Press/1.jpg']::text[]),
('One-Arm_Kettlebell_Push_Press','One-Arm Kettlebell Push Press','strength','intermediate','compound','push','kettlebells',ARRAY['shoulders']::text[],ARRAY['calves','quadriceps','triceps']::text[],ARRAY['Hold a kettlebell by the handle. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so, so that the palm faces forward. This will be your starting position.','Dip your body by bending the knees, keeping your torso upright.','Immediately reverse direction, driving through the heels, in essence jumping to create momentum. As you do so, press the kettlebell overhead to lockout by extending the arms, using your body''s momentum to move the weight. Lower the weight to perform the next repetition.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Push_Press/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Push_Press/1.jpg']::text[]),
('One-Arm_Kettlebell_Row','One-Arm Kettlebell Row','strength','intermediate','compound','pull','kettlebells',ARRAY['middle back']::text[],ARRAY['biceps','lats']::text[],ARRAY['Place a kettlebell in front of your feet. Bend your knees slightly and then push your butt out as much as possible as you bend over to get in the starting position. Grab the kettlebell and pull it to your stomach, retracting your shoulder blade and flexing the elbow. Keep your back straight. Lower and repeat.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Row/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Row/1.jpg']::text[]),
('One-Arm_Kettlebell_Snatch','One-Arm Kettlebell Snatch','strength','expert','compound','pull','kettlebells',ARRAY['shoulders']::text[],ARRAY['calves','glutes','hamstrings','lower back','traps','triceps']::text[],ARRAY['Place a kettlebell between your feet. Bend your knees and push your butt back to get in the proper starting position.','Look straight ahead and swing the kettlebell back between your legs.','Immediately reverse the direction and drive through with your hips and knees, accelerating the kettlebell upward. As the kettlebell rises to your shoulder rotate your hand and punch straight up, using momentum to receive the weight locked out overhead.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Snatch/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Snatch/1.jpg']::text[]),
('One-Arm_Kettlebell_Split_Jerk','One-Arm Kettlebell Split Jerk','strength','intermediate','compound','push','kettlebells',ARRAY['shoulders']::text[],ARRAY['glutes','hamstrings','quadriceps','triceps']::text[],ARRAY['Hold a kettlebell by the handle. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so, so that the palm faces forward. This will be your starting position.','Dip your body by bending the knees, keeping your torso upright.','Immediately reverse direction, driving through the heels, in essence jumping to create momentum. As you do so, press the kettlebell overhead to lockout by extending the arms, using your body''s momentum to move the weight.','Receive the weight overhead by returning to a squat position underneath the weight, positioning one leg in front of you and one leg behind you.','Keeping the weight overhead, return to a standing position and bring your feet together. Lower the weight to perform the next repetition.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Split_Jerk/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Split_Jerk/1.jpg']::text[]),
('One-Arm_Kettlebell_Split_Snatch','One-Arm Kettlebell Split Snatch','strength','expert','compound','pull','kettlebells',ARRAY['shoulders']::text[],ARRAY['hamstrings','quadriceps']::text[],ARRAY['Hold a kettlebell in one hand by the handle.','Squat towards the floor, and then reverse the motion, extending the hips, knees, and finally the ankles, to raise the kettlebell overhead.','After fully extending the body, descend into a lunge position to receive the weights overhead, one leg forward and one leg back. Ensure you drive through with your hips and lock the ketttlebells overhead in one uninterrupted motion.','Return to a standing position, holding the weight overhead, and bring the feet together. Lower the weight to return to the starting position.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Split_Snatch/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Split_Snatch/1.jpg']::text[]),
('One-Arm_Kettlebell_Swings','One-Arm Kettlebell Swings','strength','intermediate','compound','pull','kettlebells',ARRAY['hamstrings']::text[],ARRAY['calves','glutes','lower back','shoulders']::text[],ARRAY[]::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Swings/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Kettlebell_Swings/1.jpg']::text[]),
('One-Arm_Long_Bar_Row','One-Arm Long Bar Row','strength','beginner','compound','pull','barbell',ARRAY['middle back']::text[],ARRAY['biceps','lats']::text[],ARRAY['Position a bar into a landmine or in a corner to keep it from moving. Load an appropriate weight onto your end.','Stand next to the bar, and take a grip with one hand close to the collar. Using your hips and legs, rise to a standing position.','Assume a bent-knee stance with your hips back and your chest up. Your arm should be extended. This will be your starting position.','Pull the weight to your side by retracting the shoulder and flexing the elbow. Do not jerk the weight or cheat during the movement.','After a brief pause, return to the starting position.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Long_Bar_Row/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Long_Bar_Row/1.jpg']::text[]),
('One-Arm_Medicine_Ball_Slam','One-Arm Medicine Ball Slam','strength','beginner','compound','pull','medicine ball',ARRAY['abdominals']::text[],ARRAY['lats','shoulders']::text[],ARRAY['Start in a standing position with a staggered, athletic stance. Hold a medicine ball in one hand, on the same side as your back leg. This will be your starting position.','Begin by winding the arm, raising the medicine ball above your head. As you do so, extend through the hips, knees, and ankles to load up for the slam.','At peak extension, flex the shoulders, spine, and hips to throw the ball hard into the ground directly in front of you.','Catch the ball on the bounce and continue for the desired number of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Medicine_Ball_Slam/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Medicine_Ball_Slam/1.jpg']::text[]),
('One-Arm_Open_Palm_Kettlebell_Clean','One-Arm Open Palm Kettlebell Clean','strength','intermediate','compound','pull','kettlebells',ARRAY['hamstrings']::text[],ARRAY['forearms','glutes','lower back','quadriceps','shoulders']::text[],ARRAY['Place one kettlebell between your feet.','Grab the handle with one hand and raise the kettlebell rapidly, let it flip so that the ball of the kettlebell lands in the palm of your hand.','Throw the kettlebell out in front of you and catch the handle with one hand.','Take the kettlebell to the floor and repeat. Make sure to work both arms.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Open_Palm_Kettlebell_Clean/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Open_Palm_Kettlebell_Clean/1.jpg']::text[]),
('One-Arm_Overhead_Kettlebell_Squats','One-Arm Overhead Kettlebell Squats','strength','expert','compound','push','kettlebells',ARRAY['quadriceps']::text[],ARRAY['calves','glutes','hamstrings','shoulders']::text[],ARRAY['Clean and press a kettlebell with one arm. Clean the kettlebell to your shoulder by extending through the legs and hips as you pull the kettlebell towards your shoulder. Rotate your wrist as you do so. Press the weight overhead by extending through the elbow.This will be your starting position.','Looking straight ahead and keeping a kettlebell locked out above you, flex the knees and hips and lower your torso between your legs, keeping your head and chest up.','Pause at the bottom position for a second before rising back to the top, driving through the heels of your feet.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Overhead_Kettlebell_Squats/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Overhead_Kettlebell_Squats/1.jpg']::text[]),
('One-Arm_Side_Deadlift','One-Arm Side Deadlift','strength','expert','compound','pull','barbell',ARRAY['quadriceps']::text[],ARRAY['abdominals','calves','glutes','hamstrings','lower back','traps']::text[],ARRAY['Stand to the side of a barbell next to its center. Bend your knees and lower your body until you are able to reach the barbell.','Grasp the bar as if you were grabbing a briefcase (palms facing you since the bar is sideways). You may need a wrist wrap if you are using a significant amount of weight. This is your starting position.','Use your legs to help lift the barbell up while exhaling. Your arms should extend fully as bring the barbell up until you are in a standing position.','Slowly bring the barbell back down while inhaling. Tip: Make sure to bend your knees while lowering the weight to avoid any injury from occurring.','Repeat for the recommended amount of repetitions.','Switch arms and repeat the movement.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Side_Deadlift/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Side_Deadlift/1.jpg']::text[]),
('One-Arm_Side_Laterals','One-Arm Side Laterals','strength','beginner','isolation','push','dumbbell',ARRAY['shoulders']::text[],ARRAY[]::text[],ARRAY['Pick a dumbbell and place it in one of your hands. Your non lifting hand should be used to grab something steady such as an incline bench press. Lean towards your lifting arm and away from the hand that is gripping the incline bench as this will allow you to keep your balance.','Stand with a straight torso and have the dumbbell by your side at arm''s length with the palm of the hand facing you. This will be your starting position.','While maintaining the torso stationary (no swinging), lift the dumbbell to your side with a slight bend on the elbow and your hand slightly tilted forward as if pouring water in a glass. Continue to go up until you arm is parallel to the floor. Exhale as you execute this movement and pause for a second at the top.','Lower the dumbbell back down slowly to the starting position as you inhale.','Repeat for the recommended amount of repetitions.','Switch arms and repeat the exercise.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Side_Laterals/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Arm_Side_Laterals/1.jpg']::text[]),
('One-Legged_Cable_Kickback','One-Legged Cable Kickback','strength','intermediate','isolation','push','cable',ARRAY['glutes']::text[],ARRAY['hamstrings']::text[],ARRAY['Hook a leather ankle cuff to a low cable pulley and then attach the cuff to your ankle.','Face the weight stack from a distance of about two feet, grasping the steel frame for support.','While keeping your knees and hips bent slightly and your abs tight, contract your glutes to slowly "kick" the working leg back in a semicircular arc as high as it will comfortably go as you breathe out. Tip: At full extension, squeeze your glutes for a second in order to achieve a peak contraction.','Now slowly bring your working leg forward, resisting the pull of the cable until you reach the starting position.','Repeat for the recommended amount of repetitions.','Switch legs and repeat the movement for the other side.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Legged_Cable_Kickback/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One-Legged_Cable_Kickback/1.jpg']::text[]),
('One_Arm_Against_Wall','One Arm Against Wall','stretching','beginner','isolation','static',NULL,ARRAY['lats']::text[],ARRAY[]::text[],ARRAY['From a standing position, place a bent arm against a wall or doorway.','Slowly lean toward your arm until you feel a stretch in your lats.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Arm_Against_Wall/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Arm_Against_Wall/1.jpg']::text[]),
('One_Arm_Chin-Up','One Arm Chin-Up','strength','expert','compound','pull','other',ARRAY['middle back']::text[],ARRAY['biceps','forearms','lats']::text[],ARRAY['For this exercise, start out by placing a towel around a chin up bar.','Grab the chin-up bar with your palm facing you. One hand will be grabbing the chin-up bar and the other will be grabbing the towel.','Bring your torso back around 30 degrees or so while creating a curvature on your lower back and sticking your chest out. This is your starting position.v','Pull your torso up until the bar touches your upper chest by drawing the shoulders and the upper arms down and back. Exhale as you perform this portion of the movement. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary as it moves through space and only the arms should move. The forearms should do no other work other than hold the bar.','After a second on the contracted position, start to inhale and slowly lower your torso back to the starting position when your arms are fully extended and the lats are fully stretched.','Repeat this motion for the prescribed amount of repetitions.','Switch arms and repeat the movement.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Arm_Chin-Up/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Arm_Chin-Up/1.jpg']::text[]),
('One_Arm_Dumbbell_Bench_Press','One Arm Dumbbell Bench Press','strength','beginner','compound','push','dumbbell',ARRAY['chest']::text[],ARRAY['shoulders','triceps']::text[],ARRAY['Lie down on a flat bench with a dumbbell in one hand on top of your thigh.','By using your thigh to help you get the dumbbell up, clean the dumbbell up so that you can hold it in front of you at shoulder width. Use the hand you are not lifting with to help position the dumbbell over you properly.','Once at shoulder width, rotate your wrist forward so that the palm of your hand is facing away from you. This will be your starting position.','Bring down the weights slowly to your side as you breathe in. Keep full control of the dumbbell at all times. Tip: Use the hand that you are not lifting with to help keep the dumbbell balance as you may struggle a bit at first. Only use your non-lifting hand if it is needed. Otherwise, keep it resting to the side.','As you breathe out, push the dumbbells up using your pectoral muscles. Lock your arms in the contracted position, squeeze your chest, hold for a second and then start coming down slowly. Tip: It should take at least twice as long to go down than to come up.','Repeat the movement for the prescribed amount of repetitions of your training program.','Switch arms and repeat the movement.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Arm_Dumbbell_Bench_Press/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Arm_Dumbbell_Bench_Press/1.jpg']::text[]),
('One_Arm_Dumbbell_Preacher_Curl','One Arm Dumbbell Preacher Curl','strength','beginner','isolation','pull','dumbbell',ARRAY['biceps']::text[],ARRAY[]::text[],ARRAY['Grab a dumbbell with the right arm and place the upper arm on top of the preacher bench or the incline bench. The dumbbell should be held at shoulder length. This will be your starting position.','As you breathe in, slowly lower the dumbbell until your upper arm is extended and the biceps is fully stretched.','As you exhale, use the biceps to curl the weight up until your biceps is fully contracted and the dumbbell is at shoulder height. Again, remember that to ensure full contraction you need to bring that small finger higher than the thumb.','Squeeze the biceps hard for a second at the contracted position and repeat for the recommended amount of repetitions.','Switch arms and repeat the movement.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Arm_Dumbbell_Preacher_Curl/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Arm_Dumbbell_Preacher_Curl/1.jpg']::text[]),
('One_Arm_Floor_Press','One Arm Floor Press','strength','intermediate','compound','push','barbell',ARRAY['triceps']::text[],ARRAY['chest','shoulders']::text[],ARRAY['Lie down on a flat surface with your back pressing against the floor or an exercise mat. Make sure your knees are bent.','Have a partner hand you the bar on one hand. When starting, your arm should be just about fully extended, similar to the starting position of a barbell bench press. However, this time your grip will be neutral (palms facing your torso).','Make sure the hand you are not using to lift the weight is placed by your side.','Begin the exercise by lowering the barbell until your elbow touches the ground. Make sure to breathe in as this is the eccentric (lowering part of the exercise).','Then start lifting the barbell back up to the original starting position. Remember to breathe out during the concentric (lifting part of the exercise).','Repeat until you have performed your recommended repetitions.','Switch arms and repeat the movement.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Arm_Floor_Press/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Arm_Floor_Press/1.jpg']::text[]),
('One_Arm_Lat_Pulldown','One Arm Lat Pulldown','strength','beginner','compound','pull','cable',ARRAY['lats']::text[],ARRAY['biceps','middle back']::text[],ARRAY['Select an appropriate weight and adjust the knee pad to help keep you down. Grasp the handle with a pronated grip. This will be your starting position.','Pull the handle down, squeezing your elbow to your side as you flex the elbow.','Pause at the bottom of the motion, and then slowly return the handle to the starting position.','For multiple repetitions, avoid completely returning the weight to keep tension on the muscles being worked.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Arm_Lat_Pulldown/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Arm_Lat_Pulldown/1.jpg']::text[]),
('One_Arm_Pronated_Dumbbell_Triceps_Extension','One Arm Pronated Dumbbell Triceps Extension','strength','beginner','isolation','push','dumbbell',ARRAY['triceps']::text[],ARRAY[]::text[],ARRAY['Lie flat on a bench while holding a dumbbell at arms length. Your arm should be perpendicular to your body. The palm of your hand should be facing towards your feet as a pronated grip is required to perform this exercise.','Place your non lifting hand on your bicep for support.','Slowly begin to lower the dumbbell down as you breathe in.','Then, begin lifting the dumbbell upward as you contract the triceps. Remember to breathe out during the concentric (lifting part of the exercise).','Repeat until you have performed your set repetitions.','Switch arms and repeat the movement.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Arm_Pronated_Dumbbell_Triceps_Extension/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Arm_Pronated_Dumbbell_Triceps_Extension/1.jpg']::text[]),
('One_Arm_Supinated_Dumbbell_Triceps_Extension','One Arm Supinated Dumbbell Triceps Extension','strength','beginner','isolation','push','dumbbell',ARRAY['triceps']::text[],ARRAY[]::text[],ARRAY['Lie flat on a bench while holding a dumbbell at arms length. Your arm should be perpendicular to your body. The palm of your hand should be facing towards your face as a supinated grip is required to perform this exercise.','Place your non lifting hand on your bicep for support.','Slowly begin to lower the dumbbell down as you breathe in.','Then, begin lifting the dumbbell upward as you contract the triceps. Remember to breathe out during the concentric (lifting part of the exercise).','Repeat until you have performed your set repetitions.','Switch arms and repeat the movement.','Switch arms again and repeat the movement.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Arm_Supinated_Dumbbell_Triceps_Extension/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Arm_Supinated_Dumbbell_Triceps_Extension/1.jpg']::text[]),
('One_Half_Locust','One Half Locust','stretching','beginner',NULL,'static',NULL,ARRAY['quadriceps']::text[],ARRAY['abdominals','biceps','chest']::text[],ARRAY['Lie facedown on the floor.','Put your left hand under your left hipbone to pad your hip and pubic bone.','Bend your right knee so you can hold the foot in your right hand.','Lift the foot in the air and simultaneously lift your shoulders off the floor. This also stretches the right hip flexor and the chest and shoulders. Switch sides. If it doesn''t bother your back, you can try it with both arms and legs at the same time.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Half_Locust/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Half_Locust/1.jpg']::text[]),
('One_Handed_Hang','One Handed Hang','stretching','beginner',NULL,'static','other',ARRAY['lats']::text[],ARRAY['biceps']::text[],ARRAY['Grab onto a chinup bar with one hand, using a pronated grip. Keep your feet on the floor or a step. Allow the majority of your weight to hang from that hand, while keeping your feet on the ground. Hold for 10-20 seconds and switch sides.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Handed_Hang/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Handed_Hang/1.jpg']::text[]),
('One_Knee_To_Chest','One Knee To Chest','stretching','beginner','compound','static',NULL,ARRAY['glutes']::text[],ARRAY['hamstrings','lower back']::text[],ARRAY['Start off by lying on the floor.','Extend one leg straight and pull the other knee to your chest. Hold under the knee joint to protect the kneecap.','Gently tug that knee toward your nose.','Switch sides. This stretches the buttocks and lower back of the bent leg and the hip flexor of the straight leg.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Knee_To_Chest/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Knee_To_Chest/1.jpg']::text[]),
('One_Leg_Barbell_Squat','One Leg Barbell Squat','strength','expert','compound','push','barbell',ARRAY['quadriceps']::text[],ARRAY['calves','glutes','hamstrings']::text[],ARRAY['Start by standing about 2 to 3 feet in front of a flat bench with your back facing the bench. Have a barbell in front of you on the floor. Tip: Your feet should be shoulder width apart from each other.','Bend the knees and use a pronated grip with your hands being wider than shoulder width apart from each other to lift the barbell up until you can rest it on your chest.','Then lift the barbell over your head and rest it on the base of your neck. Move one foot back so that your toe is resting on the flat bench. Your other foot should be stationary in front of you. Keep your head up at all times as looking down will get you off balance and also maintain a straight back. Tip: Make sure your back is straight and chest is out while performing this exercise.','As you inhale, slowly lower your leg until your thigh is parallel to the floor. At this point, your knee should be over your toes. Your chest should be directly above the middle of your thigh.','Leading with the chest and hips and contracting the quadriceps, elevate your leg back to the starting position as you exhale.','Repeat for the recommended amount of repetitions.','Switch legs and repeat the movement.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Leg_Barbell_Squat/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/One_Leg_Barbell_Squat/1.jpg']::text[]),
('Open_Palm_Kettlebell_Clean','Open Palm Kettlebell Clean','strength','expert','compound','pull','kettlebells',ARRAY['hamstrings']::text[],ARRAY['glutes','lower back','quadriceps','shoulders']::text[],ARRAY['Place one kettlebell between your feet. Clean the kettlebell by extending through the legs and hips as you raise the kettlebell towards your shoulders.','Release the kettlebell as it comes up, and let it flip so that the ball of the kettlebell lands in the palms of your hands.','Release the kettlebell out in front of you and catch the handle with both hands. Lower the kettlebell to the starting position and repeat.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Open_Palm_Kettlebell_Clean/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Open_Palm_Kettlebell_Clean/1.jpg']::text[]),
('Otis-Up','Otis-Up','strength','beginner','compound','pull','other',ARRAY['abdominals']::text[],ARRAY['chest','shoulders','triceps']::text[],ARRAY['Secure your feet and lay back on the floor. Your knees should be bent. Hold a weight with both hands to your chest. This will be your starting position.','Initiate the movement by flexing the hips and spine to raise your torso up from the ground.','As you move up, press the weight up so that it is above your head at the top of the movement.','Return the weight to your chest as you reverse the sit-up motion, ensuring not to go all the way down to the floor.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Otis-Up/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Otis-Up/1.jpg']::text[]),
('Overhead_Cable_Curl','Overhead Cable Curl','strength','intermediate','isolation','pull','cable',ARRAY['biceps']::text[],ARRAY[]::text[],ARRAY['To begin, set a weight that is comfortable on each side of the pulley machine. Note: Make sure that the amount of weight selected is the same on each side.','Now adjust the height of the pulleys on each side and make sure that they are positioned at a height higher than that of your shoulders.','Stand in the middle of both sides and use an underhand grip (palms facing towards the ceiling) to grab each handle. Your arms should be fully extended and parallel to the floor with your feet positioned shoulder width apart from each other. Your body should be evenly aligned the handles. This is the starting position.','While exhaling, slowly squeeze the biceps on each side until your forearms and biceps touch.','While inhaling, move your forearms back to the starting position. Note: Your entire body is stationary during this exercise except for the forearms.','Repeat for the recommended amount of repetitions prescribed in your program.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Overhead_Cable_Curl/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Overhead_Cable_Curl/1.jpg']::text[]),
('Overhead_Lat','Overhead Lat','stretching','expert',NULL,'static','other',ARRAY['lats']::text[],ARRAY['triceps']::text[],ARRAY['Sit upright on the floor with your partner behind you. Raise one arm straight up, and flex the elbow, attempting to touch your hand to your back. Your parner should hold your tricep and wrist. This will be your starting position.','Attempt to pull your upper arm to your side as your partner prevents you from doing actually doing so.','After 10-20 seconds, relax the arm and allow your partner to further stretch the lat by applying gentle pressure to the tricep. Hold for 10-20 seconds, and then switch sides.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Overhead_Lat/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Overhead_Lat/1.jpg']::text[]),
('Overhead_Slam','Overhead Slam','plyometrics','beginner','compound','pull','medicine ball',ARRAY['lats']::text[],ARRAY[]::text[],ARRAY['Hold a medine ball with both hands and stand with your feet at shoulder width. This will be your starting position.','Initiate the countermovement by raising the ball above your head and fully extending your body.','Reverse the motion, slamming the ball into the ground directly in front of you as hard as you can.','Receive the ball with both hands on the bounce and repeat the movement.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Overhead_Slam/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Overhead_Slam/1.jpg']::text[]),
('Overhead_Squat','Overhead Squat','olympic weightlifting','expert','compound','push','barbell',ARRAY['quadriceps']::text[],ARRAY['abdominals','calves','glutes','hamstrings','lower back','shoulders','triceps']::text[],ARRAY['Start out by having a barbell in front of you on the floor. Your feet should be wider than shoulder width apart from each other.','Bend the knees and use a pronated grip (palms facing you) to grab the barbell. Your hands should be at a wider than shoulder width apart from each other before lifting. Once you are positioned, lift the barbell up until you can rest it on your chest.','Move the barbell over and slightly behind your head and make sure your arms are fully extended. Keep your head up at all times and also maintain a straight back. Retract your shoulder blades. This is your starting position.','Slowly lower the weight by bending your knees until your thighs are parallel to the ground while inhaling. Tip: Keep your back straight while performing this exercise to avoid any injuries and your arms should remain extended and over your head at all times.','Now use your feet and legs to help bring the weight back up to the starting position while exhaling.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Overhead_Squat/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Overhead_Squat/1.jpg']::text[]),
('Overhead_Stretch','Overhead Stretch','stretching','beginner','compound','static',NULL,ARRAY['abdominals']::text[],ARRAY['chest','forearms','lats','triceps']::text[],ARRAY['Standing straight up, lace your fingers together and open your palms to the ceiling. Keep your shoulders down as you extend your arms up.','To create a full torso stretch, pull your tailbone down and stabilize your torso as you do this. Stretch the muscles on both the front and the back of the torso.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Overhead_Stretch/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Overhead_Stretch/1.jpg']::text[]),
('Overhead_Triceps','Overhead Triceps','stretching','expert',NULL,'static','body only',ARRAY['triceps']::text[],ARRAY['lats']::text[],ARRAY['Sit upright on the floor with your partner behind you. Raise one arm straight up, and flex the elbow, attempting to touch your hand to your back. Your parner should hold your elbow and wrist. This will be your starting position.','Attempt to extend the arm straight into the air as your partner prevents you from doing actually doing so.','After 10-20 seconds, relax the arm and allow your partner to further stretch the tricep by applying gentle pressure to the wrist. Hold for 10-20 seconds, and then switch sides.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Overhead_Triceps/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Overhead_Triceps/1.jpg']::text[]),
('Pallof_Press','Pallof Press','strength','beginner','isolation','pull','cable',ARRAY['abdominals']::text[],ARRAY['chest','shoulders','triceps']::text[],ARRAY['Connect a standard handle to a tower, and—if possible—position the cable to shoulder height. If not, a low pulley will suffice.','With your side to the cable, grab the handle with both hands and step away from the tower. You should be approximately arm''s length away from the pulley, with the tension of the weight on the cable.','With your feet positioned hip-width apart and knees slightly bent, hold the cable to the middle of your chest. This will be your starting position.','Press the cable away from your chest, fully extending both arms. You core should be tight and engaged.','Hold the repetition for several seconds before returning to the starting position.','At the conclusion of the set, repeat facing the other direction.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pallof_Press/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pallof_Press/1.jpg']::text[]),
('Pallof_Press_With_Rotation','Pallof Press With Rotation','strength','beginner','compound','pull','cable',ARRAY['abdominals']::text[],ARRAY['chest','shoulders','triceps']::text[],ARRAY['Connect a standard handle to a tower, and position the cable to shoulder height.','With your side to the cable, grab the handle with one hand and step away from the tower. You should be approximately arm''s length away from the pulley, with the tension of the weight on the cable. Align outstretched arm with cable.','With your feet positioned hip-width apart, pull the cable into your chest and grab the handle with your other hand. Both hands should be on the handle at this time.','Facing forward, press the cable away from your chest. You core should be tight and engaged.','Keeping your hips straight, twist your torso away from the pulley until you get a full quarter rotation.','Maintain your rigid stance and straight arms. Return to the neutral position in a slow and controlled manner. Your arms should be extended in front of you.','With the side tension still engaging your core, bring your hands to your chest and immediately press outward to a fully extended position. This constitutes one rep.','Repeat to failure.','Then, reposition and repeat the same series of movements on the opposite side.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pallof_Press_With_Rotation/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pallof_Press_With_Rotation/1.jpg']::text[]),
('Palms-Down_Dumbbell_Wrist_Curl_Over_A_Bench','Palms-Down Dumbbell Wrist Curl Over A Bench','strength','beginner','isolation','pull','dumbbell',ARRAY['forearms']::text[],ARRAY[]::text[],ARRAY['Start out by placing two dumbbells on one side of a flat bench.','Kneel down on both of your knees so that your body is facing the flat bench.','Use your arms to grab both of the dumbbells with a pronated grip (palms facing down) and bring them up so that your forearms are resting against the flat bench. Your wrists should be hanging over the edge.','Start out by curling your wrist upwards and exhaling.','Slowly lower your wrists back down to the starting position while inhaling.','Your forearms should be stationary as your wrist is the only movement needed to perform this exercise.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Palms-Down_Dumbbell_Wrist_Curl_Over_A_Bench/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Palms-Down_Dumbbell_Wrist_Curl_Over_A_Bench/1.jpg']::text[]),
('Palms-Down_Wrist_Curl_Over_A_Bench','Palms-Down Wrist Curl Over A Bench','strength','beginner','isolation','pull','barbell',ARRAY['forearms']::text[],ARRAY[]::text[],ARRAY['Start out by placing a barbell on one side of a flat bench.','Kneel down on both of your knees so that your body is facing the flat bench.','Use your arms to grab the barbell with a pronated grip (palms down) and bring them up so that your forearms are resting against the flat bench. Your wrists should be hanging over the edge.','Start out by curling your wrist upwards and exhaling.','Slowly lower your wrists back down to the starting position while inhaling.','Your forearms should be stationary as your wrist is the only movement needed to perform this exercise.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Palms-Down_Wrist_Curl_Over_A_Bench/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Palms-Down_Wrist_Curl_Over_A_Bench/1.jpg']::text[]),
('Palms-Up_Barbell_Wrist_Curl_Over_A_Bench','Palms-Up Barbell Wrist Curl Over A Bench','strength','beginner','isolation','pull','barbell',ARRAY['forearms']::text[],ARRAY[]::text[],ARRAY['Start out by placing a barbell on one side of a flat bench.','Kneel down on both of your knees so that your body is facing the flat bench.','Use your arms to grab the barbell with a supinated grip (palms up) and bring them up so that your forearms are resting against the flat bench. Your wrists should be hanging over the edge.','Start out by curling your wrist upwards and exhaling.','Slowly lower your wrists back down to the starting position while inhaling.','Your forearms should be stationary as your wrist is the only movement needed to perform this exercise.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Palms-Up_Barbell_Wrist_Curl_Over_A_Bench/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Palms-Up_Barbell_Wrist_Curl_Over_A_Bench/1.jpg']::text[]),
('Palms-Up_Dumbbell_Wrist_Curl_Over_A_Bench','Palms-Up Dumbbell Wrist Curl Over A Bench','strength','beginner','isolation','pull','dumbbell',ARRAY['forearms']::text[],ARRAY[]::text[],ARRAY['Start out by placing two dumbbells on one side of a flat bench.','Kneel down on both of your knees so that your body is facing the flat bench.','Use your arms to grab both of the dumbbells with a supinated grip (palms up) and bring them up so that your forearms are resting against the flat bench. Your wrists should be hanging over the edge.','Start out by curling your wrist upwards and exhaling.','Slowly lower your wrists back down to the starting position while inhaling. Make sure to inhale during this part of the exercise.','Your forearms should be stationary as your wrist is the only movement needed to perform this exercise.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Palms-Up_Dumbbell_Wrist_Curl_Over_A_Bench/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Palms-Up_Dumbbell_Wrist_Curl_Over_A_Bench/1.jpg']::text[]),
('Parallel_Bar_Dip','Parallel Bar Dip','strength','beginner','compound','push','other',ARRAY['triceps']::text[],ARRAY['chest','shoulders']::text[],ARRAY['Stand between a set of parallel bars. Place a hand on each bar, and then take a small jump to help you get into the starting position with your arms locked out.','Begin by flexing the elbow, lowering your body until your arms break 90 degrees. Avoid swinging, and maintain good posture throughout the descent.','Reverse the motion by extending the elbow, pushing yourself back up into the starting position.','Repeat for the desired number of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Parallel_Bar_Dip/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Parallel_Bar_Dip/1.jpg']::text[]),
('Pelvic_Tilt_Into_Bridge','Pelvic Tilt Into Bridge','stretching','intermediate','compound','static',NULL,ARRAY['lower back']::text[],ARRAY[]::text[],ARRAY['Lie down with your feet on the floor, heels directly under your knees.','Lift only your tailbone to the ceiling to stretch your lower back. (Don''t lift the entire spine yet.) Pull in your stomach.','To go into a bridge, lift the entire spine except the neck.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pelvic_Tilt_Into_Bridge/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pelvic_Tilt_Into_Bridge/1.jpg']::text[]),
('Peroneals-SMR','Peroneals-SMR','stretching','intermediate',NULL,'static','foam roll',ARRAY['calves']::text[],ARRAY[]::text[],ARRAY['Lay on your side, supporting your weight on your forearm and on a foam roller placed on the outside of your lower leg. Your upper leg can either be on top of your lower leg, or you can cross it in front of you. This will be your starting position.','Raise your hips off of the ground and begin to roll from below the knee to above the ankle on the side of your leg, pausing at points of tension for 10-30 seconds. Repeat on the other leg.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Peroneals-SMR/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Peroneals-SMR/1.jpg']::text[]),
('Peroneals_Stretch','Peroneals Stretch','stretching','intermediate',NULL,'static','other',ARRAY['calves']::text[],ARRAY[]::text[],ARRAY['In a seated position, loop a belt, rope, or band around one foot. This will be your starting position.','With the leg extended and the heel off of the ground, pull on the belt so that the foot is inverted, with the inside of the foot being pulled towards you. Hold for 10-20 seconds, and then switch sides.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Peroneals_Stretch/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Peroneals_Stretch/1.jpg']::text[]),
('Physioball_Hip_Bridge','Physioball Hip Bridge','strength','beginner','compound','push','exercise ball',ARRAY['glutes']::text[],ARRAY['hamstrings']::text[],ARRAY['Lay on a ball so that your upper back is on the ball with your hips unsupported. Both feet should be flat on the floor, hip width apart or wider. This will be your starting position.','Begin by extending the hips using your glutes and hamstrings, raising your hips upward as you bridge.','Pause at the top of the motion and return to the starting position.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Physioball_Hip_Bridge/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Physioball_Hip_Bridge/1.jpg']::text[]),
('Pin_Presses','Pin Presses','powerlifting','intermediate','compound','push','barbell',ARRAY['triceps']::text[],ARRAY['chest','forearms','lats','middle back','shoulders']::text[],ARRAY['Pin presses remove the eccentric phase of the bench press, developing starting strength. They also allow you to train a desired range of motion.','The bench should be set up in a power rack. Set the pins to the desired point in your range of motion, whether it just be lockout or an inch off of your chest. The bar should be moved to the pins and prepared for lifting.','Begin by lying on the bench, with the bar directly above the contact point during your regular bench. Tuck your feet underneath you and arch your back. Using the bar to help support your weight, lift your shoulder off the bench and retract them, squeezing the shoulder blades together. Use your feet to drive your traps into the bench. Maintain this tight body position throughout the movement.','You can take a standard bench grip, or shoulder width to focus on the triceps. The bar, wrist, and elbow should stay in line at all times. Focus on squeezing the bar and trying to pull it apart.','Drive the bar up with as much force as possible. The elbows should be tucked in until lockout.','Return the bar to the pins, pausing before beginning the next repetition.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pin_Presses/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pin_Presses/1.jpg']::text[]),
('Piriformis-SMR','Piriformis-SMR','stretching','intermediate','isolation','static','foam roll',ARRAY['glutes']::text[],ARRAY[]::text[],ARRAY['Sit with your buttocks on top of a foam roll. Bend your knees, and then cross one leg so that the ankle is over the knee. This will be your starting position.','Shift your weight to the side of the crossed leg, rolling over the buttocks until you feel tension in your upper glute. You may assist the stretch by using one hand to pull the bent knee towards your chest. Hold this position for 10-30 seconds, and then switch sides.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Piriformis-SMR/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Piriformis-SMR/1.jpg']::text[]),
('Plank','Plank','strength','beginner','isolation','static','body only',ARRAY['abdominals']::text[],ARRAY[]::text[],ARRAY['Get into a prone position on the floor, supporting your weight on your toes and your forearms. Your arms are bent and directly below the shoulder.','Keep your body straight at all times, and hold this position as long as possible. To increase difficulty, an arm or leg can be raised.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Plank/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Plank/1.jpg']::text[]),
('Plate_Pinch','Plate Pinch','strength','intermediate','isolation','static','other',ARRAY['forearms']::text[],ARRAY[]::text[],ARRAY['Grab two wide-rimmed plates and put them together with the smooth sides facing outward','Use your fingers to grip the outside part of the plate and your thumb for the other side thus holding both plates together. This is the starting position.','Squeeze the plate with your fingers and thumb. Hold this position for as long as you can.','Repeat for the recommended amount of sets prescribed in your program.','Switch arms and repeat the movements.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Plate_Pinch/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Plate_Pinch/1.jpg']::text[]),
('Plate_Twist','Plate Twist','strength','intermediate','compound','pull','other',ARRAY['abdominals']::text[],ARRAY[]::text[],ARRAY['Lie down on the floor or an exercise mat with your legs fully extended and your upper body upright. Grab the plate by its sides with both hands out in front of your abdominals with your arms slightly bent.','Slowly cross your legs near your ankles and lift them up off the ground. Your knees should also be bent slightly. Note: Move your upper body back slightly to help keep you balanced turning this exercise. This is the starting position.','Move the plate to the left side and touch the floor with it. Breathe out as you perform that movement.','Come back to the starting position as you breathe in and then repeat the movement but this time to the right side of the body. Tip: Use a slow controlled movement at all times. Jerking motions can injure the back.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Plate_Twist/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Plate_Twist/1.jpg']::text[]),
('Platform_Hamstring_Slides','Platform Hamstring Slides','strength','beginner','isolation','pull','other',ARRAY['hamstrings']::text[],ARRAY['glutes']::text[],ARRAY['For this movement a wooden floor or similar is needed. Lay on your back with your legs extended. Place a gym towel or a light weight underneath your heel. This will be your starting position.','Begin the movement by flexing the knee, keeping your other leg straight.','Continue bringing the heel closer to you, sliding it on the floor.','At full knee flexion, reverse the movement to return to the starting position.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Platform_Hamstring_Slides/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Platform_Hamstring_Slides/1.jpg']::text[]),
('Plie_Dumbbell_Squat','Plie Dumbbell Squat','strength','beginner','compound','push','dumbbell',ARRAY['quadriceps']::text[],ARRAY['abdominals','calves','glutes','hamstrings']::text[],ARRAY['Hold a dumbbell at the base with both hands and stand straight up. Move your legs so that they are wider than shoulder width apart from each other with your knees slightly bent.','Your toes should be facing out. Note: Your arms should be stationary while performing the exercise. This is the starting position.','Slowly bend the knees and lower your legs until your thighs are parallel to the floor. Make sure to inhale as this is the eccentric part of the exercise.','Press mainly with the heel of the foot to bring the body back to the starting position while exhaling.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Plie_Dumbbell_Squat/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Plie_Dumbbell_Squat/1.jpg']::text[]),
('Plyo_Kettlebell_Pushups','Plyo Kettlebell Pushups','strength','expert','compound','push','kettlebells',ARRAY['chest']::text[],ARRAY['shoulders','triceps']::text[],ARRAY['Place a kettlebell on the floor. Place yourself in a pushup position, on your toes with one hand on the ground and one hand holding the kettlebell, with your elbows extended. This will be your starting position.','Begin by lowering yourself as low as you can, keeping your back straight.','Quickly and forcefully reverse direction, pushing yourself up to the other side of the kettlebell, switching hands as you do so. Continue the movement by descending and repeating the movement back and forth.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Plyo_Kettlebell_Pushups/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Plyo_Kettlebell_Pushups/1.jpg']::text[]),
('Plyo_Push-up','Plyo Push-up','plyometrics','beginner','compound','push','body only',ARRAY['chest']::text[],ARRAY['shoulders','triceps']::text[],ARRAY['Move into a prone position on the floor, supporting your weight on your hands and toes.','Your arms should be fully extended with the hands around shoulder width. Keep your body straight throughout the movement. This will be your starting position.','Descend by flexing at the elbow, lowering your chest towards the ground.','At the bottom, reverse the motion by pushing yourself up through elbow extension as quickly as possible. Attempt to push your upper body up until your hands leave the ground.','Return to the starting position and repeat the exercise.','For added difficulty, add claps into the movement while you are air borne.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Plyo_Push-up/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Plyo_Push-up/1.jpg']::text[]),
('Posterior_Tibialis_Stretch','Posterior Tibialis Stretch','stretching','intermediate',NULL,'static','other',ARRAY['calves']::text[],ARRAY[]::text[],ARRAY['In a seated position, loop a belt, rope, or band around one foot. This will be your starting position.','With the leg extended and the heel off of the ground, pull on the belt so that the foot is everted, with the outside of the foot being pulled towards you. Hold for 10-20 seconds, and then switch sides.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Posterior_Tibialis_Stretch/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Posterior_Tibialis_Stretch/1.jpg']::text[]),
('Power_Clean','Power Clean','strength','intermediate','compound','pull','barbell',ARRAY['hamstrings']::text[],ARRAY['calves','forearms','glutes','lower back','middle back','quadriceps','shoulders','traps','triceps']::text[],ARRAY['Stand with your feet slightly wider than shoulder width apart and toes pointing out slightly.','Squat down and grasp bar with a closed, pronated grip. Your hands should be slightly wider than shoulder width apart outside knees with elbows fully extended.','Place the bar about 1 inch in front of your shins and over the balls of your feet.','Your back should be flat or slightly arched, your chest held up and out and your shoulder blades should be retracted.','Keep your head in a neutral position (in line with vertebral column and not tilted or rotated) with your eyes focused straight ahead. Inhale during this phase.','Lift the bar from the floor by forcefully extending the hips and the knees as you exhale. Tip: The upper torso should maintain the same angle. Do not bend at the waist yet and do not let the hips rise before the shoulders (this would have the effect of pushing the glutes in the air and stretching the hamstrings.','Keep elbows fully extended with the head in a neutral position and the shoulders over the bar.','As the bar raises keep it as close to the shins as possible.','As the bar passes the knees, thrust your hips forward and slightly bend the knees to avoid locking them. Tip: At this point your thighs should be against the bar.','Keep the back flat or slightly arched, elbows fully extended and your head neutral. Tip: You will hold your breath until the next phase.','Inhale and then forcefully and quickly extend your hips and knees and stand on your toes.','Keep the bar as close to your body as possible. Tip: Your back should be flat with the elbows pointed out to the sides and your head in a neutral position. Also, keep your shoulders over the bar and arms straight as long as possible.','When your lower body joints are fully extended, shrug the shoulders upward rapidly without letting the elbows flex yet. Exhale during this portion of the movement.','As the shoulders reach their highest elevation flex your elbows to begin pulling your body under the bar.','Continue to pull the arms as high and as long as possible. Tip: Due to the explosive nature of this phase, your torso will be erect or with an arched back, your head will be tilted back slightly and your feet may lose contact with the floor.','After the lower body has fully extended and the bar reaches near maximal height, pull your body under the bar and rotate the arms around and under the bar.','Simultaneously, flex the hips and knees into a quarter squat position.','Once the arms are under the bar, inhale and then lift your elbows to position the upper arms parallel to the floor. Rack the bar across the front of your collar bones and front shoulder muscles.','Catch the bar with an erect and tight torso, a neutral head position and flat feet. Exhale during this movement.','Stand up by extending the hips and knees to a fully erect position.','Lower the bar by gradually reducing the muscular tension of the arms to allow a controlled descent of the bar to the thighs. Inhale during this movement.','Simultaneously flex the hips and knees to cushion the impact of the bar on the thighs.','Squat down with the elbows fully extended until the bar touches the floor.','Start over at Phase 1 and repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Power_Clean/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Power_Clean/1.jpg']::text[]),
('Power_Clean_from_Blocks','Power Clean from Blocks','olympic weightlifting','intermediate','compound','pull','barbell',ARRAY['hamstrings']::text[],ARRAY['quadriceps']::text[],ARRAY['With a barbell on boxes of the desired height, take a grip just outside the legs. Lower your hips with the weight focused on the heels, back straight, head facing forward, chest up, with your shoulders just in front of the bar. This will be your starting position.','Begin the first pull by driving through the heels, extending your knees. Your back angle should stay the same, and your arms should remain straight. As the bar approaches the mid-thigh position, begin extending through the hips.','In a jumping motion, accelerate by extending the hips, knees, and ankles, using speed to move the bar upward. There should be no need to actively pull through the arms to accelerate the weight. At the end of the second pull, the body should be fully extended, leaning slightly back, with the arms still extended.','As full extension is achieved, transition into the third pull by aggressively shrugging and flexing the arms with the elbows up and out. At peak extension, pull yourself under the bar far enough that it can be racked onto the shoulders, rotating your elbows under the bar as you do so. The bar should be racked onto the protracted shoulders, lightly touching the throat with the hands relaxed.','Immediately recover by driving through the heels, keeping the torso upright and elbows up. Continue until you have risen to a standing position, and complete the repetition by returning the weight to the boxes.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Power_Clean_from_Blocks/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Power_Clean_from_Blocks/1.jpg']::text[]),
('Power_Jerk','Power Jerk','olympic weightlifting','expert','compound','push','barbell',ARRAY['quadriceps']::text[],ARRAY['abdominals','calves','glutes','hamstrings','shoulders','triceps']::text[],ARRAY['Standing with the weight racked on the front of the shoulders, begin with the dip. With your feet directly under your hips, flex the knees without moving the hips backward. Go down only slightly, and reverse direction as powerfully as possible.','Drive through the heels create as much speed and force as possible, and be sure to move your head out of the way as the bar leaves the shoulders.','At this moment as the feet leave the floor, the feet must be placed into the receiving position as quickly as possible. In the brief moment the feet are not actively driving against the platform, the athletes effort to push the bar up will drive them down. The feet should be moved to a slightly wider stance, with the knees partially bent.','Receive the bar with the arms locked out overhead.','Return to a standing position.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Power_Jerk/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Power_Jerk/1.jpg']::text[]),
('Power_Partials','Power Partials','strength','beginner','isolation','push','dumbbell',ARRAY['shoulders']::text[],ARRAY[]::text[],ARRAY['Stand up with your torso upright and a dumbbell on each hand being held at arms length. The elbows should be close to the torso.','The palms of the hands should be facing your torso. Your feet should be about shoulder width apart. This will be your starting position.','Keeping your arms straight and the torso stationary, lift the weights out to your sides until they are about shoulder level height while exhaling.','Feel the contraction for a second and begin to lower the weights back down to the starting position while inhaling. Tip: Keep the palms facing down with the little finger slightly higher while lifting and lowering the weights as it will concentrate the stress on your shoulders mainly.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Power_Partials/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Power_Partials/1.jpg']::text[]),
('Power_Snatch','Power Snatch','olympic weightlifting','expert','compound','pull','barbell',ARRAY['hamstrings']::text[],ARRAY['calves','glutes','lower back','quadriceps','shoulders','traps','triceps']::text[],ARRAY['Begin with a loaded barbell on the floor. The bar should be close to or touching the shins, and a wide grip should be taken on the bar. The feet should be directly below the hips, with the feet turned out as needed. Lower the hips, with the chest up and the head looking forward. The shoulders should be just in front of the bar. This will be the starting position.','Begin the first pull by driving through the front of the heels, raising the bar from the ground. The back angle should stay the same until the bar passes the knees.','Transition into the second pull by extending through the hips knees and ankles, driving the bar up as quickly as possible. The bar should be close to the body. At peak extension, shrug the shoulders and allow the elbows to flex to the side.','As you move your feet into the receiving position, a slightly wider position, pull yourself below the bar as you elevate the bar overhead. The bar should be received in a partial squat. Continue raising the bar to the overhead position, receiving the bar locked out overhead.','Return to a standing position with the weight over head.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Power_Snatch/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Power_Snatch/1.jpg']::text[]),
('Power_Snatch_from_Blocks','Power Snatch from Blocks','olympic weightlifting','intermediate','compound','pull','barbell',ARRAY['quadriceps']::text[],ARRAY['calves','forearms','glutes','hamstrings','lower back','shoulders','traps','triceps']::text[],ARRAY['Begin with a loaded barbell on boxes or stands of the desired height. A wide grip should be taken on the bar. The feet should be directly below the hips, with the feet turned out as needed. Lower the hips, with the chest up and the head looking forward. The shoulders should be just in front of the bar, with the elbows pointed out. This will be the starting position.','Begin the first pull by driving through the front of the heels, raising the bar from the boxes.','Transition into the second pull by extending through the hips knees and ankles, driving the bar up as quickly as possible. The bar should be close to the body. At peak extension, shrug the shoulders and allow the elbows to flex to the side.','As you move your feet into the receiving position, forcefully pull yourself below the bar as you elevate the bar overhead. The feet should move to just outside the hips, turned out as necessary. Receive the bar above a full squat and with the arms fully extended overhead.','Keeping the bar aligned over the front of the heels, your head and chest up, drive through heels of the feet to move to a standing position. Carefully return the weight to the boxes.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Power_Snatch_from_Blocks/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Power_Snatch_from_Blocks/1.jpg']::text[]),
('Power_Stairs','Power Stairs','strongman','intermediate','compound','pull','other',ARRAY['hamstrings']::text[],ARRAY['adductors','calves','glutes','lower back','quadriceps','shoulders','traps']::text[],ARRAY['In the power stairs, implements are moved up a staircase. For training purposes, these can be performed with a tire or box.','Begin by taking the implement with both hands. Set your feet wide, with your head and chest up. Drive through the ground with your heels, extending your knees and hips to raise the weight from the ground.','As you lean back, attempt to swing the weight onto the stairs, which are usually around 16-18" high. You can use your legs to help push the weight onto the stair.','Repeat for 3-5 repetitions, and continue with a heavier weight, moving as fast as possible.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Power_Stairs/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Power_Stairs/1.jpg']::text[]),
('Preacher_Curl','Preacher Curl','strength','beginner','isolation','pull','barbell',ARRAY['biceps']::text[],ARRAY[]::text[],ARRAY['To perform this movement you will need a preacher bench and an E-Z bar. Grab the E-Z curl bar at the close inner handle (either have someone hand you the bar which is preferable or grab the bar from the front bar rest provided by most preacher benches). The palm of your hands should be facing forward and they should be slightly tilted inwards due to the shape of the bar.','With the upper arms positioned against the preacher bench pad and the chest against it, hold the E-Z Curl Bar at shoulder length. This will be your starting position.','As you breathe in, slowly lower the bar until your upper arm is extended and the biceps is fully stretched.','As you exhale, use the biceps to curl the weight up until your biceps is fully contracted and the bar is at shoulder height. Squeeze the biceps hard and hold this position for a second.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Preacher_Curl/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Preacher_Curl/1.jpg']::text[]),
('Preacher_Hammer_Dumbbell_Curl','Preacher Hammer Dumbbell Curl','strength','beginner','isolation','pull','dumbbell',ARRAY['biceps']::text[],ARRAY['forearms']::text[],ARRAY['Place the upper part of both arms on top of the preacher bench as you hold a dumbbell in each hand with the palms facing each other (neutral grip).','As you breathe in, slowly lower the dumbbells until your upper arm is extended and the biceps is fully stretched.','As you exhale, use the biceps to curl the weight up until your biceps is fully contracted and the dumbbells are at shoulder height.','Squeeze the biceps hard for a second at the contracted position and repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Preacher_Hammer_Dumbbell_Curl/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Preacher_Hammer_Dumbbell_Curl/1.jpg']::text[]),
('Press_Sit-Up','Press Sit-Up','strength','expert','compound','push','barbell',ARRAY['abdominals']::text[],ARRAY['chest','shoulders','triceps']::text[],ARRAY['To begin, lie down on a bench with a barbell resting on your chest. Position your legs so they are secure on the extension of the abdominal bench. This is the starting position.','While inhaling, tighten your abdominals and glutes. Simultaneously curl your torso as you do when performing a sit-up and press the barbell to an overhead position while exhaling. Tip: Use your arms to push the barbell out as you perform this exercise while still focusing on the abdominal muscles.','Lower your upper body back down to the starting position while bringing the barbell back down to your torso. Remember to breathe in while lowering the body.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Press_Sit-Up/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Press_Sit-Up/1.jpg']::text[]),
('Prone_Manual_Hamstring','Prone Manual Hamstring','strength','beginner','isolation','static',NULL,ARRAY['hamstrings']::text[],ARRAY[]::text[],ARRAY['You will need a partner for this exercise. Lay face down with your legs straight. Your assistant will place their hand on your heel.','To begin, flex the knee to curl your leg up. Your partner should provide resistance, starting light and increasing the pressure as the movement is completed. Communicate with your partner to monitor appropriate resistance levels.','Pause at the top, returning the leg to the starting position as your partner provides resistance going the other direction.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Prone_Manual_Hamstring/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Prone_Manual_Hamstring/1.jpg']::text[]),
('Prowler_Sprint','Prowler Sprint','cardio','beginner','compound','push','other',ARRAY['hamstrings']::text[],ARRAY['calves','chest','glutes','quadriceps','shoulders']::text[],ARRAY['Place your sled on an appropriate surface, loaded to a suitable weight. The sled should provide enough resistance to require effort, but not so heavy that you are significantly slowed down.','You may use the upright or the low handles for this exercise. Place your hands on the handles with your arms extended, leaning into the implement.','With good posture, drive through the ground with alternating, short steps. Move as fast as you can for a short distance.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Prowler_Sprint/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Prowler_Sprint/1.jpg']::text[]),
('Pull_Through','Pull Through','strength','beginner','compound','pull','cable',ARRAY['glutes']::text[],ARRAY['hamstrings','lower back']::text[],ARRAY['Begin standing a few feet in front of a low pulley with a rope or handle attached. Face away from the machine, straddling the cable, with your feet set wide apart.','Begin the movement by reaching through your legs as far as possible, bending at the hips. Keep your knees slightly bent. Keeping your arms straight, extend through the hip to stand straight up. Avoid pulling upward through the shoulders; all of the motion should originate through the hips.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pull_Through/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pull_Through/1.jpg']::text[]),
('Pullups','Pullups','strength','beginner','compound','pull','body only',ARRAY['lats']::text[],ARRAY['biceps','middle back']::text[],ARRAY['Grab the pull-up bar with the palms facing forward using the prescribed grip. Note on grips: For a wide grip, your hands need to be spaced out at a distance wider than your shoulder width. For a medium grip, your hands need to be spaced out at a distance equal to your shoulder width and for a close grip at a distance smaller than your shoulder width.','As you have both arms extended in front of you holding the bar at the chosen grip width, bring your torso back around 30 degrees or so while creating a curvature on your lower back and sticking your chest out. This is your starting position.','Pull your torso up until the bar touches your upper chest by drawing the shoulders and the upper arms down and back. Exhale as you perform this portion of the movement. Tip: Concentrate on squeezing the back muscles once you reach the full contracted position. The upper torso should remain stationary as it moves through space and only the arms should move. The forearms should do no other work other than hold the bar.','After a second on the contracted position, start to inhale and slowly lower your torso back to the starting position when your arms are fully extended and the lats are fully stretched.','Repeat this motion for the prescribed amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pullups/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pullups/1.jpg']::text[]),
('Push-Up_Wide','Push-Up Wide','strength','beginner','compound',NULL,'body only',ARRAY['chest']::text[],ARRAY['abdominals','shoulders','triceps']::text[],ARRAY['With your hands wide apart, support your body on your toes and hands in a plank position. Your elbows should be extended and your body straight. Do not allow your hips to sag. This will be your starting position.','To begin, allow the elbows to flex, lowering your chest to the floor as you inhale.','Using your pectoral muscles, press your upper body back up to the starting position by extending the elbows. Exhale as you perform this step.','After pausing at the contracted position, repeat the movement for the prescribed amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Push-Up_Wide/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Push-Up_Wide/1.jpg']::text[]),
('Push-Ups_-_Close_Triceps_Position','Push-Ups - Close Triceps Position','strength','intermediate','compound','push','body only',ARRAY['triceps']::text[],ARRAY['chest','shoulders']::text[],ARRAY['Lie on the floor face down and place your hands closer than shoulder width for a close hand position. Make sure that you are holding your torso up at arms'' length.','Lower yourself until your chest almost touches the floor as you inhale.','Using your triceps and some of your pectoral muscles, press your upper body back up to the starting position and squeeze your chest. Breathe out as you perform this step.','After a second pause at the contracted position, repeat the movement for the prescribed amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Push-Ups_-_Close_Triceps_Position/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Push-Ups_-_Close_Triceps_Position/1.jpg']::text[]),
('Push-Ups_With_Feet_Elevated','Push-Ups With Feet Elevated','strength','beginner','compound','push','body only',ARRAY['chest']::text[],ARRAY['shoulders','triceps']::text[],ARRAY['Lie on the floor face down and place your hands about 36 inches apart from each other holding your torso up at arms length.','Place your toes on top of a flat bench. This will allow your body to be elevated. Note: The higher the elevation of the flat bench, the higher the resistance of the exercise is.','Lower yourself until your chest almost touches the floor as you inhale.','Using your pectoral muscles, press your upper body back up to the starting position and squeeze your chest. Breathe out as you perform this step.','After a second pause at the contracted position, repeat the movement for the prescribed amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Push-Ups_With_Feet_Elevated/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Push-Ups_With_Feet_Elevated/1.jpg']::text[]),
('Push-Ups_With_Feet_On_An_Exercise_Ball','Push-Ups With Feet On An Exercise Ball','strength','intermediate','compound','push','exercise ball',ARRAY['chest']::text[],ARRAY['shoulders','triceps']::text[],ARRAY['Lie on the floor face down and place your hands about 36 inches apart from each other holding your torso up at arms length.','Place your toes on top of an exercise ball. This will allow your body to be elevated.','Lower yourself until your chest almost touches the floor as you inhale.','Using your pectoral muscles, press your upper body back up to the starting position and squeeze your chest. Breathe out as you perform this step.','After a second pause at the contracted position, repeat the movement for the prescribed amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Push-Ups_With_Feet_On_An_Exercise_Ball/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Push-Ups_With_Feet_On_An_Exercise_Ball/1.jpg']::text[]),
('Push_Press','Push Press','olympic weightlifting','expert','compound','push','barbell',ARRAY['shoulders']::text[],ARRAY['quadriceps','triceps']::text[],ARRAY[]::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Push_Press/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Push_Press/1.jpg']::text[]),
('Push_Press_-_Behind_the_Neck','Push Press - Behind the Neck','olympic weightlifting','intermediate','compound','push','barbell',ARRAY['shoulders']::text[],ARRAY['calves','quadriceps','triceps']::text[],ARRAY['Standing with the weight racked on the back of the shoulders, begin with the dip. With your feet directly under your hips, flex the knees without moving the hips backward. Go down only slightly, and reverse direction as powerfully as possible. Drive through the heels create as much speed and force as possible, moving the bar in a vertical path.','Using the momentum generated, finish pressing the weight overhead be extending through the arms.','Return to the starting position, using your legs to absorb the impact.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Push_Press_-_Behind_the_Neck/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Push_Press_-_Behind_the_Neck/1.jpg']::text[]),
('Push_Up_to_Side_Plank','Push Up to Side Plank','strength','beginner','compound','push','body only',ARRAY['chest']::text[],ARRAY['abdominals','shoulders','triceps']::text[],ARRAY['Get into pushup position on the toes with your hands just outside of shoulder width.','Perform a pushup by allowing the elbows to flex. As you descend, keep your body straight.','Do one pushup and as you come up, shift your weight on the left side of the body, twist to the side while bringing the right arm up towards the ceiling in a side plank.','Lower the arm back to the floor for another pushup and then twist to the other side.','Repeat the series, alternating each side, for 10 or more reps.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Push_Up_to_Side_Plank/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Push_Up_to_Side_Plank/1.jpg']::text[]),
('Pushups','Pushups','strength','beginner','compound','push','body only',ARRAY['chest']::text[],ARRAY['shoulders','triceps']::text[],ARRAY['Lie on the floor face down and place your hands about 36 inches apart while holding your torso up at arms length.','Next, lower yourself downward until your chest almost touches the floor as you inhale.','Now breathe out and press your upper body back up to the starting position while squeezing your chest.','After a brief pause at the top contracted position, you can begin to lower yourself downward again for as many repetitions as needed.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pushups/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pushups/1.jpg']::text[]),
('Pushups_Close_and_Wide_Hand_Positions','Pushups (Close and Wide Hand Positions)','strength','beginner','compound','push','body only',ARRAY['chest']::text[],ARRAY['shoulders','triceps']::text[],ARRAY['Lie on the floor face down and body straight with your toes on the floor and the hands wider than shoulder width for a wide hand position and closer than shoulder width for a close hand position. Make sure you are holding your torso up at arms length.','Lower yourself until your chest almost touches the floor as you inhale.','Using your pectoral muscles, press your upper body back up to the starting position and squeeze your chest. Breathe out as you perform this step.','After a second pause at the contracted position, repeat the movement for the prescribed amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pushups_Close_and_Wide_Hand_Positions/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pushups_Close_and_Wide_Hand_Positions/1.jpg']::text[]),
('Pyramid','Pyramid','stretching','beginner',NULL,'static','exercise ball',ARRAY['lower back']::text[],ARRAY['shoulders']::text[],ARRAY['Start off by rolling your torso forward onto the ball so your hips rest on top of the ball and become the highest point of your body.','Rest your hands and feet on the floor. Your arms and legs can be slightly bent or straight, depending on the size of the ball, your flexibility, and the length of your limbs. This also helps develop stabilizing strength in your torso and shoulders.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pyramid/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Pyramid/1.jpg']::text[]),
('Quad_Stretch','Quad Stretch','stretching','intermediate',NULL,'static','other',ARRAY['quadriceps']::text[],ARRAY[]::text[],ARRAY['Lay on your side. Loop a belt, rope, or band around your top foot. Flex the knee and extend your hip, attempting to touch your glutes with your foot, and holding the belt with your hands. This will be your starting position.','With the belt being held over the shoulder or overhead, gently pull to increase the stretch in the quadriceps. Hold for 10-20 seconds, and then switch sides.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Quad_Stretch/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Quad_Stretch/1.jpg']::text[]),
('Quadriceps-SMR','Quadriceps-SMR','stretching','intermediate','isolation','static','foam roll',ARRAY['quadriceps']::text[],ARRAY[]::text[],ARRAY['Lay facedown on the floor with your weight supported by your hands or forearms. Place a foam roll underneath one leg on the quadriceps, and keep the foot off of the ground. Make sure to relax the leg as much as possible. This will be your starting position.','Shifting as much weight onto the leg to be stretched as is tolerable, roll over the foam from above the knee to below the hip, holding points of tension for 10-30 seconds. Switch sides.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Quadriceps-SMR/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Quadriceps-SMR/1.jpg']::text[]),
('Quick_Leap','Quick Leap','plyometrics','beginner','compound','push','other',ARRAY['quadriceps']::text[],ARRAY['calves','hamstrings']::text[],ARRAY['You will need a box for this exerise.','Begin facing the box standing 1-2 feet from its edge.','By utilizing your hips, hop onto the box, landing on both legs. Ensure that you land with your legs bent and your feet flat.','Immediately upon landing, fully extend through the entire body and swing your arms overhead to explode off of the box. Use your legs to absorb the impact of landing.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Quick_Leap/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Quick_Leap/1.jpg']::text[]),
('Rack_Delivery','Rack Delivery','olympic weightlifting','intermediate','compound','pull','barbell',ARRAY['shoulders']::text[],ARRAY['forearms','traps']::text[],ARRAY['This drill teaches the delivery of the barbell to the rack position on the shoulders. Begin holding a bar in the scarecrow position, with the upper arms parallel to the floor, and the forearms hanging down. Use a hook grip, with your fingers wrapped over your thumbs.','Begin by rotating the elbows around the bar, delivering the bar to the shoulders. As your elbows come forward, relax your grip. The shoulders should be protracted, providing a shelf for the bar, which should lightly contact the throat.','It is important that the bar stay close to the body at all times, as with a heavier load any distance will result in an unwanted collision. As the movement becomes smoother, speed and load can be increased before progressing further.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rack_Delivery/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rack_Delivery/1.jpg']::text[]),
('Rack_Pull_with_Bands','Rack Pull with Bands','powerlifting','intermediate','compound','pull','barbell',ARRAY['lower back']::text[],ARRAY['forearms','glutes','hamstrings','quadriceps','traps']::text[],ARRAY['Set up in a power rack with the bar on the pins. The pins should be set to the desired point; just below the knees, just above, or in the mid thigh position. Attach bands to the base of the rack, or secure them with dumbbells. Attach the other end to the bar. You may need to choke the bands to provide tension.','Position yourself against the bar in proper deadlifting position. Your feet should be under your hips, your grip shoulder width, back arched, and hips back to engage the hamstrings. Since the weight is typically heavy, you may use a mixed grip, a hook grip, or use straps to aid in holding the weight.','With your head looking forward, extend through the hips and knees, pulling the weight up and back until lockout. Be sure to pull your shoulders back as you complete the movement. Return the weight to the pins and repeat.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rack_Pull_with_Bands/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rack_Pull_with_Bands/1.jpg']::text[]),
('Rack_Pulls','Rack Pulls','powerlifting','intermediate','compound','pull','barbell',ARRAY['lower back']::text[],ARRAY['forearms','glutes','hamstrings','traps']::text[],ARRAY['Set up in a power rack with the bar on the pins. The pins should be set to the desired point; just below the knees, just above, or in the mid thigh position. Position yourself against the bar in proper deadlifting position. Your feet should be under your hips, your grip shoulder width, back arched, and hips back to engage the hamstrings. Since the weight is typically heavy, you may use a mixed grip, a hook grip, or use straps to aid in holding the weight.','With your head looking forward, extend through the hips and knees, pulling the weight up and back until lockout. Be sure to pull your shoulders back as you complete the movement.','Return the weight to the pins and repeat.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rack_Pulls/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rack_Pulls/1.jpg']::text[]),
('Rear_Leg_Raises','Rear Leg Raises','stretching','beginner',NULL,'push','body only',ARRAY['quadriceps']::text[],ARRAY[]::text[],ARRAY['Place yourself on your hands knees on an exercise mat. Your head should be looking forward and the bend of the knees should create a 90-degree angle between the hamstrings and the calves. This will be your starting position.','Extend one leg up and behind you. The knee and hip should both extend. Repeat for 5-10 repetitions, and then switch sides.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rear_Leg_Raises/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rear_Leg_Raises/1.jpg']::text[]),
('Recumbent_Bike','Recumbent Bike','cardio','beginner',NULL,NULL,'machine',ARRAY['quadriceps']::text[],ARRAY['calves','glutes','hamstrings']::text[],ARRAY['To begin, seat yourself on the bike and adjust the seat to your height.','Select the desired option from the menu. You may have to start pedaling to turn it on. You can use the manual setting, or you can select a program to use. Typically, you can enter your age and weight to estimate the amount of calories burned during exercise. The level of resistance can be changed throughout the workout. The handles can be used to monitor your heart rate to help you stay at an appropriate intensity.','Recumbent bikes offer convenience, cardiovascular benefits, and have less impact than other activities. A 150 lb person will burn about 230 calories cycling at a moderate rate for 30 minutes, compared to 450 calories or more running.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Recumbent_Bike/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Recumbent_Bike/1.jpg']::text[]),
('Return_Push_from_Stance','Return Push from Stance','plyometrics','beginner','compound','push','medicine ball',ARRAY['shoulders']::text[],ARRAY['chest','triceps']::text[],ARRAY['You will need a partner for this drill.','Begin in an athletic 2 or 3 point stance.','At the signal, move into a position to receive the pass from your partner.','Catch the medicine ball with both hands and immediately throw it back to your partner.','You can modify this drill by running different routes.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Return_Push_from_Stance/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Return_Push_from_Stance/1.jpg']::text[]),
('Reverse_Band_Bench_Press','Reverse Band Bench Press','powerlifting','intermediate','compound','push','barbell',ARRAY['triceps']::text[],ARRAY['chest','forearms','lats','middle back','shoulders']::text[],ARRAY['Position a bench inside a power rack, with the bar set to the correct height. Begin by anchoring bands either to band pegs or to the top of the rack. Ensure that you will be position properly under the bands. Attach the other end to the barbell.','Lie on the bench, tuck your feet underneath you and arch your back. Using the bar to help support your weight, lift your shoulder off the bench and retract them, squeezing the shoulder blades together. Use your feet to drive your traps into the bench. Maintain this tight body position throughout the movement. However wide your grip, it should cover the ring on the bar.','Pull the bar out of the rack without protracting your shoulders. Focus on squeezing the bar and trying to pull it apart. Lower the bar to your lower chest or upper stomach. The bar, wrist, and elbow should stay in line at all times.','Pause when the barbell touches your torso, and then drive the bar up with as much force as possible. The elbows should be tucked in until lockout.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Band_Bench_Press/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Band_Bench_Press/1.jpg']::text[]),
('Reverse_Band_Box_Squat','Reverse Band Box Squat','powerlifting','intermediate','compound','push','barbell',ARRAY['quadriceps']::text[],ARRAY['abductors','adductors','calves','forearms','glutes','hamstrings','lower back']::text[],ARRAY['Begin in a power rack with a box at the appropriate height behind you. Set up the bands either on band pegs or attached to the top of the rack, ensuring they will be directly above the bar during the squat. Attach the other end to the bar.','Begin by stepping under the bar and placing it across the back of the shoulders. Squeeze your shoulder blades together and rotate your elbows forward, attempting to bend the bar across your shoulders. Remove the bar from the rack, creating a tight arch in your lower back, and step back into position. Place your feet wider for more emphasis on the back, glutes, adductors, and hamstrings, or closer together for more quad development. Keep your head facing forward.','With your back, shoulders, and core tight, push your knees and butt out and you begin your descent. Sit back with your hips until you are seated on the box. Ideally, your shins should be perpendicular to the ground. Pause when you reach the box, and relax the hip flexors. Never bounce off of a box.','Keeping the weight on your heels and pushing your feet and knees out, drive upward off of the box as you lead the movement with your head. Continue upward, maintaining tightness head to toe. Use care to return the barbell to the rack.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Band_Box_Squat/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Band_Box_Squat/1.jpg']::text[]),
('Reverse_Band_Deadlift','Reverse Band Deadlift','powerlifting','expert','compound','pull','barbell',ARRAY['lower back']::text[],ARRAY['abductors','adductors','calves','glutes','hamstrings','quadriceps']::text[],ARRAY['Set the bar up in a power rack. Attach bands to the top of the rack, using either bands pegs or the frame itself. Attach the other end of the bands to the bar.','Approach the bar so that it is centered over your feet. You feet should be about hip width apart. Bend at the hip to grip the bar at shoulder width, allowing your shoulder blades to protract. Typically, you would use an overhand grip or an over/under grip on heavier sets.','With your feet, and your grip set, take a big breath and then lower your hips and bend the knees until your shins contact the bar. Look forward with your head, keep your chest up and your back arched, and begin driving through the heels to move the weight upward.','After the bar passes the knees, aggressively pull the bar back, pulling your shoulder blades together as you drive your hips forward into the bar.','Lower the bar by bending at the hips and guiding it to the floor.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Band_Deadlift/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Band_Deadlift/1.jpg']::text[]),
('Reverse_Band_Power_Squat','Reverse Band Power Squat','powerlifting','expert','compound','push','barbell',ARRAY['quadriceps']::text[],ARRAY['adductors','calves','glutes','hamstrings','lower back']::text[],ARRAY['Begin in a power rack with the pins and bar set at the appropriate height. After loading the bar, attach bands to the top of the rack, using either pegs or the frame itself. Attach the other end of the bands to the bar.','Begin by stepping under the bar and placing it across the back of the shoulders. Squeeze your shoulder blades together and rotate your elbows forward, attempting to bend the bar across your shoulders. Remove the bar from the rack, creating a tight arch in your lower back, and step back into position. Place your feet wide for more emphasis on the back, glutes, adductors, and hamstrings.','Keep your head facing forward. With your back, shoulders, and core tight, push your knees and butt out and you begin your descent. Sit back with your hips as much as possible. Ideally, your shins should be perpendicular to the ground. Lower bar position necessitates a greater torso lean to keep the bar over the heels. Continue until you break parallel, which is defined as the crease of the hip being in line with the top of the knee.','Keeping the weight on your heels and pushing your feet and knees out, drive upward as you lead the movement with your head. Continue upward, maintaining tightness head to toe, until you have returned to the starting position.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Band_Power_Squat/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Band_Power_Squat/1.jpg']::text[]),
('Reverse_Band_Sumo_Deadlift','Reverse Band Sumo Deadlift','powerlifting','expert','compound','pull','barbell',ARRAY['hamstrings']::text[],ARRAY['abductors','adductors','calves','forearms','glutes','lower back','quadriceps','traps']::text[],ARRAY['Begin with a bar loaded on the floor inside of a power rack. Attach bands to the top of the rack, using either pegs or the frame itself. Attach the other end to the barbell.','Approach the bar so that the bar intersects the middle of the feet. The feet should be set very wide, near the collars. Bend at the hips to grip the bar. The arms should be directly below the shoulders, inside the legs, and you can use a pronated grip, a mixed grip, or hook grip. Relax the shoulders, which in effect lengthens your arms.','Take a breath, and then lower your hips, looking forward with your head with your chest up. Drive through the floor, spreading your feet apart, with your weight on the back half of your feet. Extend through the hips and knees.','As the bar passes through the knees, lean back and drive the hips into the bar, pulling your shoulder blades together.','Return the weight to the ground by bending at the hips and controlling the weight on the way down.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Band_Sumo_Deadlift/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Band_Sumo_Deadlift/1.jpg']::text[]),
('Reverse_Barbell_Curl','Reverse Barbell Curl','strength','beginner','isolation','pull','barbell',ARRAY['biceps']::text[],ARRAY['forearms']::text[],ARRAY['Stand up with your torso upright while holding a barbell at shoulder width with the elbows close to the torso. The palm of your hands should be facing down (pronated grip). This will be your starting position.','While holding the upper arms stationary, curl the weights while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the bar is at shoulder level. Hold the contracted position for a second as you squeeze the muscle.','Slowly begin to bring the bar back to starting position as your breathe in.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Barbell_Curl/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Barbell_Curl/1.jpg']::text[]),
('Reverse_Barbell_Preacher_Curls','Reverse Barbell Preacher Curls','strength','intermediate','isolation','pull','e-z curl bar',ARRAY['biceps']::text[],ARRAY['forearms']::text[],ARRAY['Grab an EZ-bar using a shoulder width and palms down (pronated) grip.','Now place the upper part of both arms on top of the preacher bench and have your arms extended. This will be your starting position.','As you exhale, use the biceps to curl the weight up until your biceps are fully contracted and the barbell is at shoulder height. Squeeze the biceps hard for a second at the contracted position.','As you breathe in, slowly lower the barbell until your upper arms are extended and the biceps is fully stretched.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Barbell_Preacher_Curls/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Barbell_Preacher_Curls/1.jpg']::text[]),
('Reverse_Cable_Curl','Reverse Cable Curl','strength','beginner','isolation','pull','cable',ARRAY['biceps']::text[],ARRAY['forearms']::text[],ARRAY['Stand up with your torso upright while holding a bar attachment that is attached to a low pulley using a pronated (palms down) and shoulder width grip. Make sure also that you keep the elbows close to the torso. This will be your starting position.','While holding the upper arms stationary, curl the weights while contracting the biceps as you breathe out. Only the forearms should move. Continue the movement until your biceps are fully contracted and the bar is at shoulder level. Hold the contracted position for a second as you squeeze the muscle.','Slowly begin to bring the bar back to starting position as your breathe in.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Cable_Curl/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Cable_Curl/1.jpg']::text[]),
('Reverse_Crunch','Reverse Crunch','strength','beginner','isolation','pull','body only',ARRAY['abdominals']::text[],ARRAY[]::text[],ARRAY['Lie down on the floor with your legs fully extended and arms to the side of your torso with the palms on the floor. Your arms should be stationary for the entire exercise.','Move your legs up so that your thighs are perpendicular to the floor and feet are together and parallel to the floor. This is the starting position.','While inhaling, move your legs towards the torso as you roll your pelvis backwards and you raise your hips off the floor. At the end of this movement your knees will be touching your chest.','Hold the contraction for a second and move your legs back to the starting position while exhaling.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Crunch/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Crunch/1.jpg']::text[]),
('Reverse_Flyes','Reverse Flyes','strength','beginner','isolation','pull','dumbbell',ARRAY['shoulders']::text[],ARRAY[]::text[],ARRAY['To begin, lie down on an incline bench with the chest and stomach pressing against the incline. Have the dumbbells in each hand with the palms facing each other (neutral grip).','Extend the arms in front of you so that they are perpendicular to the angle of the bench. The legs should be stationary while applying pressure with the ball of your toes. This is the starting position.','Maintaining the slight bend of the elbows, move the weights out and away from each other (to the side) in an arc motion while exhaling. Tip: Try to squeeze your shoulder blades together to get the best results from this exercise.','The arms should be elevated until they are parallel to the floor.','Feel the contraction and slowly lower the weights back down to the starting position while inhaling.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Flyes/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Flyes/1.jpg']::text[]),
('Reverse_Flyes_With_External_Rotation','Reverse Flyes With External Rotation','strength','intermediate','isolation','pull','dumbbell',ARRAY['shoulders']::text[],ARRAY[]::text[],ARRAY['To begin, lie down on an incline bench set at a 30-degree angle with the chest and stomach pressing against the incline.','Have the dumbbells in each hand with the palms facing down to the floor. Your arms should be in front of you so that they are perpendicular to the angle of the bench. Tip: Your elbows should have a slight bend. The legs should be stationary while applying pressure with the ball of your toes (your heels should not be touching the floor). This is the starting position.','Maintaining the slight bend of the elbows, move the weights out and away from each other in an arc motion while exhaling.','As you lift the weight, your wrist should externally rotate by 90-degrees so that you go from a palms down (pronated) grip to a palms facing each other (neutral) grip. Tip: Try to squeeze your shoulder blades together to get the best results from this exercise.','The arms should be elevated until they are level with the head.','Feel the contraction and slowly lower the weights back down to the starting position while inhaling.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Flyes_With_External_Rotation/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Flyes_With_External_Rotation/1.jpg']::text[]),
('Reverse_Grip_Bent-Over_Rows','Reverse Grip Bent-Over Rows','strength','intermediate','compound','pull','barbell',ARRAY['middle back']::text[],ARRAY['biceps','lats','shoulders']::text[],ARRAY['Stand erect while holding a barbell with a supinated grip (palms facing up).','Bend your knees slightly and bring your torso forward, by bending at the waist, while keeping the back straight until it is almost parallel to the floor. Tip: Make sure that you keep the head up. The barbell should hang directly in front of you as your arms hang perpendicular to the floor and your torso. This is your starting position.','While keeping the torso stationary, lift the barbell as you breathe out, keeping the elbows close to the body and not doing any force with the forearm other than holding the weights. On the top contracted position, squeeze the back muscles and hold for a second.','Slowly lower the weight again to the starting position as you inhale.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Grip_Bent-Over_Rows/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Grip_Bent-Over_Rows/1.jpg']::text[]),
('Reverse_Grip_Triceps_Pushdown','Reverse Grip Triceps Pushdown','strength','beginner','isolation','push','cable',ARRAY['triceps']::text[],ARRAY[]::text[],ARRAY['Start by setting a bar attachment (straight or e-z) on a high pulley machine.','Facing the bar attachment, grab it with the palms facing up (supinated grip) at shoulder width. Lower the bar by using your lats until your arms are fully extended by your sides. Tip: Elbows should be in by your sides and your feet should be shoulder width apart from each other. This is the starting position.','Slowly elevate the bar attachment up as you inhale so it is aligned with your chest. Only the forearms should move and the elbows/upper arms should be stationary by your side at all times.','Then begin to lower the cable bar back down to the original staring position while exhaling and contracting the triceps hard.','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Grip_Triceps_Pushdown/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Grip_Triceps_Pushdown/1.jpg']::text[]),
('Reverse_Hyperextension','Reverse Hyperextension','strength','intermediate',NULL,'pull','machine',ARRAY['hamstrings']::text[],ARRAY['calves','glutes']::text[],ARRAY['Place your feet between the pads after loading an appropriate weight. Lay on the top pad, allowing your hips to hang off the back, while grasping the handles to hold your position.','To begin the movement, flex the hips, pulling the legs forward.','Reverse the motion by extending the hips, kicking the leg back. It is very important not to over-extend the hip on this movement, stopping short of your full range of motion.','Return by again flexing the hip, pulling the carriage forward as far as you can.','Repeat for the desired number of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Hyperextension/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Hyperextension/1.jpg']::text[]),
('Reverse_Machine_Flyes','Reverse Machine Flyes','strength','beginner','isolation','pull','machine',ARRAY['shoulders']::text[],ARRAY[]::text[],ARRAY['Adjust the handles so that they are fully to the rear. Make an appropriate weight selection and adjust the seat height so the handles are at shoulder level. Grasp the handles with your hands facing inwards. This will be your starting position.','In a semicircular motion, pull your hands out to your side and back, contracting your rear delts.','Keep your arms slightly bent throughout the movement, with all of the motion occurring at the shoulder joint.','Pause at the rear of the movement, and slowly return the weight to the starting position.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Machine_Flyes/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Machine_Flyes/1.jpg']::text[]),
('Reverse_Plate_Curls','Reverse Plate Curls','strength','beginner','isolation','pull','other',ARRAY['biceps']::text[],ARRAY['forearms']::text[],ARRAY['Start by standing straight with a weighted plate held by both hands and arms fully extended. Use a pronated grip (palms facing down) and make sure your fingers grab the rough side of the plate while your thumb grabs the smooth side. Note: For the best results, grab the weighted plate at an 11:00 and 1:00 o''clock position.','Your feet should be shoulder width apart from each other and the weighted plate should be near the groin area. This is the starting position.','Slowly lift the plate up while keeping the elbows in and the upper arms stationary until your biceps and forearms touch while exhaling. The plate should be evenly aligned with your torso at this point.','Feel the contraction for a second and begin to lower the weight back down to the starting position while inhaling','Repeat for the recommended amount of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Plate_Curls/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Plate_Curls/1.jpg']::text[]),
('Reverse_Triceps_Bench_Press','Reverse Triceps Bench Press','strength','intermediate','compound','push','barbell',ARRAY['triceps']::text[],ARRAY['chest','shoulders']::text[],ARRAY['Lie back on a flat bench. Using a close, supinated grip (around shoulder width), lift the bar from the rack and hold it straight over you with your arms locked extended in front of you and perpendicular to the floor. This will be your starting position.','As you breathe in, come down slowly until you feel the bar on your middle chest. Tip: Make sure that as opposed to a regular bench press, you keep the elbows close to the torso at all times in order to maximize triceps involvement.','After a second pause, bring the bar back to the starting position as you breathe out and push the bar using your triceps muscles. Lock your arms in the contracted position, hold for a second and then start coming down slowly again. Tip: It should take at least twice as long to go down than to come up.','Repeat the movement for the prescribed amount of repetitions.','When you are done, place the bar back in the rack.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Triceps_Bench_Press/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Reverse_Triceps_Bench_Press/1.jpg']::text[]),
('Rhomboids-SMR','Rhomboids-SMR','stretching','intermediate',NULL,'static','foam roll',ARRAY['middle back']::text[],ARRAY['traps']::text[],ARRAY['Lay down with your back on the floor. Place a foam roll underneath your upper back, and cross your arms in front of you, protracting your shoulders. This will be your starting position.','Raise your hips off of the ground, placing your weight onto the foam roll. Shift your weight to one side at a time, rolling over your middle and upper back. Pause at points of tension for 10-30 seconds.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rhomboids-SMR/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rhomboids-SMR/1.jpg']::text[]),
('Rickshaw_Carry','Rickshaw Carry','strongman','intermediate','compound',NULL,'other',ARRAY['forearms']::text[],ARRAY['abdominals','calves','glutes','hamstrings','lower back','quadriceps','traps']::text[],ARRAY['Position the frame at the starting point, and load with the appropriate weight. Standing in the center of the frame, begin by gripping the handles and driving through your heels to lift the frame. Ensure your chest and head are up and your back is straight.','Immediately begin walking briskly with quick, controlled steps. Keep your chest up and head forward, and make sure you continue breathing. Bring the frame to the ground after you have reached the end point.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rickshaw_Carry/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rickshaw_Carry/1.jpg']::text[]),
('Rickshaw_Deadlift','Rickshaw Deadlift','strongman','intermediate','compound','pull','other',ARRAY['quadriceps']::text[],ARRAY['forearms','glutes','hamstrings','lower back','traps']::text[],ARRAY['Load the frame with the desired weight. Center yourself between the handles. You feet should be about hip width apart. Bend at the hips to grip the handles, allowing your shoulder blades to protract.','With your feet and your grip set, take a big breath and then lower your hips and flex the knees. Look forward with your head, keep your chest up and your back arched, and begin driving through the heels to move the weight upward. As the weight comes up, pull your shoulder blades together as you drive your hips forward.','Lower the weight by bending at the hips and guiding it to the ground.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rickshaw_Deadlift/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Rickshaw_Deadlift/1.jpg']::text[]),
('Ring_Dips','Ring Dips','strength','intermediate','compound','push','other',ARRAY['triceps']::text[],ARRAY['chest','shoulders']::text[],ARRAY['Grip a ring in each hand, and then take a small jump to help you get into the starting position with your arms locked out.','Begin by flexing the elbow, lowering your body until your arms break 90 degrees. Avoid swinging, and maintain good posture throughout the descent.','Reverse the motion by extending the elbow, pushing yourself back up into the starting position.','Repeat for the desired number of repetitions.']::text[],ARRAY['https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Ring_Dips/0.jpg','https://raw.githubusercontent.com/yuhonas/free-exercise-db/main/exercises/Ring_Dips/1.jpg']::text[])
